// ── FCM Token save to Firestore ────────────────────────────────────────────────
async function saveFcmToken(db, userId, token) {
  if (!db || !userId || !token) return;
  try {
    const ref = fsDoc(db, "fcmTokens", userId);
    const snap = await fsGet(ref);
    const existing = snap.exists() ? (snap.data().tokens || []) : [];
    if (existing.includes(token)) return; // already saved
    const updated = [...new Set([...existing, token])].slice(-5); // max 5 tokens per user
    await fsSet(ref, { tokens: updated, userId, updatedAt: new Date().toISOString() }, { merge: true });
    console.log("[FCM] Token saved for user:", userId);
  } catch(e) { console.warn("[FCM] Save token failed:", e); }
}

// ── Request notification permission ───────────────────────────────────────────
async function ensureNotifPermission() {
  if (typeof Notification === "undefined") return false;
  if (Notification.permission === "granted") return true;
  if (Notification.permission === "denied") return false;
  try {
    const result = await Notification.requestPermission();
    return result === "granted";
  } catch(e) { return false; }
}

// ── Show notification via Service Worker (works when app minimized) ────────────
async function showLocalNotification(title, body, opts = {}) {
  if (typeof Notification === "undefined") return;
  const granted = await ensureNotifPermission();
  if (!granted) return;

  const icon    = opts.icon  || "/icons/icon-192x192.png";
  const badge   = opts.badge || "/icons/icon-72x72.png";
  const tag     = opts.tag   || ("askh-" + Date.now());
  const actions = opts.actions || [];

  // Try Service Worker notification first (works when tab minimized/background)
  try {
    const swReg = await navigator.serviceWorker?.ready;
    if (swReg?.showNotification) {
      await swReg.showNotification(title, {
        body, icon, badge, tag,
        vibrate:   [200, 100, 200, 100, 200],
        renotify:  true,
        requireInteraction: opts.requireInteraction || false,
        data: opts.data || {},
        actions,
      });
      return;
    }
  } catch(e) { /* fallthrough to basic */ }

  // Fallback: basic Notification API
  try { new Notification(title, { body, icon, tag }); } catch(e) {}
}

// ── Global dedup tracker ───────────────────────────────────────────────────────
let _lastNotifTs  = 0;
let _shownNotifs  = new Set();

// ── Setup Firestore real-time listener — fires for EVERY user ─────────────────
function setupNotificationListener(db, currentUser, currentRole) {
  if (!db || !currentUser) return null;

  // Request permission immediately on setup
  ensureNotifPermission().then(granted => {
    if (!granted) console.warn("[Notif] Permission denied — notifications won't show");
  });

  if (!fsOnSnapshot || !fsDoc) return null;

  const ref = fsDoc(db, "notifTrigger", "latest");

  const unsub = fsOnSnapshot(ref, async (snap) => {
    if (!snap.exists()) return;
    const data = snap.data();
    if (!data?.title || !data?.ts) return;

    // Dedup by timestamp
    if (data.ts <= _lastNotifTs) return;
    if (_shownNotifs.has(data.ts)) return;
    _lastNotifTs = data.ts;
    _shownNotifs.add(data.ts);
    if (_shownNotifs.size > 50) {
      const arr = [..._shownNotifs];
      _shownNotifs = new Set(arr.slice(-20));
    }

    // Skip notifications older than 60 seconds (stale on page refresh)
    const age = (Date.now() - data.ts) / 1000;
    if (age > 60) return;

    // UNIVERSAL: sab ko show karo — koi role check nahi
    // (targetRoles still saved for history display, not for filtering)
    await showLocalNotification(data.title, data.body || "", {
      tag:  "askh-" + data.ts,
      data: { type: data.type, ts: data.ts },
    });

    // Also save to history for this user
    try {
      await saveNotifToHistory(db, data);
    } catch(e) {}

  }, (err) => {
    console.warn("[Notif] Listener error:", err);
  });

  return unsub;
}

// ── Trigger notification — write to Firestore, all listeners fire ──────────────
async function triggerNotification(db, type, title, body, currentUser, extraData = {}) {
  if (!db || !fsDoc || !fsSet) return;
  const payload = {
    type,
    title,
    body,
    targetRoles:  ["all"], // Hamesha all — sab ko jaaye
    targetUids:   extraData.targetUids || [],
    sentBy:       currentUser?.displayName || currentUser?.email?.split("@")[0] || "System",
    sentByUid:    currentUser?.uid || "",
    ts:           Date.now(),
    createdAt:    new Date().toISOString(),
  };
  try {
    await fsSet(fsDoc(db, "notifTrigger", "latest"), payload);
  } catch(e) {
    console.warn("[Notif] triggerNotification failed:", e);
  }
}

// ── FCM Setup function (call once on login) ────────────────────────────────────
// NOTE: FCM ke liye Firebase project mein VAPID key chahiye.
// firebase.json mein "messaging" enable karo.
// Ye function gracefully fail karta hai agar FCM setup na ho.
async function setupFCM(db, userId) {
  if (!db || !userId) return;
  try {
    // Dynamic import of Firebase Messaging
    const { getMessaging, getToken, onMessage } = await import(
      "https://www.gstatic.com/firebasejs/10.7.1/firebase-messaging.js"
    ).catch(() => ({ getMessaging: null, getToken: null, onMessage: null }));

    if (!getMessaging) {
      console.log("[FCM] Firebase Messaging not available — using Firestore listener only");
      return;
    }

    const messaging = getMessaging();

    // VAPID key — Firebase Console > Project Settings > Cloud Messaging > Web Push certificates
    const VAPID_KEY = "Paste_in_inverted_qomas"; // <-- Paste your VAPID key here from Firebase Console

    if (!VAPID_KEY) {
      console.log("[FCM] VAPID key not set — using Firestore listener only");
      return;
    }

    // Get FCM token
    const token = await getToken(messaging, {
      vapidKey: VAPID_KEY,
      serviceWorkerRegistration: await navigator.serviceWorker?.ready,
    });

    if (token) {
      await saveFcmToken(db, userId, token);
      console.log("[FCM] Token registered successfully");
    }

    // Foreground message handler
    onMessage(messaging, (payload) => {
      const { title, body } = payload.notification || {};
      if (title) showLocalNotification(title, body || "");
    });

  } catch(e) {
    console.warn("[FCM] Setup failed (using Firestore listener only):", e.message);
    // App works fine without FCM — Firestore listener handles in-app notifications
  }
}
