// ─── PRODUCT SAVE HELPER ─────────────────────────────────────────────────────
// Robust save — tries update first, falls back to set
async function saveProductsToFirestore(db, updatedProducts) {
  if (!db || !updatedProducts?.length) return;
  try {
    const ref = fsDoc(db, "meta", "products");
    const snap = await fsGet(ref);
    if (snap.exists()) {
      await fsUpdate(ref, { list: updatedProducts });
    } else {
      await fsSet(ref, { list: updatedProducts });
    }
  } catch(e) {
    // If update fails, try set
    try {
      await fsSet(fsDoc(db, "meta", "products"), { list: updatedProducts });
    } catch(e2) {
      console.warn("[Products] Failed to save to Firestore:", e2);
    }
  }
}

