// ═══════════════════════════════════════════════════════════════════════════════
// SYSTEM HEALTH MONITOR — Portal Bug Early Warning System
// Monitors: Firebase, Firestore, AI, WooCommerce, Orders, Stock, Team, Storage
// Saves logs to Firestore meta/systemHealth
// Owner/ACEO only — real-time alerts before things break
// ═══════════════════════════════════════════════════════════════════════════════

// ── Global error interceptor — catches all unhandled errors ─────────────────
const PORTAL_ERRORS = [];
const MAX_ERRORS = 50;

function initGlobalErrorCapture() {
  if (window._errorCaptureInit) return;
  window._errorCaptureInit = true;

  window.addEventListener("error", (e) => {
    const entry = {
      id:        Date.now().toString(),
      type:      "js_error",
      severity:  "high",
      message:   e.message || "Unknown JS error",
      source:    (e.filename || "").split("/").pop(),
      line:      e.lineno || 0,
      time:      new Date().toISOString(),
      resolved:  false,
    };
    PORTAL_ERRORS.unshift(entry);
    if (PORTAL_ERRORS.length > MAX_ERRORS) PORTAL_ERRORS.pop();
    window.dispatchEvent(new CustomEvent("portal_error", { detail: entry }));
  });

  window.addEventListener("unhandledrejection", (e) => {
    const entry = {
      id:        Date.now().toString(),
      type:      "promise_rejection",
      severity:  "high",
      message:   String(e.reason?.message || e.reason || "Unhandled promise rejection"),
      source:    "async",
      line:      0,
      time:      new Date().toISOString(),
      resolved:  false,
    };
    PORTAL_ERRORS.unshift(entry);
    if (PORTAL_ERRORS.length > MAX_ERRORS) PORTAL_ERRORS.pop();
    window.dispatchEvent(new CustomEvent("portal_error", { detail: entry }));
  });
}

// Call immediately
initGlobalErrorCapture();

// ── Health check functions ────────────────────────────────────────────────────
async function checkFirebaseHealth(db) {
  try {
    const start = Date.now();
    await fsGet(fsDoc(db, "meta", "products"));
    const ms = Date.now() - start;
    return { ok: true, ms, label: "Firestore Read", detail: `${ms}ms response time` };
  } catch(e) {
    return { ok: false, ms: 0, label: "Firestore Read", detail: e.message };
  }
}

async function checkFirebaseWrite(db) {
  try {
    const start = Date.now();
    await fsSet(fsDoc(db, "meta", "healthPing"),
      { ping: new Date().toISOString(), ok: true }, { merge: true });
    const ms = Date.now() - start;
    return { ok: true, ms, label: "Firestore Write", detail: `${ms}ms write speed` };
  } catch(e) {
    return { ok: false, ms: 0, label: "Firestore Write", detail: e.message };
  }
}

async function checkGeminiAI(db) {
  try {
    const snap = await fsGet(fsDoc(db, "meta", "aiconfig"));
    const key  = snap.exists() ? snap.data().geminiKey : localStorage.getItem("gkey");
    if (!key) return { ok: false, label: "Gemini AI", detail: "No API key configured" };
    const start = Date.now();
    const res = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${key}`,
      { method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ contents: [{ parts: [{ text: "ping" }] }] }) }
    );
    const ms = Date.now() - start;
    if (res.ok) return { ok: true, ms, label: "Gemini AI", detail: `API responding (${ms}ms)` };
    const err = await res.json();
    return { ok: false, ms, label: "Gemini AI", detail: err.error?.message || `HTTP ${res.status}` };
  } catch(e) {
    return { ok: false, ms: 0, label: "Gemini AI", detail: e.message };
  }
}

async function checkWebsite() {
  try {
    const start = Date.now();
    const res = await fetch(
      `https://api.allorigins.win/get?url=${encodeURIComponent(WEBSITE_URL)}`,
      { signal: AbortSignal.timeout(7000) }
    ).catch(() =>
      fetch(`https://corsproxy.io/?${encodeURIComponent(WEBSITE_URL)}`,
        { signal: AbortSignal.timeout(7000) })
    );
    const ms = Date.now() - start;
    if (res.ok) return { ok: true, ms, label: "Website", detail: `askhushboo.com online (${ms}ms)` };
    return { ok: false, ms, label: "Website", detail: `HTTP ${res.status}` };
  } catch(e) {
    return { ok: false, ms: 0, label: "Website", detail: "Unreachable — " + e.message };
  }
}

function checkOrderHealth(orders) {
  const now     = Date.now();
  const issues  = [];
  const HOUR    = 3600000;

  // Stuck orders — pending > 48h
  const stuckPending = (orders||[]).filter(o => {
    if (o.status !== "pending") return false;
    const age = (now - (o.createdAt?.toDate?.()?.getTime() || new Date(o.createdAt||0).getTime())) / HOUR;
    return age > 48;
  });
  if (stuckPending.length > 0)
    issues.push({ severity:"high", message:`${stuckPending.length} order(s) stuck in Pending for 48+ hours`, ids: stuckPending.map(o=>o.orderId).slice(0,5) });

  // Dispatched not delivered > 7 days
  const stuckDispatched = (orders||[]).filter(o => {
    if (o.status !== "dispatched") return false;
    const age = (now - (o.statusUpdatedAt ? new Date(o.statusUpdatedAt).getTime() : new Date(o.createdAt||0).getTime())) / (HOUR*24);
    return age > 7;
  });
  if (stuckDispatched.length > 0)
    issues.push({ severity:"medium", message:`${stuckDispatched.length} order(s) dispatched but not delivered in 7+ days`, ids: stuckDispatched.map(o=>o.orderId).slice(0,5) });

  // Large revenue orders still pending (Rs.5000+)
  const highValuePending = (orders||[]).filter(o =>
    o.status === "pending" && Number(o.revenue||0) >= 5000
  );
  if (highValuePending.length > 0)
    issues.push({ severity:"high", message:`${highValuePending.length} high-value order(s) (Rs.5k+) still pending`, ids: highValuePending.map(o=>o.orderId).slice(0,3) });

  return { ok: issues.length === 0, issues, label: "Order Health",
    detail: issues.length === 0 ? "All orders flowing normally" : `${issues.length} issue(s) detected` };
}

function checkInventoryHealth(products) {
  const issues = [];
  const outOfStock  = (products||[]).filter(p => Number(p.stock||0) === 0);
  const criticalLow = (products||[]).filter(p => Number(p.stock||0) > 0 && Number(p.stock||0) < 5);
  if (outOfStock.length > 0)
    issues.push({ severity:"high", message:`${outOfStock.length} product(s) completely OUT OF STOCK`, ids: outOfStock.map(p=>p.name).slice(0,5) });
  if (criticalLow.length > 0)
    issues.push({ severity:"medium", message:`${criticalLow.length} product(s) have critically low stock (< 5 units)`, ids: criticalLow.map(p=>`${p.name} (${p.stock})`).slice(0,5) });
  return { ok: issues.length === 0, issues, label: "Inventory",
    detail: issues.length === 0 ? "All products have healthy stock" : `${issues.length} stock issue(s)` };
}

function checkTeamHealth(members, orders) {
  const issues = [];
  const now   = new Date();
  const today = now.toISOString().slice(0,10);

  // Members with no role
  const noRole = (members||[]).filter(m => !m.role || m.role === "member");
  if (noRole.length > 0)
    issues.push({ severity:"low", message:`${noRole.length} team member(s) have no role assigned`, ids: noRole.map(m=>m.name||m.email).slice(0,3) });

  return { ok: issues.length === 0, issues, label: "Team",
    detail: issues.length === 0 ? "Team configuration looks good" : `${issues.length} team issue(s)` };
}

// ── Save health report to Firestore ──────────────────────────────────────────
async function saveHealthReport(db, report) {
  try {
    await fsSet(fsDoc(db, "meta", "systemHealth"), {
      lastRun:   new Date().toISOString(),
      score:     report.score,
      status:    report.status,
      checks:    report.checks,
      issues:    report.allIssues,
      jsErrors:  PORTAL_ERRORS.slice(0,10),
    }, { merge: true });
  } catch {}
}

// ── Main Health Monitor Component ─────────────────────────────────────────────
function SystemHealthTab({ db, orders, products, members, role }) {
  const [running,     setRunning]     = useState(false);
  const [lastRun,     setLastRun]     = useState(null);
  const [report,      setReport]      = useState(null);
  const [liveErrors,  setLiveErrors]  = useState([...PORTAL_ERRORS]);
  const [sub,         setSub]         = useState("overview");
  const [autoRun,     setAutoRun]     = useState(false);
  const [resolvedSet, setResolvedSet] = useState(new Set());

  // Listen for new runtime errors
  useEffect(() => {
    const handler = () => setLiveErrors([...PORTAL_ERRORS]);
    window.addEventListener("portal_error", handler);
    return () => window.removeEventListener("portal_error", handler);
  }, []);

  // Load last report from Firestore on mount
  useEffect(() => {
    if (!db) return;
    fsGet(fsDoc(db, "meta", "systemHealth")).then(snap => {
      if (snap.exists()) {
        const d = snap.data();
        setReport(d);
        setLastRun(d.lastRun);
      }
    }).catch(() => {});
  }, [db]);

  // Auto-run every 30 mins if enabled
  useEffect(() => {
    if (!autoRun) return;
    const interval = setInterval(() => runChecks(), 30 * 60 * 1000);
    return () => clearInterval(interval);
  }, [autoRun, orders, products, members]);

  const runChecks = async () => {
    setRunning(true);
    setSub("overview");

    const checks = {};
    const allIssues = [];

    // Run all checks
    checks.firebase  = await checkFirebaseHealth(db);
    checks.fbwrite   = await checkFirebaseWrite(db);
    checks.gemini    = await checkGeminiAI(db);
    checks.website   = await checkWebsite();
    checks.orders    = checkOrderHealth(orders);
    checks.inventory = checkInventoryHealth(products);
    checks.team      = checkTeamHealth(members, orders);
    checks.network   = { ok: navigator.onLine, label: "Network",
                          detail: navigator.onLine ? "Connected" : "OFFLINE" };

    // Collect all issues
    Object.values(checks).forEach(c => {
      if (c.issues) allIssues.push(...c.issues);
    });

    // Add JS errors as issues
    liveErrors.slice(0,5).forEach(e => {
      allIssues.push({ severity: "high", message: "JS Error: " + e.message, ids: [e.source + ":" + e.line] });
    });

    // Score: each check is worth 10 points, issues deduct
    const totalChecks  = Object.keys(checks).length;
    const passedChecks = Object.values(checks).filter(c => c.ok).length;
    const issueDeduct  = Math.min(allIssues.filter(i => i.severity==="high").length * 5, 20);
    const score = Math.max(0, Math.round((passedChecks / totalChecks) * 100) - issueDeduct);
    const status = score >= 90 ? "excellent" : score >= 70 ? "good" : score >= 50 ? "warning" : "critical";

    const newReport = { checks, allIssues, score, status, lastRun: new Date().toISOString() };
    setReport(newReport);
    setLastRun(newReport.lastRun);
    await saveHealthReport(db, newReport);
    setRunning(false);
  };

  const resolveIssue = (idx) => {
    setResolvedSet(s => { const n = new Set(s); n.add(idx); return n; });
  };

  const card  = { background:"rgba(255,255,255,0.03)", border:"1px solid rgba(212,168,67,0.15)", borderRadius:14, padding:"18px 20px", marginBottom:12 };
  const stabs = [["overview","📊 Overview"],["checks","🔍 System Checks"],["issues","⚠️ Issues"],["errors","🐛 JS Errors"],["log","📋 Activity Log"]];

  const scoreColor = !report ? "#D4A843"
    : report.score >= 90 ? "#4ade80"
    : report.score >= 70 ? "#D4A843"
    : report.score >= 50 ? "#fbbf24"
    : "#f87171";

  const statusLabel = {
    excellent: "🟢 All Systems Operational",
    good:      "🟡 Mostly Healthy — Minor Issues",
    warning:   "🟠 Warning — Attention Needed",
    critical:  "🔴 Critical — Immediate Action Required",
  };

  const unresolved = report?.allIssues?.filter((_,i) => !resolvedSet.has(i)) || [];
  const highCount  = unresolved.filter(i => i.severity==="high").length;

  return (
    <div style={{ padding:"24px 24px 80px", maxWidth:960, margin:"0 auto" }}>
      {/* Header */}
      <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"space-between", flexWrap:"wrap", gap:12, marginBottom:24 }}>
        <div>
          <h2 style={{ fontSize:22, fontWeight:700, color:"#D4A843", marginBottom:4 }}>
            🛡️ System Health Monitor
          </h2>
          <p style={{ fontSize:12, color:"rgba(247,237,216,0.45)" }}>
            Real-time bug detection · Early warnings · Full diagnostic report
            {lastRun && <span> · Last run: {new Date(lastRun).toLocaleString("en-PK")}</span>}
          </p>
        </div>
        <div style={{ display:"flex", gap:8, alignItems:"center" }}>
          <div style={{ display:"flex", alignItems:"center", gap:6, padding:"6px 12px",
            background:"rgba(255,255,255,0.03)", border:"1px solid rgba(212,168,67,0.15)", borderRadius:10 }}>
            <div style={{ width:10, height:10, borderRadius:"50%",
              background: autoRun ? "#4ade80" : "rgba(255,255,255,0.15)" }}/>
            <span style={{ fontSize:11, color:"rgba(247,237,216,0.5)" }}>Auto (30m)</span>
            <button onClick={() => setAutoRun(r=>!r)} style={{
              padding:"2px 8px", borderRadius:6, border:"none", cursor:"pointer",
              background: autoRun ? "rgba(248,113,113,0.15)" : "rgba(74,222,128,0.15)",
              color: autoRun ? "#f87171" : "#4ade80", fontSize:10, fontWeight:700,
              fontFamily:"DM Sans,sans-serif" }}>
              {autoRun ? "Disable" : "Enable"}
            </button>
          </div>
          <button onClick={runChecks} disabled={running} style={{
            padding:"10px 22px", borderRadius:12, border:"none",
            cursor: running ? "wait" : "pointer",
            background: running ? "rgba(212,168,67,0.2)" : "linear-gradient(135deg,#A07830,#D4A843,#F0C84A)",
            color:"#030201", fontWeight:800, fontSize:13, fontFamily:"DM Sans,sans-serif" }}>
            {running ? "⏳ Running..." : "▶ Run Full Check"}
          </button>
        </div>
      </div>

      {/* Subtabs */}
      <div style={{ display:"flex", gap:7, flexWrap:"wrap", marginBottom:20 }}>
        {stabs.map(([k,l]) => (
          <button key={k} onClick={() => setSub(k)} style={{
            padding:"7px 16px", borderRadius:20, border:"none", cursor:"pointer",
            fontFamily:"DM Sans,sans-serif", fontWeight:700, fontSize:11,
            background: sub===k ? "linear-gradient(135deg,#A07830,#D4A843,#F0C84A)" : "rgba(212,168,67,0.07)",
            color: sub===k ? "#030201" : "rgba(212,168,67,0.7)",
            outline: sub===k ? "none" : "1px solid rgba(212,168,67,0.15)",
            position:"relative",
          }}>
            {l}
            {k==="issues" && highCount > 0 && (
              <span style={{ position:"absolute", top:-5, right:-5, width:16, height:16,
                borderRadius:"50%", background:"#f87171", color:"#fff",
                fontSize:9, fontWeight:800, display:"flex", alignItems:"center", justifyContent:"center" }}>
                {highCount}
              </span>
            )}
            {k==="errors" && liveErrors.length > 0 && (
              <span style={{ position:"absolute", top:-5, right:-5, width:16, height:16,
                borderRadius:"50%", background:"#f97316", color:"#fff",
                fontSize:9, fontWeight:800, display:"flex", alignItems:"center", justifyContent:"center" }}>
                {liveErrors.length}
              </span>
            )}
          </button>
        ))}
      </div>

      {/* ── OVERVIEW ── */}
      {sub === "overview" && (
        <>
          {!report ? (
            <div style={{ ...card, textAlign:"center", padding:48 }}>
              <p style={{ fontSize:40, marginBottom:16 }}>🛡️</p>
              <p style={{ fontSize:15, fontWeight:700, color:"#F7EDD8", marginBottom:8 }}>No health data yet</p>
              <p style={{ fontSize:12, color:"rgba(247,237,216,0.4)", marginBottom:20 }}>
                Click "Run Full Check" to analyze the entire portal
              </p>
              <button onClick={runChecks} style={{
                padding:"12px 28px", borderRadius:12, border:"none", cursor:"pointer",
                background:"linear-gradient(135deg,#A07830,#D4A843,#F0C84A)",
                color:"#030201", fontWeight:800, fontSize:14, fontFamily:"DM Sans,sans-serif" }}>
                ▶ Run First Check
              </button>
            </div>
          ) : (
            <>
              {/* Score card */}
              <div style={{ ...card, display:"flex", alignItems:"center", gap:24,
                background: scoreColor + "08", border:"1px solid " + scoreColor + "30" }}>
                <div style={{ width:90, height:90, borderRadius:"50%", flexShrink:0,
                  border:"3px solid " + scoreColor,
                  display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center",
                  background: scoreColor + "10" }}>
                  <p style={{ fontSize:28, fontWeight:900, color:scoreColor, margin:0, lineHeight:1 }}>{report.score}</p>
                  <p style={{ fontSize:9, color:scoreColor, margin:0, letterSpacing:"0.5px" }}>/ 100</p>
                </div>
                <div style={{ flex:1 }}>
                  <p style={{ fontSize:16, fontWeight:800, color:scoreColor, marginBottom:4 }}>
                    {statusLabel[report.status] || "Unknown"}
                  </p>
                  <p style={{ fontSize:12, color:"rgba(247,237,216,0.5)" }}>
                    {unresolved.length === 0
                      ? "No active issues. Portal is running perfectly."
                      : `${unresolved.length} active issue(s) — ${highCount} high priority`}
                  </p>
                  <div style={{ marginTop:10, height:5, borderRadius:3, background:"rgba(255,255,255,0.06)", overflow:"hidden" }}>
                    <div style={{ height:"100%", borderRadius:3, width: report.score+"%",
                      background: `linear-gradient(90deg,${scoreColor}80,${scoreColor})`,
                      transition:"width 0.8s ease" }}/>
                  </div>
                </div>
              </div>

              {/* Quick stats */}
              <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:12, marginBottom:12 }}>
                {[
                  { n: Object.values(report.checks||{}).filter(c=>c.ok).length,
                    t: Object.keys(report.checks||{}).length,
                    l:"Checks Passed", c:"#4ade80" },
                  { n: unresolved.filter(i=>i.severity==="high").length,   t:null, l:"High Priority",   c:"#f87171"  },
                  { n: unresolved.filter(i=>i.severity==="medium").length, t:null, l:"Medium Priority",  c:"#fbbf24"  },
                  { n: liveErrors.length, t:null, l:"JS Errors Caught", c:"#f97316" },
                ].map(({ n, t, l, c }) => (
                  <div key={l} style={{ background:c+"08", border:"1px solid "+c+"20", borderRadius:12, padding:"14px 16px", textAlign:"center" }}>
                    <p style={{ fontSize:22, fontWeight:900, color:c, margin:"0 0 4px" }}>
                      {t !== null ? `${n}/${t}` : n}
                    </p>
                    <p style={{ fontSize:10, color:"rgba(247,237,216,0.4)", textTransform:"uppercase", letterSpacing:"0.5px" }}>{l}</p>
                  </div>
                ))}
              </div>

              {/* Top issues preview */}
              {unresolved.length > 0 && (
                <div style={card}>
                  <p style={{ fontSize:11, fontWeight:700, color:"rgba(212,168,67,0.5)",
                    letterSpacing:"1px", textTransform:"uppercase", marginBottom:12 }}>
                    Active Issues — Needs Attention
                  </p>
                  {unresolved.slice(0,5).map((issue, idx) => (
                    <div key={idx} style={{ display:"flex", alignItems:"flex-start", gap:10,
                      padding:"10px 12px", borderRadius:10, marginBottom:8,
                      background: issue.severity==="high" ? "rgba(248,113,113,0.07)" : issue.severity==="medium" ? "rgba(251,191,36,0.07)" : "rgba(255,255,255,0.03)",
                      border: "1px solid " + (issue.severity==="high" ? "rgba(248,113,113,0.2)" : issue.severity==="medium" ? "rgba(251,191,36,0.2)" : "rgba(255,255,255,0.06)") }}>
                      <span style={{ fontSize:14, flexShrink:0 }}>
                        {issue.severity==="high" ? "🔴" : issue.severity==="medium" ? "🟡" : "🔵"}
                      </span>
                      <div style={{ flex:1 }}>
                        <p style={{ fontSize:12, fontWeight:700,
                          color: issue.severity==="high" ? "#f87171" : issue.severity==="medium" ? "#fbbf24" : "#60a5fa",
                          marginBottom:2 }}>{issue.message}</p>
                        {issue.ids && issue.ids.length > 0 && (
                          <p style={{ fontSize:10, color:"rgba(247,237,216,0.35)", fontFamily:"monospace" }}>
                            {issue.ids.join(" · ")}
                          </p>
                        )}
                      </div>
                      <button onClick={() => resolveIssue(idx)} style={{
                        padding:"3px 10px", borderRadius:8, border:"none", cursor:"pointer",
                        background:"rgba(74,222,128,0.08)", color:"#4ade80",
                        fontSize:10, fontWeight:700, flexShrink:0, fontFamily:"DM Sans,sans-serif" }}>
                        ✓ Resolve
                      </button>
                    </div>
                  ))}
                  {unresolved.length > 5 && (
                    <button onClick={() => setSub("issues")} style={{
                      width:"100%", padding:"8px", background:"none",
                      border:"1px dashed rgba(212,168,67,0.2)", borderRadius:8,
                      color:"rgba(212,168,67,0.6)", fontSize:11, cursor:"pointer",
                      fontFamily:"DM Sans,sans-serif" }}>
                      View all {unresolved.length} issues →
                    </button>
                  )}
                </div>
              )}
            </>
          )}
        </>
      )}

      {/* ── SYSTEM CHECKS ── */}
      {sub === "checks" && (
        <div>
          {!report ? (
            <p style={{ color:"rgba(247,237,216,0.4)", textAlign:"center", padding:32 }}>
              Run a health check first
            </p>
          ) : (
            <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
              {Object.values(report.checks||{}).map((chk, i) => (
                <div key={i} style={{ ...card, display:"flex", alignItems:"center", gap:14,
                  marginBottom:0,
                  background: chk.ok ? "rgba(74,222,128,0.04)" : "rgba(248,113,113,0.05)",
                  border: "1px solid " + (chk.ok ? "rgba(74,222,128,0.15)" : "rgba(248,113,113,0.2)") }}>
                  <div style={{ width:36, height:36, borderRadius:"50%", flexShrink:0,
                    background: chk.ok ? "rgba(74,222,128,0.12)" : "rgba(248,113,113,0.12)",
                    display:"flex", alignItems:"center", justifyContent:"center", fontSize:18 }}>
                    {chk.ok ? "✅" : "❌"}
                  </div>
                  <div style={{ flex:1 }}>
                    <p style={{ fontSize:13, fontWeight:700,
                      color: chk.ok ? "#4ade80" : "#f87171", marginBottom:2 }}>
                      {chk.label}
                    </p>
                    <p style={{ fontSize:11, color:"rgba(247,237,216,0.45)" }}>{chk.detail}</p>
                  </div>
                  {chk.ms > 0 && (
                    <div style={{ textAlign:"right", flexShrink:0 }}>
                      <p style={{ fontSize:12, fontWeight:700,
                        color: chk.ms < 500 ? "#4ade80" : chk.ms < 1500 ? "#fbbf24" : "#f87171" }}>
                        {chk.ms}ms
                      </p>
                      <p style={{ fontSize:9, color:"rgba(247,237,216,0.3)" }}>response</p>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* ── ISSUES ── */}
      {sub === "issues" && (
        <div>
          {unresolved.length === 0 ? (
            <div style={{ ...card, textAlign:"center", padding:40 }}>
              <p style={{ fontSize:32, marginBottom:12 }}>✅</p>
              <p style={{ fontSize:14, fontWeight:700, color:"#4ade80", marginBottom:6 }}>No Active Issues</p>
              <p style={{ fontSize:12, color:"rgba(247,237,216,0.4)" }}>
                All resolved or no issues detected in last check
              </p>
            </div>
          ) : (
            <>
              {["high","medium","low"].map(sev => {
                const sevIssues = unresolved
                  .map((iss,idx) => ({...iss, _idx:idx}))
                  .filter(i => i.severity === sev);
                if (sevIssues.length === 0) return null;
                const sevColor = sev==="high"?"#f87171":sev==="medium"?"#fbbf24":"#60a5fa";
                const sevLabel = sev==="high"?"🔴 High Priority":sev==="medium"?"🟡 Medium Priority":"🔵 Low Priority";
                return (
                  <div key={sev} style={{ marginBottom:16 }}>
                    <p style={{ fontSize:11, fontWeight:700, color:sevColor,
                      letterSpacing:"0.5px", textTransform:"uppercase", marginBottom:8 }}>
                      {sevLabel} ({sevIssues.length})
                    </p>
                    {sevIssues.map(issue => (
                      <div key={issue._idx} style={{ padding:"14px 16px", borderRadius:12, marginBottom:8,
                        background:sevColor+"06", border:"1px solid "+sevColor+"20",
                        display:"flex", alignItems:"flex-start", gap:12 }}>
                        <div style={{ flex:1 }}>
                          <p style={{ fontSize:13, fontWeight:700, color:sevColor, marginBottom:6 }}>
                            {issue.message}
                          </p>
                          {issue.ids && issue.ids.length > 0 && (
                            <div style={{ display:"flex", flexWrap:"wrap", gap:6 }}>
                              {issue.ids.map((id,ii) => (
                                <span key={ii} style={{ padding:"2px 8px", borderRadius:6,
                                  background:"rgba(255,255,255,0.04)",
                                  border:"1px solid rgba(255,255,255,0.08)",
                                  fontSize:10, color:"rgba(247,237,216,0.55)",
                                  fontFamily:"monospace" }}>{id}</span>
                              ))}
                            </div>
                          )}
                          <p style={{ fontSize:10, color:"rgba(247,237,216,0.3)", marginTop:6 }}>
                            Detected: {new Date(report?.lastRun||"").toLocaleString("en-PK")}
                          </p>
                        </div>
                        <button onClick={() => resolveIssue(issue._idx)} style={{
                          padding:"6px 14px", borderRadius:8, border:"none", cursor:"pointer",
                          background:"rgba(74,222,128,0.08)",
                          border:"1px solid rgba(74,222,128,0.2)",
                          color:"#4ade80", fontSize:11, fontWeight:700,
                          fontFamily:"DM Sans,sans-serif", flexShrink:0 }}>
                          ✓ Mark Resolved
                        </button>
                      </div>
                    ))}
                  </div>
                );
              })}
            </>
          )}
        </div>
      )}

      {/* ── JS ERRORS ── */}
      {sub === "errors" && (
        <div>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14 }}>
            <p style={{ fontSize:12, color:"rgba(247,237,216,0.45)" }}>
              Captured automatically — all JS errors and promise rejections
            </p>
            {liveErrors.length > 0 && (
              <button onClick={() => { PORTAL_ERRORS.length = 0; setLiveErrors([]); }} style={{
                padding:"5px 12px", borderRadius:8, border:"1px solid rgba(248,113,113,0.2)",
                background:"rgba(248,113,113,0.07)", color:"#f87171",
                fontSize:11, fontWeight:700, cursor:"pointer", fontFamily:"DM Sans,sans-serif" }}>
                🗑 Clear All
              </button>
            )}
          </div>
          {liveErrors.length === 0 ? (
            <div style={{ ...card, textAlign:"center", padding:40 }}>
              <p style={{ fontSize:32, marginBottom:12 }}>🐛</p>
              <p style={{ fontSize:14, fontWeight:700, color:"#4ade80", marginBottom:6 }}>No JavaScript Errors</p>
              <p style={{ fontSize:12, color:"rgba(247,237,216,0.4)" }}>
                All runtime errors will appear here automatically
              </p>
            </div>
          ) : (
            liveErrors.map((err, i) => (
              <div key={err.id} style={{ ...card, marginBottom:8,
                background:"rgba(249,115,22,0.05)", border:"1px solid rgba(249,115,22,0.2)" }}>
                <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:6 }}>
                  <span style={{ padding:"2px 8px", borderRadius:6, fontSize:9, fontWeight:700,
                    background: err.type==="js_error"?"rgba(248,113,113,0.12)":"rgba(249,115,22,0.12)",
                    color: err.type==="js_error"?"#f87171":"#f97316" }}>
                    {err.type === "js_error" ? "JS ERROR" : "PROMISE REJECTION"}
                  </span>
                  <p style={{ fontSize:10, color:"rgba(247,237,216,0.3)", marginLeft:"auto" }}>
                    {new Date(err.time).toLocaleTimeString("en-PK")}
                  </p>
                </div>
                <p style={{ fontSize:12, fontWeight:600, color:"#F7EDD8", marginBottom:4, wordBreak:"break-all" }}>
                  {err.message}
                </p>
                <p style={{ fontSize:10, color:"rgba(247,237,216,0.35)", fontFamily:"monospace" }}>
                  {err.source}{err.line ? `:${err.line}` : ""}
                </p>
              </div>
            ))
          )}
        </div>
      )}

      {/* ── ACTIVITY LOG ── */}
      {sub === "log" && (
        <div>
          <p style={{ fontSize:12, color:"rgba(247,237,216,0.4)", marginBottom:14 }}>
            What the health monitor checks — complete reference guide
          </p>
          {[
            { icon:"🔥", title:"Firestore Read",   desc:"Reads a document from Firestore. If this fails, portal data won't load.",                    freq:"Every check run", severity:"Critical" },
            { icon:"✍️", title:"Firestore Write",   desc:"Writes a test ping document. If this fails, no saves will work.",                            freq:"Every check run", severity:"Critical" },
            { icon:"🤖", title:"Gemini AI",         desc:"Sends a 'ping' to Gemini API with your key. Detects expired or invalid keys early.",          freq:"Every check run", severity:"High"     },
            { icon:"🌐", title:"Website",           desc:"Checks if askhushboo.com is online. Detects downtime before customers complain.",              freq:"Every check run", severity:"High"     },
            { icon:"📦", title:"Order Health",      desc:"Checks for stuck orders (48h+ pending), missing deliveries (7d+ dispatched), high-value pending.", freq:"Every check run", severity:"High"  },
            { icon:"🧴", title:"Inventory",         desc:"Detects out-of-stock products and critically low stock (< 5 units).",                          freq:"Every check run", severity:"Medium"   },
            { icon:"👥", title:"Team",              desc:"Checks for members without roles assigned.",                                                    freq:"Every check run", severity:"Low"      },
            { icon:"📶", title:"Network",           desc:"Checks if the browser is online. Warns before offline errors appear.",                         freq:"Every check run", severity:"Critical" },
            { icon:"🐛", title:"JS Error Capture",  desc:"Captures ALL JavaScript errors and promise rejections automatically in real-time.",             freq:"Continuous",      severity:"High"     },
          ].map(c => (
            <div key={c.title} style={{ ...card, display:"flex", gap:14, marginBottom:10 }}>
              <span style={{ fontSize:22, flexShrink:0 }}>{c.icon}</span>
              <div style={{ flex:1 }}>
                <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:4 }}>
                  <p style={{ fontSize:13, fontWeight:700, color:"#F7EDD8" }}>{c.title}</p>
                  <span style={{ padding:"1px 7px", borderRadius:6, fontSize:9, fontWeight:700,
                    background: c.severity==="Critical"?"rgba(248,113,113,0.12)":c.severity==="High"?"rgba(249,115,22,0.12)":c.severity==="Medium"?"rgba(251,191,36,0.12)":"rgba(96,165,250,0.12)",
                    color: c.severity==="Critical"?"#f87171":c.severity==="High"?"#f97316":c.severity==="Medium"?"#fbbf24":"#60a5fa" }}>
                    {c.severity}
                  </span>
                  <span style={{ fontSize:10, color:"rgba(247,237,216,0.3)", marginLeft:"auto" }}>
                    {c.freq}
                  </span>
                </div>
                <p style={{ fontSize:11, color:"rgba(247,237,216,0.5)", lineHeight:1.6 }}>{c.desc}</p>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}


// ─────────────────────────────────────────────────────────────────────────────
// PWA INSTALL BANNER — Feature #16
// "Add to Home Screen" prompt + offline indicator
// ─────────────────────────────────────────────────────────────────────────────
function PWAInstallBanner() {
  const [deferredPrompt, setDeferredPrompt] = useState(null);
  const [showBanner,     setShowBanner]     = useState(false);
  const [installed,      setInstalled]      = useState(false);
  const [isOnline,       setIsOnline]       = useState(navigator.onLine);

  useEffect(() => {
    // Detect install prompt
    const handler = (e) => {
      e.preventDefault();
      setDeferredPrompt(e);
      const dismissed = localStorage.getItem("pwa_banner_dismissed");
      if (!dismissed) setShowBanner(true);
    };
    window.addEventListener("beforeinstallprompt", handler);

    // Detect if already installed
    if (window.matchMedia("(display-mode: standalone)").matches) {
      setInstalled(true);
    }

    // Online/offline detection
    const goOnline  = () => setIsOnline(true);
    const goOffline = () => setIsOnline(false);
    window.addEventListener("online",  goOnline);
    window.addEventListener("offline", goOffline);

    return () => {
      window.removeEventListener("beforeinstallprompt", handler);
      window.removeEventListener("online",  goOnline);
      window.removeEventListener("offline", goOffline);
    };
  }, []);

  const install = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === "accepted") setInstalled(true);
    setShowBanner(false);
    setDeferredPrompt(null);
  };

  const dismiss = () => {
    setShowBanner(false);
    try { localStorage.setItem("pwa_banner_dismissed", "1"); } catch {}
  };

  return (
    <>
      {/* Offline indicator */}
      {!isOnline && (
        <div style={{
          position: "fixed", top: 0, left: 0, right: 0, zIndex: 9999,
          background: "#dc2626", color: "#fff", textAlign: "center",
          padding: "8px 16px", fontSize: 12, fontWeight: 700,
          fontFamily: "DM Sans,sans-serif", letterSpacing: "0.5px",
        }}>
          📶 You are offline — some features may not work
        </div>
      )}

      {/* Install banner */}
      {showBanner && !installed && (
        <div style={{
          position: "fixed", bottom: 80, left: 16, right: 16, zIndex: 9000,
          background: "linear-gradient(135deg,#0F0C08,#1a1410)",
          border: "1px solid rgba(212,168,67,0.35)",
          borderRadius: 18, padding: "16px 20px",
          display: "flex", alignItems: "center", gap: 14,
          boxShadow: "0 8px 32px rgba(0,0,0,0.6)",
          animation: "slideUp 0.4s cubic-bezier(0.34,1.2,0.64,1)",
        }}>
          <div style={{ width: 44, height: 44, borderRadius: 12, flexShrink: 0,
            background: "linear-gradient(135deg,#A07830,#D4A843)",
            display: "flex", alignItems: "center", justifyContent: "center",
            fontSize: 22 }}>✦</div>
          <div style={{ flex: 1 }}>
            <p style={{ fontSize: 13, fontWeight: 700, color: "#F7EDD8", margin: "0 0 3px" }}>
              Install AS KHUSHBOO Portal
            </p>
            <p style={{ fontSize: 11, color: "rgba(247,237,216,0.5)", margin: 0 }}>
              Add to home screen for the full app experience
            </p>
          </div>
          <div style={{ display: "flex", gap: 8, flexShrink: 0 }}>
            <button onClick={dismiss} style={{
              padding: "7px 12px", borderRadius: 8, border: "1px solid rgba(255,255,255,0.1)",
              background: "transparent", color: "rgba(247,237,216,0.4)",
              fontSize: 11, cursor: "pointer", fontFamily: "DM Sans,sans-serif",
            }}>Later</button>
            <button onClick={install} style={{
              padding: "7px 16px", borderRadius: 8, border: "none",
              background: "linear-gradient(135deg,#A07830,#D4A843)", color: "#030201",
              fontSize: 11, fontWeight: 800, cursor: "pointer", fontFamily: "DM Sans,sans-serif",
            }}>Install</button>
          </div>
        </div>
      )}
      <style>{`
        @keyframes slideUp { from { transform: translateY(20px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
      `}</style>
    </>
  );
}

function PremiumSidebar({ tabs, active, onChange, user, role, points }) {
  const [collapsed,    setCollapsed]    = useState(false);
  const [openGroups,   setOpenGroups]   = useState(["main","inventory"]);

  const lvl = getLoyaltyLevel(points);

  // Build a map of id -> tab for quick lookup
  const tabMap = {};
  tabs.forEach(t => { tabMap[t.id] = t; });

  const toggleGroup = (gid) => {
    setOpenGroups(prev =>
      prev.includes(gid) ? prev.filter(x => x !== gid) : [...prev, gid]
    );
  };

  // Auto-open group that contains active tab
  useEffect(() => {
    const g = TAB_GROUPS.find(g => g.tabs.includes(active));
    if (g && !openGroups.includes(g.id)) {
      setOpenGroups(prev => [...prev, g.id]);
    }
  }, [active]);

  const sidebarWidth = collapsed ? 64 : 220;

  // Role info
  const roleInfo = TEAM_ROLES[role] || TEAM_ROLES.member;

  return (
    <div style={{
      width: sidebarWidth,
      minWidth: sidebarWidth,
      maxWidth: sidebarWidth,
      height: "calc(100vh - 57px)",
      position: "sticky",
      top: 57,
      background: "linear-gradient(180deg, #0A0805 0%, #080603 100%)",
      borderRight: "1px solid rgba(212,168,67,0.12)",
      display: "flex",
      flexDirection: "column",
      transition: "width 0.3s cubic-bezier(0.4,0,0.2,1), min-width 0.3s cubic-bezier(0.4,0,0.2,1)",
      overflow: "hidden",
      zIndex: 80,
      flexShrink: 0,
    }}>

      {/* ── Collapse toggle ── */}
      <div style={{
        display: "flex",
        justifyContent: collapsed ? "center" : "flex-end",
        padding: "10px 10px 6px",
        borderBottom: "1px solid rgba(212,168,67,0.08)",
      }}>
        <button
          onClick={() => setCollapsed(c => !c)}
          title={collapsed ? "Expand sidebar" : "Collapse sidebar"}
          style={{
            width: 28, height: 28, borderRadius: 8,
            background: "rgba(212,168,67,0.06)",
            border: "1px solid rgba(212,168,67,0.18)",
            cursor: "pointer", color: "#D4A843",
            display: "flex", alignItems: "center", justifyContent: "center",
            fontSize: 14, transition: "all 0.2s",
            flexShrink: 0,
          }}
        >
          {collapsed ? "›" : "‹"}
        </button>
      </div>

      {/* ── User mini profile ── */}
      {!collapsed && (
        <div style={{
          padding: "14px 14px 10px",
          borderBottom: "1px solid rgba(212,168,67,0.08)",
        }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <div style={{
              width: 36, height: 36, borderRadius: "50%", flexShrink: 0,
              background: `linear-gradient(135deg, ${roleInfo.color}30, ${roleInfo.color}10)`,
              border: `1px solid ${roleInfo.color}50`,
              display: "flex", alignItems: "center", justifyContent: "center",
              fontSize: 16,
            }}>
              {roleInfo.label?.match(/\p{Emoji}/u)?.[0] || "👤"}
            </div>
            <div style={{ overflow: "hidden", minWidth: 0 }}>
              <p style={{
                fontSize: 12, fontWeight: 700, color: "#F7EDD8",
                overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap",
              }}>
                {user?.displayName || user?.email?.split("@")[0] || "User"}
              </p>
              <p style={{
                fontSize: 10, color: roleInfo.color,
                overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap",
                fontWeight: 600,
              }}>
                {roleInfo.label}
              </p>
            </div>
          </div>

          {/* XP / Points mini bar */}
          {lvl && (
            <div style={{ marginTop: 10 }}>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                <span style={{ fontSize: 9, color: "rgba(212,168,67,0.5)", letterSpacing: "0.5px" }}>
                  {lvl.emoji || "⭐"} {lvl.name}
                </span>
                <span style={{ fontSize: 9, color: "rgba(212,168,67,0.5)" }}>
                  {points} pts
                </span>
              </div>
              <div style={{ height: 3, background: "rgba(255,255,255,0.06)", borderRadius: 2, overflow: "hidden" }}>
                <div style={{
                  width: `${Math.min(100, (points / (lvl.min + 50)) * 100)}%`,
                  height: "100%",
                  background: `linear-gradient(90deg, ${lvl.color}, #FFE98A)`,
                  borderRadius: 2,
                  boxShadow: `0 0 6px ${lvl.color}60`,
                  transition: "width 0.5s ease",
                }}/>
              </div>
            </div>
          )}
        </div>
      )}

      {/* Collapsed avatar */}
      {collapsed && (
        <div style={{ padding: "10px 0", display: "flex", justifyContent: "center", borderBottom: "1px solid rgba(212,168,67,0.08)" }}>
          <div style={{
            width: 34, height: 34, borderRadius: "50%",
            background: `linear-gradient(135deg, ${roleInfo.color}30, ${roleInfo.color}10)`,
            border: `1px solid ${roleInfo.color}50`,
            display: "flex", alignItems: "center", justifyContent: "center",
            fontSize: 15,
          }}>
            {roleInfo.label?.match(/\p{Emoji}/u)?.[0] || "👤"}
          </div>
        </div>
      )}

      {/* ── Navigation groups ── */}
      <div style={{
        flex: 1,
        overflowY: "auto",
        overflowX: "hidden",
        padding: "8px 0",
        scrollbarWidth: "thin",
        scrollbarColor: "rgba(212,168,67,0.15) transparent",
      }}>
        {TAB_GROUPS.map(group => {
          // Filter to only tabs that exist in current user's tabs
          const groupTabs = group.tabs
            .map(id => tabMap[id])
            .filter(Boolean);

          if (groupTabs.length === 0) return null;

          const isOpen    = openGroups.includes(group.id);
          const hasActive = groupTabs.some(t => t.id === active);

          return (
            <div key={group.id} style={{ marginBottom: 2 }}>
              {/* Group header */}
              {!collapsed && (
                <button
                  onClick={() => toggleGroup(group.id)}
                  style={{
                    width: "100%", background: "none", border: "none", cursor: "pointer",
                    display: "flex", alignItems: "center", justifyContent: "space-between",
                    padding: "7px 14px 5px",
                    color: hasActive ? "#D4A843" : "rgba(247,237,216,0.3)",
                  }}
                >
                  <div style={{ display: "flex", alignItems: "center", gap: 7 }}>
                    <span style={{ fontSize: 12 }}>{group.icon}</span>
                    <span style={{
                      fontSize: 9, fontWeight: 700, letterSpacing: "1.2px",
                      textTransform: "uppercase",
                      color: hasActive ? "#D4A843" : "rgba(247,237,216,0.3)",
                    }}>
                      {group.label}
                    </span>
                  </div>
                  <span style={{
                    fontSize: 10, color: "rgba(247,237,216,0.3)",
                    transform: isOpen ? "rotate(90deg)" : "none",
                    transition: "transform 0.2s",
                    display: "inline-block",
                  }}>›</span>
                </button>
              )}

              {/* Divider in collapsed mode */}
              {collapsed && (
                <div style={{ height: 1, background: "rgba(212,168,67,0.06)", margin: "4px 10px" }}/>
              )}

              {/* Tab items */}
              {(isOpen || collapsed) && groupTabs.map(t => {
                const isActive = t.id === active;
                return (
                  <button
                    key={t.id}
                    onClick={() => onChange(t.id)}
                    title={collapsed ? t.label : undefined}
                    style={{
                      width: "100%", background: "none", border: "none",
                      cursor: "pointer", textAlign: "left",
                      display: "flex", alignItems: "center",
                      gap: collapsed ? 0 : 10,
                      justifyContent: collapsed ? "center" : "flex-start",
                      padding: collapsed ? "9px 0" : "8px 12px 8px 22px",
                      borderRadius: collapsed ? 0 : "0 10px 10px 0",
                      marginRight: collapsed ? 0 : 8,
                      position: "relative",
                      transition: "all 0.18s ease",
                      background: isActive
                        ? collapsed
                          ? "rgba(212,168,67,0.12)"
                          : "linear-gradient(90deg, rgba(212,168,67,0.12), rgba(212,168,67,0.04))"
                        : "transparent",
                    }}
                    onMouseEnter={e => {
                      if (!isActive) e.currentTarget.style.background = "rgba(212,168,67,0.06)";
                    }}
                    onMouseLeave={e => {
                      if (!isActive) e.currentTarget.style.background = "transparent";
                    }}
                  >
                    {/* Active indicator bar */}
                    {isActive && (
                      <div style={{
                        position: "absolute",
                        left: 0, top: "20%", bottom: "20%",
                        width: 3, borderRadius: "0 2px 2px 0",
                        background: "linear-gradient(180deg,#A07830,#D4A843,#F0C84A)",
                        boxShadow: "0 0 8px rgba(212,168,67,0.6)",
                      }}/>
                    )}

                    {/* Icon */}
                    <span style={{
                      fontSize: collapsed ? 18 : 15,
                      lineHeight: 1,
                      filter: isActive ? "drop-shadow(0 0 6px rgba(212,168,67,0.5))" : "none",
                      flexShrink: 0,
                      minWidth: collapsed ? "auto" : 18,
                      textAlign: "center",
                    }}>
                      {t.icon}
                    </span>

                    {/* Label */}
                    {!collapsed && (
                      <span style={{
                        fontSize: 12, fontWeight: isActive ? 700 : 500,
                        color: isActive ? "#F7EDD8" : "rgba(247,237,216,0.55)",
                        fontFamily: "DM Sans, sans-serif",
                        overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap",
                        letterSpacing: "0.2px",
                      }}>
                        {t.label}
                      </span>
                    )}

                    {/* Active dot in collapsed mode */}
                    {collapsed && isActive && (
                      <div style={{
                        position: "absolute", right: 6, top: "50%",
                        transform: "translateY(-50%)",
                        width: 4, height: 4, borderRadius: "50%",
                        background: "#D4A843",
                        boxShadow: "0 0 6px #D4A843",
                      }}/>
                    )}
                  </button>
                );
              })}
            </div>
          );
        })}
      </div>

      {/* ── Brand footer ── */}
      {!collapsed && (
        <div style={{
          padding: "12px 14px",
          borderTop: "1px solid rgba(212,168,67,0.08)",
        }}>
          <div style={{
            display: "flex", alignItems: "center", gap: 8,
          }}>
            <div style={{
              width: 6, height: 6, borderRadius: "50%",
              background: "#4ade80",
              boxShadow: "0 0 6px #4ade8080",
              animation: "pulse 2s infinite",
              flexShrink: 0,
            }}/>
            <span style={{
              fontSize: 9, color: "rgba(247,237,216,0.3)",
              letterSpacing: "0.5px", fontFamily: "Cinzel, serif",
            }}>
              BrandFlow
            </span>
          </div>
          <p style={{ fontSize: 8, color: "rgba(247,237,216,0.2)", marginTop: 3 }}>
            Portal v6 · Karachi
          </p>
        </div>
      )}

      {/* Collapsed green dot */}
      {collapsed && (
        <div style={{ padding: "10px 0", display: "flex", justifyContent: "center", borderTop: "1px solid rgba(212,168,67,0.08)" }}>
          <div style={{
            width: 6, height: 6, borderRadius: "50%",
            background: "#4ade80", boxShadow: "0 0 6px #4ade8080",
            animation: "pulse 2s infinite",
          }}/>
        </div>
      )}
    </div>
  );
}


function TabBar({ tabs, active, onChange }) {
  return (
    <div className="tabbar-scroll" style={{
      display:"flex", gap:6, padding:"14px 20px 0",
      flexWrap:"nowrap",
      overflowX:"auto",
      WebkitOverflowScrolling:"touch",
      borderBottom:`1px solid rgba(212,168,67,0.08)`,
      background:"rgba(3,2,1,0.6)",
      backdropFilter:"blur(12px)",
      WebkitBackdropFilter:"blur(12px)",
      position:"sticky", top:73, zIndex:90,
      paddingBottom:0,
      scrollbarWidth:"none",
    }}>
      {tabs.map(t => (
        <button key={t.id} onClick={()=>onChange(t.id)} style={{
          padding:"9px 16px",
          borderRadius:"10px 10px 0 0",
          border:`1px solid ${active===t.id ? "rgba(212,168,67,0.35)" : "transparent"}`,
          borderBottom: active===t.id ? "2px solid transparent" : "2px solid transparent",
          cursor:"pointer",
          fontFamily:"DM Sans, sans-serif",
          fontWeight: active===t.id ? 700 : 500,
          fontSize:12,
          letterSpacing:"0.3px",
          transition:"all 0.22s ease",
          background: active===t.id
            ? "linear-gradient(135deg, rgba(212,168,67,0.12) 0%, rgba(212,168,67,0.06) 100%)"
            : "transparent",
          color: active===t.id ? C.gold : C.muted,
          boxShadow: active===t.id
            ? "0 -2px 12px rgba(212,168,67,0.08), inset 0 1px 0 rgba(212,168,67,0.15)"
            : "none",
          position:"relative",
          bottom:0,
          marginBottom: active===t.id ? "-1px" : 0,
        }}>
          <span style={{marginRight:5}}>{t.icon}</span>{t.label}
          {active===t.id && (
            <div style={{
              position:"absolute", bottom:0, left:"20%", right:"20%",
              height:2,
              background:goldGrad,
              borderRadius:"2px 2px 0 0",
              boxShadow:"0 0 8px rgba(212,168,67,0.6)",
            }}/>
          )}
        </button>
      ))}
    </div>
  );
}

// ─── PROGRESS BAR ────────────────────────────────────────────────────────────
function ProgressBar({ pct, color=C.gold, height=5, label="" }) {
  return (
    <div>
      {label && <div style={{ display:"flex", justifyContent:"space-between", marginBottom:5 }}>
        <span style={{ fontSize:11, color:C.muted, fontWeight:500 }}>{label}</span>
        <span style={{ fontSize:11, color, fontWeight:700 }}>{Math.round(pct)}%</span>
      </div>}
      <div style={{
        background:`rgba(212,168,67,0.08)`,
        borderRadius:height, height,
        overflow:"hidden",
        boxShadow:"inset 0 1px 2px rgba(0,0,0,0.3)",
      }}>
        <div style={{
          width:`${Math.min(100,pct)}%`, height:"100%", borderRadius:height,
          background:`linear-gradient(90deg, ${C.goldD}, ${color}, ${C.goldXL})`,
          transition:"width .7s cubic-bezier(0.34,1.2,0.64,1)",
          boxShadow:`0 0 8px ${color}60`,
        }} />
      </div>
    </div>
  );
}

// ─── WA POPUP ────────────────────────────────────────────────────────────────
function buildCustomerMsg(order) {
  const LINE  = "--------------------";
  const notes = order.notes ? "\nNote: " + order.notes : "";
  return (
    "Salam, " + order.customer + "!\n\n" +
    "Thank you for shopping with *BrandFlow*.\n" +
    "Your order has been placed and is now being processed.\n\n" +
    LINE + "\n" +
    "       *ORDER DETAILS*\n" +
    LINE + "\n\n" +
    "*Order ID:*     " + order.orderId + "\n" +
    "*Product:*      " + order.product + "\n" +
    "*Quantity:*     " + order.qty + " bottle(s)\n" +
    "*Total Amount:* Rs. " + Number(order.revenue).toLocaleString("en-PK") + "\n" +
    "*Channel:*      " + order.channel + "\n" +
    "*Status:*       Pending Confirmation\n\n" +
    LINE + "\n" +
    "       *NEXT STEPS*\n" +
    LINE + "\n\n" +
    "- Your order has been received successfully.\n" +
    "- Our team will confirm and prepare your order shortly.\n" +
    "- Once dispatched, you will receive a delivery update." +
    notes + "\n\n" +
    "If you have any questions, please contact us on this number.\n\n" +
    "_Khushboo That Speaks for You_\n" +
    "*BrandFlow*\n" +
    WEBSITE_URL
  );
}

function buildBrandNotifyMsg(order) {
  const SEP     = "-------------------";
  const addedBy = order.addedBy ? "\n* Added By: " + order.addedBy : "";
  const notes   = order.notes   ? "\n* Notes: " + order.notes : "";
  return (
    "NEW ORDER ALERT - BrandFlow\n\n" +
    SEP + "\n" +
    "Order ID: " + order.orderId + "\n" +
    "Product: " + order.product + " x " + order.qty + "\n" +
    "Total Amount: Rs. " + Number(order.revenue).toLocaleString("en-PK") + "\n" +
    "Customer: " + order.customer + "\n" +
    "Phone: " + (order.phone || "Not provided") + "\n" +
    "Channel: " + order.channel + "\n" +
    "Status: Pending" +
    addedBy + notes + "\n" +
    SEP + "\n\n" +
    "ACTION REQUIRED\n" +
    "Please review and process this order. Update the order status after confirmation or dispatch."
  );
}

// ─── NEW: DISPATCH WA MESSAGE ─────────────────────────────────────────────────
function buildDispatchMsg(order) {
  return (
    "Salam *" + order.customer + "*!\n\n" +
    "Your *BrandFlow* order has been dispatched!\n\n" +
    "--------------------\n" +
    "*Order ID:* " + order.orderId + "\n" +
    "*Product:* " + order.product + " x " + order.qty + "\n" +
    "*Amount:* Rs. " + Number(order.revenue).toLocaleString("en-PK") + "\n" +
    "*Status:* Dispatched\n" +
    "--------------------\n\n" +
    "Your order is on its way — arriving very soon!\n\n" +
    "_Khushboo That Speaks for You_\n" +
    "*BrandFlow* | " + WEBSITE_URL
  );
}

// ─── NEW: ORDER STATUS PIPELINE COMPONENT ────────────────────────────────────
const STATUS_PIPELINE = [
  { key:"pending",    label:"Pending",    icon:"🕐", color:"#fbbf24" },
  { key:"confirmed",  label:"Confirmed",  icon:"✅", color:"#60a5fa" },
  { key:"packed",     label:"Packed",     icon:"📦", color:"#f472b6" },
  { key:"dispatched", label:"Dispatched", icon:"🚚", color:"#a78bfa" },
  { key:"delivered",  label:"Delivered",  icon:"🎉", color:"#34d399" },
];

function OrderPipeline({ order, onStatusChange, access }) {
  const currentIdx = STATUS_PIPELINE.findIndex(s => s.key === order.status);
  const waNum = order.phone
    ? "92" + order.phone.replace(/^0/, "").replace(/\D/g, "")
    : null;

  return (
    <div style={{ marginTop:10, padding:"12px 14px",
      background:"rgba(212,168,67,0.03)", borderRadius:10,
      border:`1px solid ${C.border}` }}>
      {/* Pipeline Steps */}
      <div style={{ display:"flex", alignItems:"center", gap:0, marginBottom:10, overflowX:"auto" }}>
        {STATUS_PIPELINE.map((s, i) => {
          const isDone    = i < currentIdx;
          const isCurrent = i === currentIdx;
          return (
            <div key={s.key} style={{ display:"flex", alignItems:"center" }}>
              <div
                onClick={() => access.admin && onStatusChange(s.key)}
                title={access.admin ? `Set to ${s.label}` : ""}
                style={{
                  display:"flex", flexDirection:"column", alignItems:"center",
                  gap:3, padding:"6px 8px", borderRadius:8,
                  cursor: access.admin ? "pointer" : "default",
                  background: isCurrent ? `${s.color}20` : isDone ? "rgba(52,211,153,0.08)" : "transparent",
                  border: isCurrent ? `1px solid ${s.color}60` : "1px solid transparent",
                  transition:"all .2s", minWidth:64, textAlign:"center",
                  transform: isCurrent ? "scale(1.05)" : "scale(1)",
                }}>
                <span style={{ fontSize:16 }}>{isDone ? "✅" : s.icon}</span>
                <span style={{ fontSize:9, fontWeight: isCurrent ? 700 : 400,
                  color: isCurrent ? s.color : isDone ? C.green : C.muted,
                  fontFamily:"DM Sans, sans-serif" }}>{s.label}</span>
              </div>
              {i < STATUS_PIPELINE.length - 1 && (
                <div style={{ width:16, height:2, flexShrink:0,
                  background: isDone ? C.green : C.border,
                  transition:"background .3s" }} />
              )}
            </div>
          );
        })}
      </div>
      {/* Dispatch WA Button — only when dispatched and phone available */}
      {order.status === "dispatched" && waNum && (
        <a
          href={`https://wa.me/${waNum}?text=${encodeURIComponent(buildDispatchMsg(order))}`}
          target="_blank" rel="noreferrer"
          style={{ ...S.btn("green", {
            display:"inline-flex", alignItems:"center",
            gap:6, fontSize:11, padding:"6px 12px", textDecoration:"none"
          }) }}>
          🚚 Dispatch WA Bhejo
        </a>
      )}
    </div>
  );
}

function WAPopup({ order, onClose }) {
  const [step, setStep] = useState(1);
  const [customerSent, setCustomerSent] = useState(false);
  const [brandSent,    setBrandSent]    = useState(false);

  const customerNum = order.phone
    ? "92" + order.phone.replace(/^0/, "").replace(/\D/g, "")
    : null;

  const customerUrl = customerNum
    ? `https://wa.me/${customerNum}?text=${encodeURIComponent(buildCustomerMsg(order))}`
    : null;
  const brandUrl = `https://wa.me/${BRAND_WA}?text=${encodeURIComponent(buildBrandNotifyMsg(order))}`;

  // ── Auto-assigned channel WA ──────────────────────────────────────────────
  const autoWAUrl  = order._autoWANum
    ? `https://wa.me/${order._autoWANum}?text=${encodeURIComponent(order._autoWAMsg || "")}`
    : null;
  const autoWARole = order._autoWARole || null;

  const handleCustomer = () => {
    window.open(customerUrl, "_blank");
    setCustomerSent(true);
    setTimeout(() => setStep(2), 800);
  };

  const handleBrand = () => {
    window.open(brandUrl, "_blank");
    setBrandSent(true);
    setTimeout(() => setStep(3), 800);
  };

  return (
    <Modal onClose={onClose} maxWidth={500}>
      <div style={{ textAlign:"center", marginBottom:20 }}>
        <div style={{ fontSize:44, marginBottom:8 }}>✅</div>
        <h2 style={{ ...S.heading(20), color:C.green, marginBottom:4 }}>Order Successfully Saved!</h2>
        <p style={{ color:C.muted, fontSize:13 }}>
          Order <b style={{ color:C.gold }}>{order.orderId}</b> — ab notifications bhejo
        </p>
      </div>

      <div style={{ ...S.card({ border:`1px solid ${C.gold}30`, marginBottom:20, padding:16 }) }}>
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8 }}>
          {[
            ["🧴 Product", `${order.product} × ${order.qty}`],
            ["💰 Amount",  `Rs. ${Number(order.revenue).toLocaleString("en-PK")}`],
            ["👤 Customer", order.customer],
            ["📱 Phone",   order.phone || "—"],
            ["📍 Channel", order.channel],
            ["📋 Status",  order.status],
          ].map(([l,v]) => (
            <div key={l} style={{ padding:"8px 10px", background:"rgba(212,168,67,0.04)", borderRadius:8 }}>
              <p style={{ fontSize:10, color:C.muted, marginBottom:2 }}>{l}</p>
              <p style={{ fontSize:13, fontWeight:600 }}>{v}</p>
            </div>
          ))}
        </div>
      </div>

      <div style={{ display:"flex", gap:6, marginBottom:20, alignItems:"center", justifyContent:"center" }}>
        {[
          { n:1, label:"Customer", icon:"👤" },
          { n:2, label:"Brand",    icon:"🏪" },
          { n:3, label:"Done",     icon:"✓"  },
        ].map((s, i) => (
          <div key={s.n} style={{ display:"flex", alignItems:"center", gap:6 }}>
            <div style={{ width:32, height:32, borderRadius:"50%", display:"flex", alignItems:"center",
              justifyContent:"center", fontSize:13, fontWeight:700,
              background: step > s.n ? C.green : step === s.n ? C.gold : "rgba(255,255,255,0.05)",
              color: step > s.n || step === s.n ? C.bg : C.muted,
              border: `2px solid ${step >= s.n ? (step > s.n ? C.green : C.gold) : C.border}`,
              transition:"all .3s" }}>
              {step > s.n ? "✓" : s.icon}
            </div>
            <span style={{ fontSize:11, color: step >= s.n ? C.cream : C.muted }}>{s.label}</span>
            {i < 2 && <div style={{ width:20, height:2, background: step > s.n+0.5 ? C.green : C.border, borderRadius:1 }} />}
          </div>
        ))}
      </div>

      {step === 1 && (
        <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
          {!customerUrl && (
            <div style={{ padding:"10px 14px", background:"rgba(239,68,68,0.08)",
              border:"1px solid rgba(239,68,68,0.3)", borderRadius:8, fontSize:13, color:C.red }}>
              ⚠️ No phone number — customer notification will be skipped
            </div>
          )}
          {customerUrl ? (
            <button onClick={handleCustomer}
              style={{ ...S.btn("green", { padding:"14px", fontSize:14, width:"100%" }) }}>
              {customerSent ? "✓ WhatsApp Opened!" : "📱 Send Order Confirmation to Customer"}
            </button>
          ) : (
            <button onClick={()=>setStep(2)}
              style={{ ...S.btn("ghost", { padding:"12px", width:"100%" }) }}>
              Customer Skip → Brand Ko Notify Karo
            </button>
          )}
          <button onClick={onClose} style={{ ...S.btn("ghost", { opacity:.5, fontSize:12 }) }}>
            Skip for now
          </button>
        </div>
      )}

      {step === 2 && (
        <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
          <p style={{ fontSize:13, color:C.muted, textAlign:"center" }}>
            {customerSent ? "✅ Customer message sent!" : "Customer step skipped"} — Now notify the team
          </p>
          {/* ── Auto-assigned channel WA ── */}
          {autoWAUrl && (
            <div style={{ padding:"12px 14px", background:"rgba(212,168,67,0.06)",
              border:"1px solid rgba(212,168,67,0.2)", borderRadius:10, marginBottom:4 }}>
              <p style={{ fontSize:11, color:"#D4A843", fontWeight:700, marginBottom:8 }}>
                ⚡ Auto-Assigned: <b style={{ textTransform:"capitalize" }}>
                  {autoWARole?.replace(/_/g," ")}
                </b> — Notify
              </p>
              <a href={autoWAUrl} target="_blank" rel="noreferrer"
                style={{ display:"inline-block", padding:"8px 18px", borderRadius:10,
                  background:"linear-gradient(135deg,#A07830,#D4A843)", color:"#030201",
                  fontWeight:700, fontSize:12, textDecoration:"none" }}>
                📱 WhatsApp {autoWARole?.replace(/_/g," ")}
              </a>
            </div>
          )}
          <button onClick={handleBrand}
            style={{ ...S.btn("gold", { padding:"14px", fontSize:14, width:"100%" }) }}>
            {brandSent ? "✓ Brand WA Opened!" : "🏪 Notify Brand Team"}
          </button>
          <button onClick={()=>setStep(3)} style={{ ...S.btn("ghost", { opacity:.5, fontSize:12 }) }}>
            Skip
          </button>
        </div>
      )}

      {step === 3 && (
        <div style={{ textAlign:"center" }}>
          <p style={{ fontSize:13, color:C.muted, marginBottom:16 }}>
            {customerSent && brandSent ? "✅ Customer and brand both notified!" :
             customerSent ? "✅ Customer notified" :
             brandSent   ? "✅ Brand notified" : "Order saved"}
          </p>
          <button onClick={onClose} style={{ ...S.btn("gold", { padding:"12px 40px", fontSize:14 }) }}>
            🎉 Done — Order Close Karo
          </button>
        </div>
      )}
    </Modal>
  );
}

// ─── LEVEL UNLOCK POPUP ───────────────────────────────────────────────────────
function LevelUnlockPopup({ level, onClose }) {
  return (
    <Modal onClose={onClose}>
      <div style={{ textAlign:"center", padding:"10px 0" }}>
        <div style={{ fontSize:64, marginBottom:12, animation:"float 1.5s ease infinite" }}>
          {level.icon}
        </div>
        <h2 style={{ ...S.heading(22), color:level.color, marginBottom:8 }}>
          {level.name} Level Unlock! 🎉
        </h2>
        <p style={{ color:C.muted, marginBottom:20, fontFamily:"Cormorant Garamond, serif",
          fontStyle:"italic", fontSize:16 }}>Mubarak ho!</p>
        <div style={{ ...S.serif(56, { color:level.color, marginBottom:8 }) }}>
          {level.discountPct}%
        </div>
        <p style={{ color:C.cream, fontSize:15, marginBottom:28 }}>
          Discount mil gayi aapko ✨
        </p>
        <div style={{ display:"flex", gap:10, justifyContent:"center" }}>
          <a href={`${WEBSITE_URL}?discount=${level.discountPct}&level=${level.name.toLowerCase()}`}
            target="_blank" rel="noreferrer"
            style={{ ...S.btn("gold"), textDecoration:"none" }}>🛍️ Shop Now</a>
          <button onClick={onClose} style={S.btn("ghost")}>Later</button>
        </div>
      </div>
    </Modal>
  );
}

