// Pakistan Events Data
// ── Hijri to Gregorian Converter ─────────────────────────────────────────────
function hijriToGregorian(hYear, hMonth, hDay) {
  const jd = Math.floor((11 * hYear + 3) / 30)
    + Math.floor(354 * hYear)
    + Math.floor(30 * hMonth)
    - Math.floor((hMonth - 1) / 2)
    + hDay + 1948440 - 385;
  let l = jd + 68569;
  const n = Math.floor((4 * l) / 146097);
  l = l - Math.floor((146097 * n + 3) / 4);
  const i = Math.floor((4000 * (l + 1)) / 1461001);
  l = l - Math.floor((1461 * i) / 4) + 31;
  const j = Math.floor((80 * l) / 2447);
  const day   = l - Math.floor((2447 * j) / 80);
  l = Math.floor(j / 11);
  const month = j + 2 - 12 * l;
  const year  = 100 * (n - 49) + i + l;
  return new Date(year, month - 1, day);
}

function getCurrentHijriYear() {
  const now = new Date();
  const baseGreg  = new Date(2024, 6, 7); // 1 Muharram 1446 = July 7, 2024
  const baseHijri = 1446;
  const daysDiff  = Math.floor((now - baseGreg) / 86400000);
  return baseHijri + Math.floor(daysDiff / 354.367);
}

function islamicEventDate(hMonth, hDay) {
  const hYear = getCurrentHijriYear();
  let gDate = hijriToGregorian(hYear, hMonth, hDay);
  const today = new Date(); today.setHours(0,0,0,0);
  if (gDate < today) gDate = hijriToGregorian(hYear + 1, hMonth, hDay);
  return gDate;
}

