function printSalesReport(orders, products, period = "today") {
  const now = new Date();
  let filtered = orders;
  let periodLabel = "";

  if (period === "today") {
    filtered = orders.filter(o => {
      const d = o.createdAt?.toDate ? o.createdAt.toDate() : new Date(o.createdAt||0);
      return d.toDateString() === now.toDateString();
    });
    periodLabel = now.toLocaleDateString("en-PK",{weekday:"long",day:"numeric",month:"long",year:"numeric"});
  } else if (period === "week") {
    const weekAgo = new Date(now); weekAgo.setDate(weekAgo.getDate()-7);
    filtered = orders.filter(o => {
      const d = o.createdAt?.toDate ? o.createdAt.toDate() : new Date(o.createdAt||0);
      return d >= weekAgo;
    });
    periodLabel = "Last 7 Days";
  } else if (period === "month") {
    filtered = orders.filter(o => {
      const d = o.createdAt?.toDate ? o.createdAt.toDate() : new Date(o.createdAt||0);
      return d.getMonth()===now.getMonth() && d.getFullYear()===now.getFullYear();
    });
    periodLabel = now.toLocaleDateString("en-PK",{month:"long",year:"numeric"});
  }

  const totalRev    = filtered.reduce((a,o)=>a+Number(o.revenue||0),0);
  const delivered   = filtered.filter(o=>o.status==="delivered").length;
  const pending     = filtered.filter(o=>o.status==="pending").length;
  const confirmed   = filtered.filter(o=>o.status==="confirmed").length;
  const dispatched  = filtered.filter(o=>o.status==="dispatched").length;
  const avgOrder    = filtered.length ? Math.round(totalRev / filtered.length) : 0;
  const byProduct   = {};
  filtered.forEach(o => { byProduct[o.product]=(byProduct[o.product]||0)+Number(o.revenue||0); });
  const topProducts = Object.entries(byProduct).sort((a,b)=>b[1]-a[1]).slice(0,5);
  const byChannel   = {};
  filtered.forEach(o => { byChannel[o.channel]=(byChannel[o.channel]||0)+1; });

  const html = `<!DOCTYPE html><html lang="en">
<head>
<meta charset="UTF-8"/>
<title>Sales Report — BrandFlow</title>
<style>
  @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap');
  *  { box-sizing:border-box; margin:0; padding:0; }
  html,body { background:#030201 !important; color:#F7EDD8; font-family:'Inter','Segoe UI',sans-serif; }
  body { padding:40px 48px; max-width:860px; margin:0 auto; }

  /* ── Gold accent bar ── */
  .accent-bar { height:4px; background:linear-gradient(90deg,#A07830,#D4A843,#F0C84A,#FFE98A,#D4A843); border-radius:2px; margin-bottom:36px; }

  /* ── Header ── */
  .header { display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:32px; padding-bottom:20px; border-bottom:1px solid rgba(212,168,67,0.2); }
  .brand-block { display:flex; align-items:center; gap:14px; }
  .brand-logo  { height:56px; width:auto; object-fit:contain; }
  .brand-name  { font-size:13px; font-weight:800; color:#D4A843; letter-spacing:3px; text-transform:uppercase; }
  .brand-tag   { font-size:11px; color:rgba(247,237,216,0.4); margin-top:3px; letter-spacing:1px; }
  .report-label{ font-size:28px; font-weight:900; color:#F7EDD8; letter-spacing:-0.5px; margin-bottom:4px; }
  .period-label{ display:inline-block; padding:4px 12px; border-radius:20px; font-size:11px; font-weight:700; background:rgba(212,168,67,0.12); color:#D4A843; border:1px solid rgba(212,168,67,0.25); }
  .gen-time    { font-size:10px; color:rgba(247,237,216,0.3); margin-top:8px; letter-spacing:0.3px; }

  /* ── KPI Cards ── */
  .kpi-grid { display:grid; grid-template-columns:repeat(3,1fr); gap:16px; margin-bottom:32px; }
  .kpi      { background:rgba(212,168,67,0.05); border:1px solid rgba(212,168,67,0.18); border-radius:14px; padding:18px 20px; position:relative; overflow:hidden; }
  .kpi::before { content:''; position:absolute; top:0; left:0; right:0; height:2px; background:linear-gradient(90deg,#A07830,#D4A843,#F0C84A); }
  .kpi-val  { font-size:26px; font-weight:900; color:#D4A843; letter-spacing:-0.5px; margin-bottom:4px; }
  .kpi-lbl  { font-size:11px; color:rgba(247,237,216,0.45); text-transform:uppercase; letter-spacing:0.8px; font-weight:600; }
  .kpi-sub  { font-size:10px; color:rgba(247,237,216,0.25); margin-top:4px; }

  /* ── Section ── */
  .section       { margin-bottom:28px; }
  .section-title { font-size:11px; font-weight:800; color:rgba(212,168,67,0.6); letter-spacing:2px; text-transform:uppercase; margin-bottom:14px; display:flex; align-items:center; gap:8px; }
  .section-title::after { content:''; flex:1; height:1px; background:rgba(212,168,67,0.12); }

  /* ── Tables ── */
  table  { width:100%; border-collapse:collapse; font-size:12px; }
  th     { background:rgba(212,168,67,0.08); color:#D4A843; padding:9px 12px; text-align:left; font-weight:700; font-size:10px; text-transform:uppercase; letter-spacing:0.8px; border-bottom:1px solid rgba(212,168,67,0.15); }
  td     { padding:9px 12px; border-bottom:1px solid rgba(212,168,67,0.06); color:rgba(247,237,216,0.8); }
  tr:nth-child(even) td { background:rgba(212,168,67,0.02); }

  /* ── Status badges ── */
  .badge   { display:inline-block; padding:2px 10px; border-radius:20px; font-size:10px; font-weight:700; }
  .delivered { background:rgba(74,222,128,0.12); color:#4ade80; border:1px solid rgba(74,222,128,0.25); }
  .pending   { background:rgba(251,191,36,0.12);  color:#fbbf24; border:1px solid rgba(251,191,36,0.25); }
  .confirmed { background:rgba(96,165,250,0.12);  color:#60a5fa; border:1px solid rgba(96,165,250,0.25); }
  .dispatched{ background:rgba(192,132,252,0.12); color:#c084fc; border:1px solid rgba(192,132,252,0.25); }
  .other     { background:rgba(255,255,255,0.06); color:rgba(247,237,216,0.5); border:1px solid rgba(255,255,255,0.1); }

  /* ── Product bar chart ── */
  .bar-row    { display:flex; align-items:center; gap:12px; margin-bottom:10px; }
  .bar-label  { font-size:12px; color:#F7EDD8; width:160px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; flex-shrink:0; }
  .bar-track  { flex:1; height:8px; background:rgba(212,168,67,0.08); border-radius:4px; overflow:hidden; }
  .bar-fill   { height:100%; background:linear-gradient(90deg,#A07830,#D4A843); border-radius:4px; }
  .bar-val    { font-size:11px; font-weight:700; color:#D4A843; width:80px; text-align:right; flex-shrink:0; }

  /* ── Footer ── */
  .footer { margin-top:40px; padding-top:16px; border-top:1px solid rgba(212,168,67,0.12); display:flex; justify-content:space-between; align-items:center; }
  .footer-brand { font-size:11px; font-weight:700; color:rgba(212,168,67,0.4); letter-spacing:1px; }
  .footer-page  { font-size:10px; color:rgba(247,237,216,0.2); }

  /* ── Print ── */
  @media print {
    html,body { background:#030201 !important; }
    * { -webkit-print-color-adjust:exact !important; print-color-adjust:exact !important; color-adjust:exact !important; }
    .kpi::before, .accent-bar, .bar-fill { background-color:#D4A843 !important; }
  }
</style>
</head>
<body>

<div class="accent-bar"></div>

<!-- Header -->
<div class="header">
  <div class="brand-block">
    <img src="${LOGO}" class="brand-logo" onerror="this.style.display='none'"/>
    <div>
      <div class="brand-name">BrandFlow</div>
      <div class="brand-tag">Khushboo That Speaks for You · askhushboo.com</div>
    </div>
  </div>
  <div style="text-align:right">
    <div class="report-label">Sales Report</div>
    <div><span class="period-label">${periodLabel}</span></div>
    <div class="gen-time">Generated ${now.toLocaleString("en-PK")}</div>
  </div>
</div>

<!-- KPI Grid -->
<div class="kpi-grid">
  <div class="kpi">
    <div class="kpi-val">${filtered.length}</div>
    <div class="kpi-lbl">Total Orders</div>
  </div>
  <div class="kpi">
    <div class="kpi-val">Rs.${totalRev.toLocaleString("en-PK")}</div>
    <div class="kpi-lbl">Total Revenue</div>
  </div>
  <div class="kpi">
    <div class="kpi-val">Rs.${avgOrder.toLocaleString("en-PK")}</div>
    <div class="kpi-lbl">Avg Order Value</div>
  </div>
  <div class="kpi">
    <div class="kpi-val">${delivered}</div>
    <div class="kpi-lbl">Delivered</div>
    <div class="kpi-sub">${filtered.length > 0 ? Math.round(delivered/filtered.length*100) : 0}% completion rate</div>
  </div>
  <div class="kpi">
    <div class="kpi-val">${confirmed + dispatched}</div>
    <div class="kpi-lbl">In Progress</div>
    <div class="kpi-sub">Confirmed + Dispatched</div>
  </div>
  <div class="kpi">
    <div class="kpi-val">${pending}</div>
    <div class="kpi-lbl">Pending</div>
    <div class="kpi-sub">Awaiting confirmation</div>
  </div>
</div>

<!-- Top Products Bar Chart -->
<div class="section">
  <div class="section-title">Top Products by Revenue</div>
  ${topProducts.map(([p,r]) => `
  <div class="bar-row">
    <div class="bar-label">${p}</div>
    <div class="bar-track"><div class="bar-fill" style="width:${totalRev>0?Math.round(r/totalRev*100):0}%"></div></div>
    <div class="bar-val">Rs.${r.toLocaleString("en-PK")}</div>
  </div>`).join("")}
</div>

<!-- Channel Breakdown -->
<div class="section">
  <div class="section-title">Orders by Channel</div>
  <table>
    <tr><th>Channel</th><th>Orders</th><th>Share</th></tr>
    ${Object.entries(byChannel).sort((a,b)=>b[1]-a[1]).map(([c,n]) =>
      `<tr><td>${c}</td><td>${n}</td><td>${filtered.length>0?Math.round(n/filtered.length*100):0}%</td></tr>`
    ).join("")}
  </table>
</div>

<!-- Order Details -->
<div class="section">
  <div class="section-title">Order Details (${filtered.length} orders)</div>
  <table>
    <tr><th>#</th><th>Customer</th><th>Product</th><th>Amount</th><th>Channel</th><th>Status</th><th>Date</th></tr>
    ${filtered.map((o,i) => `
    <tr>
      <td style="color:rgba(247,237,216,0.4);font-size:10px">${i+1}</td>
      <td style="font-weight:600">${o.customer||o.customerName||"—"}</td>
      <td>${o.product||"—"}</td>
      <td style="font-weight:700;color:#D4A843">Rs.${Number(o.revenue||0).toLocaleString("en-PK")}</td>
      <td>${o.channel||"—"}</td>
      <td><span class="badge ${o.status==="delivered"?"delivered":o.status==="confirmed"?"confirmed":o.status==="dispatched"?"dispatched":o.status==="pending"?"pending":"other"}">${o.status||"—"}</span></td>
      <td style="color:rgba(247,237,216,0.4);font-size:10px">${o.createdAt ? new Date(o.createdAt?.toDate?o.createdAt.toDate():o.createdAt).toLocaleDateString("en-PK",{day:"numeric",month:"short"}) : "—"}</td>
    </tr>`).join("")}
  </table>
</div>

<!-- Footer -->
<div class="footer">
  <div class="footer-brand">BrandFlow — CONFIDENTIAL REPORT</div>
  <div class="footer-page">${now.toLocaleDateString("en-PK",{day:"numeric",month:"long",year:"numeric"})}</div>
</div>

<script>window.onload = () => window.print();</script>
</body></html>`;

  const w = window.open("","_blank","width=960,height=700");
  if (w) { w.document.write(html); w.document.close(); }
}


