function WeeklyPunchCard({ user, db }) {
  const [weekData, setWeekData] = useState({});
  const [loaded, setLoaded] = useState(false);
  const DAYS = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
  const last7 = Array.from({length:7}, (_, i) => {
    const d = new Date(); d.setDate(d.getDate() - (6 - i));
    return d.toISOString().split("T")[0];
  });

  useEffect(() => {
    const load = async () => {
      if (!db || !user) return;
      const results = {};
      for (const dateKey of last7) {
        try {
          const ref  = fsDoc(db, "attendance", dateKey, "records", user.uid);
          const snap = await fsGet(ref);
          results[dateKey] = snap.exists() ? snap.data() : null;
        } catch {}
      }
      setWeekData(results);
      setLoaded(true);
    };
    load();
  }, [db, user]);

  const STATUS_CFG = {
    present: { color:"#4ade80", icon:"✅" },
    late:    { color:"#fbbf24", icon:"⏰" },
    absent:  { color:"rgba(255,255,255,0.06)", icon:"○" },
  };
  const todayKey2 = new Date().toISOString().split("T")[0];

  return (
    <div style={{ display:"flex", gap:6, justifyContent:"flex-start", flexWrap:"nowrap", overflowX:"auto", WebkitOverflowScrolling:"touch", paddingBottom:4, scrollbarWidth:"none" }}>
      {last7.map((dateKey, idx) => {
        const d = new Date(dateKey + "T00:00:00");
        const rec = weekData[dateKey];
        const status = rec?.status || "absent";
        const cfg = STATUS_CFG[status] || STATUS_CFG.absent;
        const isToday = dateKey === todayKey2;
        const dur = rec?.clockIn && rec?.clockOut ? fmtDuration(rec.clockIn, rec.clockOut) : null;
        return (
          <div key={dateKey} style={{
            display:"flex", flexDirection:"column", alignItems:"center", gap:5,
            padding:"12px 10px",
            background: rec ? `${cfg.color}15` : "rgba(255,255,255,0.02)",
            border:`${isToday ? "2px" : "1px"} solid ${isToday ? "#D4A843" : rec ? `${cfg.color}50` : "rgba(255,255,255,0.08)"}`,
            borderRadius:14, minWidth:74,
            boxShadow: isToday ? "0 0 16px rgba(212,168,67,0.25)" : "none",
          }}>
            <span style={{ fontSize:10, color:isToday ? "#D4A843" : "rgba(247,237,216,0.38)", fontWeight:isToday?700:400 }}>{DAYS[d.getDay()]}</span>
            <span style={{ fontSize:11, color:"rgba(247,237,216,0.38)" }}>{d.getDate()}/{d.getMonth()+1}</span>
            <span style={{ fontSize:22 }}>{loaded ? cfg.icon : "⋯"}</span>
            {rec?.clockIn && <span style={{ fontSize:9, color:cfg.color, fontWeight:600 }}>{new Date(rec.clockIn).toLocaleTimeString("en-PK",{hour:"2-digit",minute:"2-digit",hour12:true})}</span>}
            {dur && <span style={{ fontSize:9, color:"#D4A843" }}>{dur}</span>}
            {isToday && <span style={{ display:"inline-block", padding:"1px 6px", borderRadius:20, fontSize:8, background:"rgba(212,168,67,0.1)", color:"#D4A843", border:"1px solid rgba(212,168,67,0.25)", fontWeight:600 }}>Aaj</span>}
          </div>
        );
      })}
    </div>
  );
}

function LiveClock({ clockIn }) {
  const [elapsed, setElapsed] = useState("");
  useEffect(() => {
    const update = () => {
      const mins = Math.floor((Date.now() - new Date(clockIn)) / 60000);
      const h = Math.floor(mins / 60), m = mins % 60;
      setElapsed(h > 0 ? `${h}h ${m}m` : `${m}m`);
    };
    update();
    const t = setInterval(update, 30000);
    return () => clearInterval(t);
  }, [clockIn]);
  return <div style={{ fontFamily:"Cormorant Garamond,serif", fontSize:24, fontWeight:700, color:"#D4A843" }}>{elapsed}</div>;
}

// ── Notification History Save Helper ─────────────────────────────────
async function saveNotifToHistory(db, notifData) {
  if (!db || !notifData?.ts) return;
  try {
    const histRef = fsDoc(db, "notifHistory", "log");
    const histSnap = await fsGet(histRef);
    const existing = histSnap.exists() ? (histSnap.data().list || []) : [];
    if (existing.find(n => n.ts === notifData.ts)) return;
    const newList = [notifData, ...existing].slice(0, 200);
    await fsSet(histRef, { list: newList });
  } catch {}
}

