// ── Open WhatsApp helper ───────────────────────────────────────────────────────
function cleanPhone(raw) {
  if (!raw) return null;
  // Remove all non-digit characters (spaces, dashes, dots, +)
  let digits = String(raw).replace(/\D/g, "");
  // Remove leading zeros
  digits = digits.replace(/^0+/, "");
  // If already starts with 92, use as-is
  if (digits.startsWith("92") && digits.length >= 11) return digits;
  // If starts with 3 (Pakistani mobile), prepend 92
  if (digits.startsWith("3") && digits.length === 10) return "92" + digits;
  // Otherwise prepend 92
  return "92" + digits;
}

function openWA(phone, msg) {
  const num = phone ? cleanPhone(phone) : BRAND_WA;
  if (!num) return;
  window.open(
    `https://wa.me/${num}?text=${encodeURIComponent(msg)}`,
    "_blank"
  );
}

// ── Firestore real-time activity log ─────────────────────────────────────────
async function logActivity(db, type, title, details, user) {
  if (!db) return;
  try {
    const ref  = fsDoc(db, "activityLog", "log");
    const snap = await fsGet(ref);
    const list = snap.exists() ? (snap.data().list || []) : [];
    const entry = {
      id:      Date.now(),
      type,
      title,
      details,
      by:      user?.displayName || user?.email?.split("@")[0] || "System",
      byUid:   user?.uid || "",
      ts:      Date.now(),
      date:    new Date().toISOString(),
      read:    [],  // uids who have read this
    };
    await fsSet(ref, { list: [entry, ...list].slice(0, 500) });
  } catch(e) { console.warn("[Activity]", e); }
}

