// ─── BRAND HEALTH SCORE ───────────────────────────────────────────────────────
function BrandHealthScore({ orders, members, db }) {
  const now      = new Date();
  const thisMonth = orders.filter(o => {
    const d = o.createdAt?.toDate ? o.createdAt.toDate() : new Date(o.createdAt || 0);
    return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
  });
  const lastMonth = orders.filter(o => {
    const d  = o.createdAt?.toDate ? o.createdAt.toDate() : new Date(o.createdAt || 0);
    const lm = new Date(now.getFullYear(), now.getMonth() - 1, 1);
    return d.getMonth() === lm.getMonth() && d.getFullYear() === lm.getFullYear();
  });

  const tmRev    = thisMonth.reduce((a, o) => a + Number(o.revenue || 0), 0);
  const lmRev    = lastMonth.reduce((a, o) => a + Number(o.revenue || 0), 0);
  const growth   = lmRev > 0 ? ((tmRev - lmRev) / lmRev) * 100 : 0;
  const delivered = orders.filter(o => o.status === "delivered").length;
  const pending   = orders.filter(o => o.status === "pending").length;
  const delivRate = orders.length ? (delivered / orders.length) * 100 : 0;
  const activeTeam = members.filter(m => m.role !== "owner" && m.role !== "removed").length;

  // Score components (each out of 100)
  const scores = [
    {
      label:    "Revenue Growth",
      icon:     "💰",
      score:    Math.min(100, Math.max(0, 50 + growth)),
      detail:   growth >= 0 ? `+${growth.toFixed(1)}% vs last month` : `${growth.toFixed(1)}% vs last month`,
      color:    growth >= 10 ? C.green : growth >= 0 ? "#fbbf24" : C.red,
      weight:   0.30,
    },
    {
      label:    "Order Volume",
      icon:     "📦",
      score:    Math.min(100, (thisMonth.length / 50) * 100),
      detail:   `${thisMonth.length} orders this month`,
      color:    thisMonth.length >= 50 ? C.green : thisMonth.length >= 20 ? "#fbbf24" : C.red,
      weight:   0.25,
    },
    {
      label:    "Delivery Rate",
      icon:     "🚚",
      score:    delivRate,
      detail:   `${delivRate.toFixed(0)}% orders delivered`,
      color:    delivRate >= 80 ? C.green : delivRate >= 60 ? "#fbbf24" : C.red,
      weight:   0.25,
    },
    {
      label:    "Pending Health",
      icon:     "⏳",
      score:    Math.max(0, 100 - (pending / Math.max(1, orders.length)) * 200),
      detail:   `${pending} orders pending`,
      color:    pending <= 5 ? C.green : pending <= 15 ? "#fbbf24" : C.red,
      weight:   0.20,
    },
  ];

  const overallScore = Math.round(
    scores.reduce((a, s) => a + s.score * s.weight, 0)
  );

  const scoreColor  = overallScore >= 75 ? C.green : overallScore >= 50 ? "#fbbf24" : C.red;
  const scoreLabel  = overallScore >= 80 ? "Excellent" : overallScore >= 65 ? "Good" :
                      overallScore >= 50 ? "Needs Work" : "Critical";
  const scoreEmoji  = overallScore >= 80 ? "🌟" : overallScore >= 65 ? "✅" :
                      overallScore >= 50 ? "⚠️" : "🚨";

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>

      {/* Main Score */}
      <div style={{ ...S.card({ textAlign: "center", padding: "40px 24px" }),
        background: `radial-gradient(ellipse at center, ${scoreColor}08 0%, transparent 70%)`,
        border: `1px solid ${scoreColor}33` }}>
        <div style={{ fontSize: 52, marginBottom: 8, animation: "float 3s ease-in-out infinite",
          display: "inline-block" }}>{scoreEmoji}</div>
        <div style={{ fontSize: 72, fontWeight: 900, color: scoreColor, lineHeight: 1,
          fontFamily: "'Cormorant Garamond', serif", marginBottom: 8 }}>
          {overallScore}
        </div>
        <div style={{ fontSize: 13, color: C.muted, marginBottom: 4 }}>Brand Health Score</div>
        <div style={{ ...S.badge(scoreColor), fontSize: 13, padding: "4px 16px",
          display: "inline-block", marginTop: 4 }}>{scoreLabel}</div>
      </div>

      {/* Score Components */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(200px,1fr))", gap: 14 }}>
        {scores.map(s => (
          <div key={s.label} className="card-hover" style={{ ...S.card() }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
              <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                <span style={{ fontSize: 20 }}>{s.icon}</span>
                <span style={{ fontSize: 13, fontWeight: 600 }}>{s.label}</span>
              </div>
              <span style={{ fontSize: 16, fontWeight: 700, color: s.color }}>
                {Math.round(s.score)}
              </span>
            </div>
            <div style={{ background: `${C.gold}15`, borderRadius: 6, height: 6, marginBottom: 8 }}>
              <div style={{ width: `${s.score}%`, height: "100%", borderRadius: 6,
                background: s.color, transition: "width 1s ease" }} />
            </div>
            <p style={{ fontSize: 11, color: C.muted }}>{s.detail}</p>
            <p style={{ fontSize: 10, color: C.muted, marginTop: 3, opacity: .6 }}>
              Weight: {(s.weight * 100).toFixed(0)}%
            </p>
          </div>
        ))}
      </div>

      {/* Recommendations */}
      <div style={S.card()}>
        <h3 style={{ ...S.heading(13), marginBottom: 14 }}>AI Recommendations</h3>
        {[
          growth < 0    && { icon:"📉", color:C.red,     text: `Revenue is down ${Math.abs(growth).toFixed(0)}% from last month. Consider a discount campaign or new product launch.` },
          pending > 10  && { icon:"⏳", color:"#fbbf24",  text: `${pending} orders are pending. Focus the team on dispatch — this directly affects customer satisfaction.` },
          delivRate < 70 && { icon:"🚚", color:C.red,    text: `Delivery rate is only ${delivRate.toFixed(0)}%. Follow up on pending orders today.` },
          thisMonth.length < 10 && { icon:"📦", color:"#fbbf24", text: `Only ${thisMonth.length} orders this month. Increase social media activity and promotions.` },
          growth > 20   && { icon:"🚀", color:C.green,   text: `${growth.toFixed(0)}% revenue growth! Keep this momentum — promote your top products.` },
          delivRate >= 90 && { icon:"⭐", color:C.green, text: `${delivRate.toFixed(0)}% delivery rate — excellent! Send follow-up messages to customers for reviews.` },
        ].filter(Boolean).slice(0, 4).map((r, i) => (
          <div key={i} style={{ display: "flex", gap: 12, padding: "10px 0",
            borderBottom: `1px solid ${C.border}`, alignItems: "flex-start" }}>
            <span style={{ fontSize: 18, flexShrink: 0 }}>{r.icon}</span>
            <p style={{ fontSize: 13, color: C.muted, lineHeight: 1.6 }}>{r.text}</p>
          </div>
        ))}
        {[growth < 0, pending > 10, delivRate < 70, thisMonth.length < 10].every(x => !x) && growth <= 20 && (
          <p style={{ fontSize: 13, color: C.green }}>
            Sab kuch theek chal raha hai! Consistency banaye rakho. 🌟
          </p>
        )}
      </div>
    </div>
  );
}

// ─── AI DAILY BRIEFING ───────────────────────────────────────────────────────
function AIDailyBriefing({ orders, members, db }) {
  const [briefing,   setBriefing]   = useState(null);
  const [loading,    setLoading]    = useState(false);
  const [lastGen,    setLastGen]    = useState(null);
  const [savedBrief, setSavedBrief] = useState(null);

  useEffect(() => {
    const load = async () => {
      if (!db) return;
      try {
        const snap = await fsGet(fsDoc(db, "meta", "dailyBriefing"));
        if (snap.exists()) {
          setSavedBrief(snap.data());
          setLastGen(snap.data().generatedAt);
        }
      } catch {}
    };
    load();
  }, [db]);

  const generateBriefing = async () => {
    setLoading(true);
    const now      = new Date();
    const today    = orders.filter(o => {
      const d = o.createdAt?.toDate ? o.createdAt.toDate() : new Date(o.createdAt || 0);
      return d.toDateString() === now.toDateString();
    });
    const pending   = orders.filter(o => o.status === "pending");
    const thisMonth = orders.filter(o => {
      const d = o.createdAt?.toDate ? o.createdAt.toDate() : new Date(o.createdAt || 0);
      return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
    });
    const tmRev      = thisMonth.reduce((a,o) => a + Number(o.revenue||0), 0);
    const todayRev   = today.reduce((a,o)=>a+Number(o.revenue||0),0);
    const teamSize   = members.filter(m=>m.role!=="owner"&&m.role!=="removed").length;
    const topProduct = today[0]?.product || "No orders yet";

    const prompt = `You are a business intelligence AI for "BrandFlow", a luxury perfume brand in Karachi, Pakistan.

Today's LIVE Data (${now.toDateString()}):
- Orders today: ${today.length}
- Revenue today: Rs. ${todayRev.toLocaleString()}
- Pending orders: ${pending.length}
- This month total orders: ${thisMonth.length}
- This month total revenue: Rs. ${tmRev.toLocaleString()}
- Active team members: ${teamSize}
- Top product today: ${topProduct}
- Day of week: ${now.toLocaleDateString("en-PK",{weekday:"long"})}

Write a concise DAILY BRIEFING in Hinglish (mix of Urdu and English — the natural way Pakistani professionals speak). Format:
1. Good morning/afternoon greeting with the day name (1 line)
2. Today's data snapshot — specific numbers (2-3 lines)
3. Top priority action for today (1-2 lines)
4. One short motivational closing line

Rules: Be warm and professional. Use REAL numbers from the data above. Total 6-8 lines max. No bullet points — flowing natural paragraphs only.`;

    try {
      const text   = await callGeminiPhase3(db, prompt, 8192);
      const result = { text, generatedAt: now.toLocaleString("en-PK"), date: now.toDateString() };
      setBriefing(result);
      setSavedBrief(result);
      if (db) {
        try { await fsUpdate(fsDoc(db,"meta","dailyBriefing"), result); }
        catch { try { await fsSet(fsDoc(db,"meta","dailyBriefing"), result); } catch {} }
      }
    } catch(e) {
      const errMsg = e.message === "NO_KEY"
        ? "Gemini API key not set. Go to AI Brain tab and save your key."
        : `AI se connect nahi ho saka: ${e.message}. Dobara try karo.`;
      setBriefing({ text: errMsg, generatedAt: now.toLocaleString("en-PK") });
    }
    setLoading(false);
  };

  const displayBrief = briefing || savedBrief;

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
      <div style={{ ...S.card({ padding: "28px 24px" }),
        background: "radial-gradient(ellipse at top left, rgba(201,164,76,0.06) 0%, transparent 60%)",
        border: `1px solid ${C.gold}22` }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start",
          flexWrap: "wrap", gap: 14, marginBottom: 20 }}>
          <div>
            <h2 style={{ ...S.serif(20), marginBottom: 4 }}>AI Daily Briefing</h2>
            <p style={{ fontSize: 12, color: C.muted }}>
              {new Date().toLocaleDateString("en-PK", { weekday:"long", day:"numeric", month:"long", year:"numeric" })}
            </p>
          </div>
          <button onClick={generateBriefing} disabled={loading}
            style={S.btn("gold", { padding: "10px 22px", minWidth: 160 })}>
            {loading ? <span style={{ display:"flex", gap:8, alignItems:"center" }}>
              <Spinner size={16} /> Generating...
            </span> : "🤖 Generate Briefing"}
          </button>
        </div>
        <ApiKeyNotice db={db} />

        {displayBrief ? (
          <div>
            <div style={{ fontSize: 14, color: "#e8d8b8", lineHeight: 1.9, whiteSpace: "pre-line",
              fontFamily: "'Cormorant Garamond', serif", fontSize: 16 }}>
              {displayBrief.text}
            </div>
            <p style={{ fontSize: 11, color: C.muted, marginTop: 16, paddingTop: 12,
              borderTop: `1px solid ${C.border}` }}>
              Generated: {displayBrief.generatedAt}
            </p>
          </div>
        ) : (
          <div style={{ textAlign: "center", padding: "24px 0" }}>
            <div style={{ fontSize: 48, marginBottom: 12, opacity: .4 }}>🤖</div>
            <p style={{ fontSize: 13, color: C.muted }}>
              Aaj ka briefing generate karo — AI aapka business snapshot prepare karega.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

// ─── SMART ALERTS PANEL ───────────────────────────────────────────────────────
function SmartAlertsPanel({ orders, members, db }) {
  const now = new Date();

  const alerts = [];

  // Pending orders > 5
  const pending = orders.filter(o => o.status === "pending");
  if (pending.length > 5)
    alerts.push({ level:"critical", icon:"🚨", title:"High Pending Orders",
      msg: `${pending.length} orders abhi bhi pending hain. Dispatch team ko alert karo.`,
      action: "View Pending Orders" });

  // No orders today
  const todayOrders = orders.filter(o => {
    const d = o.createdAt?.toDate ? o.createdAt.toDate() : new Date(o.createdAt || 0);
    return d.toDateString() === now.toDateString();
  });
  if (todayOrders.length === 0)
    alerts.push({ level:"warning", icon:"📦", title:"No Orders Today",
      msg: "No orders yet today. Post on social media or run a promo.",
      action: "Content Calendar" });

  // Revenue drop vs last week
  const thisWeekStart = new Date(now); thisWeekStart.setDate(now.getDate() - 7);
  const lastWeekStart = new Date(now); lastWeekStart.setDate(now.getDate() - 14);
  const thisWeekRev = orders.filter(o => {
    const d = o.createdAt?.toDate ? o.createdAt.toDate() : new Date(o.createdAt || 0);
    return d >= thisWeekStart;
  }).reduce((a,o) => a + Number(o.revenue||0), 0);
  const lastWeekRev = orders.filter(o => {
    const d = o.createdAt?.toDate ? o.createdAt.toDate() : new Date(o.createdAt || 0);
    return d >= lastWeekStart && d < thisWeekStart;
  }).reduce((a,o) => a + Number(o.revenue||0), 0);
  if (lastWeekRev > 0 && thisWeekRev < lastWeekRev * 0.7)
    alerts.push({ level:"warning", icon:"📉", title:"Revenue Drop",
      msg: `Is hafte revenue pichlay hafte se ${Math.round((1 - thisWeekRev/lastWeekRev)*100)}% kam hai.`,
      action: "View Analytics" });

  // Long pending orders (older than 3 days)
  const oldPending = pending.filter(o => {
    const d = o.createdAt?.toDate ? o.createdAt.toDate() : new Date(o.createdAt || 0);
    return (now - d) > 3 * 24 * 60 * 60 * 1000;
  });
  if (oldPending.length > 0)
    alerts.push({ level:"critical", icon:"⏰", title:"Orders 3+ Din Se Pending",
      msg: `${oldPending.length} orders have been pending 3+ days: ${oldPending.slice(0,3).map(o=>o.name||"—").join(", ")}`,
      action: "View in Orders" });

  // Good alerts
  if (todayOrders.length >= 5)
    alerts.push({ level:"good", icon:"🎉", title:"Aaj Ka Din Shandar!",
      msg: `Aaj ${todayOrders.length} orders aa gaye! Revenue: ${fmtRs(todayOrders.reduce((a,o)=>a+Number(o.revenue||0),0))}`,
      action: null });

  const delivRate = orders.length ? (orders.filter(o=>o.status==="delivered").length / orders.length) * 100 : 0;
  if (delivRate >= 90)
    alerts.push({ level:"good", icon:"🚀", title:"Delivery Rate Excellent",
      msg: `${delivRate.toFixed(0)}% delivery rate — customers khush hain! Follow-up message bhejo reviews ke liye.`,
      action: null });

  const LEVEL_COLORS = { critical: C.red, warning: "#fbbf24", good: C.green, info: C.blue };

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 10 }}>
        <h3 style={S.heading(14)}>Smart Alerts — Real-time</h3>
        <span style={{ fontSize: 12, color: C.muted }}>
          {alerts.length} alerts · {new Date().toLocaleTimeString("en-PK", { hour:"2-digit", minute:"2-digit" })}
        </span>
      </div>

      {alerts.length === 0 && (
        <div style={{ ...S.card({ textAlign:"center", padding: "36px 24px" }) }}>
          <div style={{ fontSize: 48, marginBottom: 12 }}>✅</div>
          <p style={{ fontSize: 14, color: C.green, fontWeight: 600 }}>Sab theek hai!</p>
          <p style={{ fontSize: 13, color: C.muted, marginTop: 6 }}>Koi critical alert nahi abhi.</p>
        </div>
      )}

      {alerts.map((alert, i) => (
        <div key={i} style={{ ...S.card({ padding: "16px 20px" }),
          borderLeft: `4px solid ${LEVEL_COLORS[alert.level]}`,
          background: `${LEVEL_COLORS[alert.level]}06` }}>
          <div style={{ display: "flex", gap: 12, alignItems: "flex-start" }}>
            <span style={{ fontSize: 22, flexShrink: 0 }}>{alert.icon}</span>
            <div style={{ flex: 1 }}>
              <div style={{ display: "flex", justifyContent: "space-between", flexWrap: "wrap", gap: 6, marginBottom: 4 }}>
                <p style={{ fontWeight: 700, fontSize: 14 }}>{alert.title}</p>
                <span style={{ ...S.badge(LEVEL_COLORS[alert.level]), fontSize: 10 }}>{alert.level}</span>
              </div>
              <p style={{ fontSize: 13, color: C.muted, lineHeight: 1.6 }}>{alert.msg}</p>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

// ─── WEEKLY REPORT GENERATOR ─────────────────────────────────────────────────
function WeeklyReportGen({ orders, members, db }) {
  const [report,    setReport]    = useState(null);
  const [loading,   setLoading]   = useState(false);
  const [copied,    setCopied]    = useState(false);

  const now = new Date();
  const weekStart = new Date(now); weekStart.setDate(now.getDate() - 7);
  const weekOrders = orders.filter(o => {
    const d = o.createdAt?.toDate ? o.createdAt.toDate() : new Date(o.createdAt || 0);
    return d >= weekStart;
  });
  const weekRev = weekOrders.reduce((a,o) => a + Number(o.revenue||0), 0);

  const prevWeekStart = new Date(now); prevWeekStart.setDate(now.getDate() - 14);
  const prevWeekOrders = orders.filter(o => {
    const d = o.createdAt?.toDate ? o.createdAt.toDate() : new Date(o.createdAt || 0);
    return d >= prevWeekStart && d < weekStart;
  });
  const prevWeekRev = prevWeekOrders.reduce((a,o) => a + Number(o.revenue||0), 0);
  const weekGrowth  = prevWeekRev > 0 ? ((weekRev - prevWeekRev) / prevWeekRev * 100).toFixed(1) : "N/A";

  const prodMap = {};
  weekOrders.forEach(o => { prodMap[o.product] = (prodMap[o.product]||0)+1; });
  const topProduct = Object.entries(prodMap).sort((a,b)=>b[1]-a[1])[0];

  const generateReport = async () => {
    setLoading(true);

    // Build extra context — product breakdown
    const prodBreakdown = Object.entries(prodMap)
      .sort((a,b)=>b[1]-a[1]).slice(0,3)
      .map(([p,c])=>`  • ${p}: ${c} orders`).join("\n") || "  • No orders this week";

    const channelMap = {};
    weekOrders.forEach(o => { channelMap[o.channel||"Direct"] = (channelMap[o.channel||"Direct"]||0)+1; });
    const topChannel = Object.entries(channelMap).sort((a,b)=>b[1]-a[1])[0]?.[0] || "N/A";

    const pendingCount   = orders.filter(o=>o.status==="pending").length;
    const deliveredCount = weekOrders.filter(o=>o.status==="delivered").length;
    const teamSize       = members.filter(m=>m.role!=="owner"&&m.role!=="removed").length;

    const prompt = `You are a senior business analyst for "BrandFlow", a luxury perfume brand based in Karachi, Pakistan.

LIVE WEEKLY DATA:
Period: ${weekStart.toLocaleDateString("en-PK",{day:"numeric",month:"short"})} — ${now.toLocaleDateString("en-PK",{day:"numeric",month:"short",year:"numeric"})}

Revenue:
  • This week: Rs. ${weekRev.toLocaleString()}
  • Last week: Rs. ${prevWeekRev.toLocaleString()}
  • Growth: ${weekGrowth !== "N/A" ? weekGrowth+"%" : "First week (no comparison)"}

Orders:
  • This week: ${weekOrders.length} orders
  • Last week: ${prevWeekOrders.length} orders
  • Delivered: ${deliveredCount}
  • Still pending: ${pendingCount}

Top Products This Week:
${prodBreakdown}

Top Sales Channel: ${topChannel}
Team Size: ${teamSize} members

Write a WEEKLY BUSINESS REPORT in Hinglish (natural Urdu-English mix, like Pakistani professionals speak). Use ONLY the real numbers above. Structure:

1. Is Hafte Ka Khulasa (2-3 lines — general overview)
2. Revenue Analysis (2 lines — specific numbers, growth comparison)
3. Operations & Orders (2 lines — delivery rate, pending status)
4. Is Hafte Kya Acha Raha (1-2 lines — highlight best performance)
5. Agli Hafte Ka Focus (3 specific action items with clarity)
6. Closing (1 motivational line)

Total ~12-15 lines. Data-driven, honest, actionable. No generic advice — only specific to the numbers above.`;

    try {
      const text = await callGeminiPhase3(db, prompt, 8192);
      setReport(text);
    } catch(e) {
      const errMsg = e.message === "NO_KEY"
        ? "Gemini API key not set. Go to AI Brain tab and save your key first."
        : `AI se connect nahi ho saka: ${e.message}`;
      setReport(errMsg);
    }
    setLoading(false);
  };

  const copyReport = () => {
    if (!report) return;
    navigator.clipboard.writeText(report).catch(() => {});
    setCopied(true);
    setTimeout(() => setCopied(false), 2500);
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>

      {/* Week snapshot */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(140px,1fr))", gap: 12 }}>
        {[
          { icon:"📦", label:"This Week Orders", value: weekOrders.length,      color: C.gold  },
          { icon:"💰", label:"This Week Revenue", value: fmtRs(weekRev),         color: C.green },
          { icon:"📊", label:"vs Last Week",      value: weekGrowth !== "N/A" ? `${Number(weekGrowth)>=0?"+":""}${weekGrowth}%` : "—",
            color: weekGrowth !== "N/A" && Number(weekGrowth) >= 0 ? C.green : C.red },
          { icon:"🏆", label:"Top Product",       value: topProduct?.[0]?.split(" ")[0] || "—", color: C.gold },
        ].map(k => (
          <div key={k.label} style={{ ...S.card({ textAlign:"center" }) }}>
            <div style={{ fontSize: 22, marginBottom: 6 }}>{k.icon}</div>
            <div style={{ fontSize: 14, fontWeight: 700, color: k.color, marginBottom: 2 }}>{k.value}</div>
            <div style={{ fontSize: 10, color: C.muted }}>{k.label}</div>
          </div>
        ))}
      </div>

      {/* Report card */}
      <div style={{ ...S.card({ padding: "24px" }),
        border: `1px solid ${C.gold}22`,
        background: "radial-gradient(ellipse at top right, rgba(201,164,76,0.04) 0%, transparent 60%)" }}>
        <ApiKeyNotice db={db} />
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", flexWrap:"wrap", gap:12, marginBottom:20 }}>
          <div>
            <h2 style={{ ...S.serif(18), marginBottom: 4 }}>AI Weekly Report</h2>
            <p style={{ fontSize: 12, color: C.muted }}>
              {weekStart.toLocaleDateString("en-PK",{day:"numeric",month:"short"})} — {now.toLocaleDateString("en-PK",{day:"numeric",month:"short",year:"numeric"})}
            </p>
          </div>
          <div style={{ display:"flex", gap:8 }}>
            {report && (
              <button onClick={copyReport}
                style={S.btn(copied ? "green" : "ghost", { padding:"8px 16px", fontSize:12 })}>
                {copied ? "Copied!" : "Copy"}
              </button>
            )}
            <button onClick={generateReport} disabled={loading}
              style={S.btn("gold", { padding:"10px 22px", minWidth:160 })}>
              {loading ? <span style={{display:"flex",gap:8,alignItems:"center"}}>
                <Spinner size={16} /> Generating...
              </span> : "Generate Report"}
            </button>
          </div>
        </div>

        {report ? (
          <div style={{ fontSize: 14, color: "#e8d8b8", lineHeight: 1.9,
            whiteSpace: "pre-line", fontFamily: "'Cormorant Garamond', serif", fontSize: 15 }}>
            {report}
          </div>
        ) : (
          <div style={{ textAlign:"center", padding:"24px 0" }}>
            <div style={{ fontSize: 48, marginBottom: 12, opacity:.4 }}>📄</div>
            <p style={{ fontSize: 13, color: C.muted }}>
              Click "Generate Report" — AI will create a full business report for this week.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

// ─── AI BRAIN TAB ─────────────────────────────────────────────────────────────
function AIBrainTab({ role, products = [], orders = [], db }) {
  const isOwnerOrCeo = ["owner","aceo"].includes(role);

  const [apiKey,     setApiKey]     = useState(() => { try { return localStorage.getItem("gkey")||""; } catch{ return ""; } });
  const [keyInput,   setKeyInput]   = useState("");
  const [showSetup,  setShowSetup]  = useState(false);
  const [testStatus, setTestStatus] = useState("");
  const [keyLoading, setKeyLoading] = useState(true);
  const [active,    setActive]   = useState((ROLE_AI_MAP[role]||["ceo"])[0]);
  const [allChats,  setAllChats] = useState({});
  const [input,     setInput]    = useState("");
  const [thinking,  setThinking] = useState(false);
  const chatRef  = useRef(null);
  const histRef  = useRef({});

  const availMods = ROLE_AI_MAP[role] || ["ceo"];
  const msgs = allChats[active] || [];

  useEffect(() => {
    const loadKey = async () => {
      if (!db) { setKeyLoading(false); return; }
      try {
        const snap = await fsGet(fsDoc(db, "meta", "aiconfig"));
        if (snap.exists()) {
          const k = snap.data().geminiKey || "";
          if (k) {
            setApiKey(k);
            try { localStorage.setItem("gkey", k); } catch {}
          } else {
            const local = localStorage.getItem("gkey") || "";
            if (local) setApiKey(local);
          }
        } else {
          const local = localStorage.getItem("gkey") || "";
          if (local) {
            setApiKey(local);
            try {
              await fsSet(fsDoc(db, "meta", "aiconfig"), { geminiKey: local });
            } catch {}
          }
        }
      } catch(e) {
        const local = localStorage.getItem("gkey") || "";
        if (local) setApiKey(local);
      }
      setKeyLoading(false);
    };
    loadKey();
  }, [db]);

  useEffect(() => {
    const loadChats = async () => {
      if (!db) return;
      try {
        const snap = await fsGet(fsDoc(db, "meta", "aichats"));
        if (snap.exists()) {
          const data = snap.data().chats || {};
          setAllChats(data);
          Object.entries(data).forEach(([mod, chatMsgs]) => {
            histRef.current[mod] = chatMsgs.map(m => ({
              role: m.role === "user" ? "user" : "model",
              parts: [{ text: m.text }]
            }));
          });
        }
      } catch {}
    };
    loadChats();
  }, [db]);

  useEffect(() => {
    if (chatRef.current) chatRef.current.scrollTop = chatRef.current.scrollHeight;
  }, [msgs, thinking]);

  const saveKey = async (k) => {
    const trimmed = k.trim();
    setApiKey(trimmed);
    try { localStorage.setItem("gkey", trimmed); } catch {}
    if (db) {
      try {
        await fsUpdate(fsDoc(db, "meta", "aiconfig"), { geminiKey: trimmed });
      } catch {
        try {
          await fsSet(fsDoc(db, "meta", "aiconfig"), { geminiKey: trimmed });
        } catch(e2) {}
      }
    }
    setKeyInput("");
    setShowSetup(false);
    setTestStatus("");
  };

  const saveChats = async (updatedChats) => {
    if (!db) return;
    try {
      await fsUpdate(fsDoc(db, "meta", "aichats"), { chats: updatedChats });
    } catch {
      try {
        await fsSet(fsDoc(db, "meta", "aichats"), { chats: updatedChats });
      } catch(e) {}
    }
  };

  const testKey = async (k) => {
    setTestStatus("testing");
    try {
      const r = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${k.trim()}`,
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            contents: [{ role: "user", parts: [{ text: "Hi" }] }],
            generationConfig: { maxOutputTokens: 20 }
          })
        }
      );
      const d = await r.json();
      if (!d.error) {
        setTestStatus("ok");
        await saveKey(k);
        return;
      }
      const code = d.error.code || 0;
      const msg  = d.error.message || "";
      if (code === 429 || msg.includes("quota") || msg.includes("RESOURCE_EXHAUSTED")) {
        setTestStatus("ok");
        await saveKey(k);
      } else if (code === 403 || msg.includes("PERMISSION_DENIED")) {
        setTestStatus("fail:Permission denied. Enable the Gemini API at aistudio.google.com.");
      } else {
        setTestStatus("fail:Check your API key — " + msg.slice(0, 80));
      }
    } catch(e) {
      setTestStatus("fail:Network error: " + e.message);
    }
  };

  const clearChat = async () => {
    const updated = { ...allChats, [active]: [] };
    setAllChats(updated);
    histRef.current[active] = [];
    await saveChats(updated);
  };

  const buildLiveContext = () => {
    const lines = [];
    if (products.length > 0) {
      lines.push("=== LIVE STOCK DATA ===");
      let totalStock = 0, totalSold = 0, lowStock = [];
      products.forEach(p => {
        const stock = Number(p.stock||0), sold = Number(p.sold||0);
        totalStock += stock; totalSold += sold;
        if (stock < 10) lowStock.push(p.name);
        lines.push(`• ${p.name}: Stock=${stock}, Sold=${sold}, Price=Rs.${p.price||"TBD"}`);
      });
      lines.push(`Total: ${totalStock} bottles in stock, ${totalSold} sold`);
      if (lowStock.length) lines.push(`LOW STOCK WARNING: ${lowStock.join(", ")}`);
    }
    if (orders.length > 0) {
      lines.push("=== ORDERS SUMMARY ===");
      const revenue = orders.reduce((a,o) => a+Number(o.revenue||0), 0);
      const pending  = orders.filter(o=>o.status==="pending").length;
      const shipped  = orders.filter(o=>o.status==="shipped").length;
      const delivered= orders.filter(o=>o.status==="delivered").length;
      const channels = {};
      orders.forEach(o => { channels[o.channel]=(channels[o.channel]||0)+1; });
      lines.push(`Total Orders: ${orders.length} | Revenue: Rs.${revenue.toLocaleString("en-PK")}`);
      lines.push(`Status — Pending:${pending}, Shipped:${shipped}, Delivered:${delivered}`);
      lines.push(`Channels: ${Object.entries(channels).map(([k,v])=>`${k}(${v})`).join(", ")}`);
    }
    return lines.length > 0
      ? "\n\n[LIVE SOFTWARE DATA]\n" + lines.join("\n") + "\n[/LIVE DATA]"
      : "";
  };

  const send = async () => {
    const txt = input.trim();
    if (!txt || thinking) return;
    if (!apiKey) { setShowSetup(true); return; }

    setInput("");
    setThinking(true);

    const userMsg = { role:"user", text:txt, ts: Date.now() };
    const newMsgs = [...(allChats[active]||[]), userMsg];
    const updatedChats = { ...allChats, [active]: newMsgs };
    setAllChats(updatedChats);

    if (!histRef.current[active]) histRef.current[active] = [];
    histRef.current[active] = [...histRef.current[active], { role:"user", parts:[{text:txt}] }];

    try {
      const mod = AI_MODULES[active];
      const liveData = buildLiveContext();
      let contentsToSend;
      if (histRef.current[active].length === 1) {
        contentsToSend = [{ role:"user", parts:[{ text:"You are: " + mod.system + liveData + "\n\n---\n\nUser: " + txt }] }];
      } else {
        contentsToSend = histRef.current[active];
      }

      const res = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${apiKey}`,
        { method:"POST", headers:{"Content-Type":"application/json"},
          body: JSON.stringify({
            contents: contentsToSend,
            generationConfig:{ maxOutputTokens:8192, temperature:0.7 }
          }) }
      );
      const data = await res.json();

      if (data.error) {
        histRef.current[active] = histRef.current[active].slice(0,-1);
        const c = data.error.code, m = data.error.message||"";
        let err = "❌ ";
        if (m.includes("API_KEY_INVALID") || m.includes("api key not valid") || m.includes("API key not valid")) {
          err += "API Key is incorrect!\n\n→ Ask owner to set the correct key\n→ AI Brain → Key Setup";
        } else if (c===429 || m.includes("quota") || m.includes("RESOURCE_EXHAUSTED")) {
          err += "Free quota exhausted! Please try again in a little while.";
        } else if (c===403) {
          err += "Permission denied. Owner se check karwao.";
        } else {
          err += `Error ${c}: ${m}`;
        }
        const errMsgs = [...newMsgs, { role:"ai", text:err, ts:Date.now() }];
        const errChats = { ...allChats, [active]: errMsgs };
        setAllChats(errChats);
        await saveChats(errChats);
      } else {
        const parts = data?.candidates?.[0]?.content?.parts || [];
        const text = parts.find(p => p.text && !p.thought)?.text || parts[0]?.text || "";
        if (text) {
          histRef.current[active] = [...histRef.current[active], { role:"model", parts:[{text}] }];
          const aiMsg = { role:"ai", text, ts:Date.now() };
          const finalMsgs = [...newMsgs, aiMsg];
          const finalChats = { ...allChats, [active]: finalMsgs };
          setAllChats(finalChats);
          await saveChats(finalChats);
        } else {
          histRef.current[active] = histRef.current[active].slice(0,-1);
          const errMsgs = [...newMsgs, { role:"ai", text:"⚠️ Empty response received. Please try again.", ts:Date.now() }];
          const errChats = { ...allChats, [active]: errMsgs };
          setAllChats(errChats);
        }
      }
    } catch(e) {
      histRef.current[active] = histRef.current[active].slice(0,-1);
      const errMsgs = [...(allChats[active]||[]), userMsg, { role:"ai", text:`🌐 Network error: ${e.message}`, ts:Date.now() }];
      setAllChats({ ...allChats, [active]: errMsgs });
    }
    setThinking(false);
  };

  const mod = AI_MODULES[active];
  const isConnected = !!apiKey;

  if (keyLoading) return (
    <div style={{ display:"flex", alignItems:"center", justifyContent:"center", height:300 }}>
      <Spinner size={32}/><span style={{ color:C.muted, marginLeft:12 }}>AI loading...</span>
    </div>
  );

  return (
    <div className="fadeUp" style={{ padding:"16px", display:"flex", flexDirection:"column", gap:16 }}>
      <div style={{ ...S.card({ display:"flex", justifyContent:"space-between", alignItems:"center",
        flexWrap:"wrap", gap:12,
        border:`1px solid ${isConnected ? C.gold+"40" : "rgba(239,68,68,0.3)"}` }) }}>
        <div style={{ display:"flex", gap:10, alignItems:"center" }}>
          <div style={{ width:10, height:10, borderRadius:"50%",
            background: isConnected ? C.green : C.red,
            boxShadow:`0 0 8px ${isConnected ? C.green : C.red}` }}/>
          <div>
            <p style={{ fontSize:13, fontWeight:600, color: isConnected ? C.cream : C.muted }}>
              {isConnected ? "✦ Gemini AI Connected" : "AI Not Connected"}
            </p>
            <p style={{ fontSize:11, color:C.muted }}>
              {isConnected ? "Gemini 2.5 Flash · Free · Shared with team" : "Owner needs to set up the API key"}
            </p>
          </div>
        </div>
        {isOwnerOrCeo && (
          <button onClick={()=>{ setShowSetup(!showSetup); setKeyInput(""); setTestStatus(""); }}
            style={{ ...S.btn(isConnected?"ghost":"gold", { fontSize:12 }) }}>
            🔑 {isConnected ? "Change Key" : "Set Up Key"}
          </button>
        )}
        {!isOwnerOrCeo && !isConnected && (
          <span style={{ fontSize:12, color:C.red }}>⚠️ Owner se AI key set karwao</span>
        )}
      </div>

      {showSetup && isOwnerOrCeo && (
        <div style={{ ...S.card({ border:`1px solid ${C.gold}40`, animation:"fadeUp .2s ease" }) }}>
          <h3 style={{ ...S.heading(14), marginBottom:4 }}>🔑 Gemini API Key Setup</h3>
          <p style={{ fontSize:12, color:C.muted, marginBottom:14, lineHeight:1.7 }}>
            Yeh key <b style={{color:C.gold}}>saari team ke liye</b> save hogi.
            Free key: <a href="https://aistudio.google.com/app/apikey" target="_blank" rel="noreferrer"
              style={{color:C.gold}}>aistudio.google.com/app/apikey</a>
          </p>
          <div style={{ display:"flex", gap:8, marginBottom:12, flexWrap:"wrap" }}>
            <input style={{ ...S.input({ flex:1, minWidth:240, fontFamily:"monospace", fontSize:12 }) }}
              type="text" placeholder="AIzaSy..."
              value={keyInput}
              onChange={e=>{ setKeyInput(e.target.value); setTestStatus(""); }}
              onKeyDown={e=>e.key==="Enter"&&keyInput.trim().length>10&&testKey(keyInput)}/>
            <button onClick={()=>testKey(keyInput)}
              disabled={keyInput.trim().length<10||testStatus==="testing"}
              style={{ ...S.btn("gold", { opacity:keyInput.trim().length<10?.5:1 }) }}>
              {testStatus==="testing" ? "Testing..." : "✓ Test & Save"}
            </button>
            {apiKey && <button onClick={()=>saveKey("")} style={S.btn("red",{padding:"10px 14px"})}>🗑 Remove</button>}
          </div>
          {testStatus==="ok" && (
            <div style={{ padding:"10px 14px", background:"rgba(52,211,153,0.1)",
              border:"1px solid rgba(52,211,153,0.3)", borderRadius:8, fontSize:13, color:C.green }}>
              ✅ Key valid! Saari team ke liye AI connected ho gaya!
            </div>
          )}
          {testStatus.startsWith("fail:") && (
            <div style={{ padding:"10px 14px", background:"rgba(239,68,68,0.08)",
              border:"1px solid rgba(239,68,68,0.3)", borderRadius:8, fontSize:13, color:C.red }}>
              ❌ {testStatus.replace("fail:","")}
            </div>
          )}
        </div>
      )}

      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(130px,1fr))", gap:10 }}>
        {availMods.map(k => {
          const m = AI_MODULES[k]; const isAct = active===k;
          const chatCount = (allChats[k]||[]).length;
          return (
            <div key={k} onClick={()=>setActive(k)} className="card-hover"
              style={{ ...S.card({ cursor:"pointer", textAlign:"center", padding:14, position:"relative",
                border:`1px solid ${isAct?C.gold:C.border}`,
                background: isAct?`${C.gold}10`:C.card }) }}>
              {chatCount>0 && (
                <div style={{ position:"absolute", top:8, right:8, background:C.gold,
                  color:C.bg, borderRadius:"50%", width:16, height:16,
                  fontSize:9, fontWeight:700, display:"flex", alignItems:"center", justifyContent:"center" }}>
                  {chatCount>9?"9+":Math.ceil(chatCount/2)}
                </div>
              )}
              <div style={{ fontSize:26, marginBottom:6 }}>{m.icon}</div>
              <p style={{ fontSize:12, fontWeight:600, color:isAct?C.gold:C.cream }}>{m.label}</p>
              <p style={{ fontSize:10, color:C.muted, marginTop:2 }}>{m.desc}</p>
            </div>
          );
        })}
      </div>

      <div style={{ ...S.card({ display:"flex", alignItems:"center", gap:12 }) }}>
        <span style={{ fontSize:28 }}>{mod.icon}</span>
        <div style={{ flex:1 }}>
          <p style={S.heading(14)}>{mod.label}</p>
          <p style={{ fontSize:12, color:C.muted }}>{mod.desc}</p>
        </div>
        <div style={{ display:"flex", gap:8, alignItems:"center" }}>
          {msgs.length > 0 && (
            <button onClick={clearChat}
              style={{ ...S.btn("ghost", { fontSize:11, padding:"4px 10px", opacity:.6 }) }}>
              🗑 Clear
            </button>
          )}
          <span style={{ ...S.badge(C.green), fontSize:10 }}>Gemini 2.5 Flash</span>
        </div>
      </div>

      <div style={S.card()}>
        <div ref={chatRef} style={{ minHeight:320, maxHeight:440, overflowY:"auto",
          display:"flex", flexDirection:"column", gap:12, padding:"4px 0 16px" }}>

          {msgs.length===0 && (
            <div style={{ flex:1, display:"flex", flexDirection:"column",
              alignItems:"center", justifyContent:"center", padding:40, gap:14 }}>
              <span style={{ fontSize:44, filter:"drop-shadow(0 0 12px rgba(201,164,76,0.4))",
                animation:"float 2s ease infinite" }}>✦</span>
              {isConnected ? (
                <>
                  <p style={{ color:C.muted, fontSize:14, fontFamily:"Cormorant Garamond,serif",
                    fontStyle:"italic" }}>Ask anything from {mod.label}</p>
                  <p style={{ color:C.muted, fontSize:12 }}>Urdu · English · Roman Urdu · Live data included</p>
                </>
              ) : (
                <p style={{ color:C.red, fontSize:13 }}>
                  {isOwnerOrCeo ? "Set up API key above" : "Ask owner to set API key"}
                </p>
              )}
            </div>
          )}

          {msgs.map((m,i) => (
            <div key={i} style={{ display:"flex", gap:8,
              justifyContent:m.role==="user"?"flex-end":"flex-start" }}>
              {m.role==="ai" && (
                <div style={{ width:28, height:28, borderRadius:"50%",
                  background:`${C.gold}20`, border:`1px solid ${C.gold}40`,
                  display:"flex", alignItems:"center", justifyContent:"center",
                  fontSize:14, flexShrink:0, marginTop:2 }}>✦</div>
              )}
              <div style={{ maxWidth:"78%", padding:"10px 14px", borderRadius:12, fontSize:13,
                lineHeight:1.7, whiteSpace:"pre-wrap",
                ...(m.role==="user"
                  ? { background:`${C.gold}15`, border:`1px solid ${C.gold}25` }
                  : { background:"rgba(212,168,67,0.06)", border:`1px solid ${C.border}` })
              }}>
                {m.text}
                {m.ts && <div style={{ fontSize:9, color:C.muted, marginTop:4, opacity:.5 }}>
                  {new Date(m.ts).toLocaleTimeString("en-PK",{hour:"2-digit",minute:"2-digit"})}
                </div>}
              </div>
              {m.role==="user" && (
                <div style={{ width:28, height:28, borderRadius:"50%",
                  background:"rgba(255,255,255,0.06)", border:`1px solid ${C.border}`,
                  display:"flex", alignItems:"center", justifyContent:"center",
                  fontSize:14, flexShrink:0, marginTop:2 }}>👤</div>
              )}
            </div>
          ))}

          {thinking && (
            <div style={{ display:"flex", gap:8, alignItems:"center" }}>
              <div style={{ width:28, height:28, borderRadius:"50%",
                background:`${C.gold}20`, border:`1px solid ${C.gold}40`,
                display:"flex", alignItems:"center", justifyContent:"center", fontSize:14 }}>✦</div>
              <div style={{ display:"flex", gap:4, alignItems:"center" }}>
                {[0,1,2].map(d=>(
                  <div key={d} style={{ width:6, height:6, borderRadius:"50%",
                    background:C.gold, animation:`pulse 1.2s ease ${d*0.2}s infinite` }}/>
                ))}
                <span style={{ color:C.muted, fontSize:12, marginLeft:4, fontStyle:"italic" }}>Thinking...</span>
              </div>
            </div>
          )}
        </div>

        <div style={{ display:"flex", gap:8, paddingTop:12, borderTop:`1px solid ${C.border}` }}>
          <input style={{ ...S.input({ flex:1 }) }}
            placeholder={isConnected ? `Ask ${mod.label}... (Enter = send)` : "Ask owner to set the API key first"}
            value={input}
            onChange={e=>setInput(e.target.value)}
            onKeyDown={e=>{ if(e.key==="Enter"&&!e.shiftKey){ e.preventDefault(); send(); } }}
            disabled={thinking || !isConnected}/>
          <button onClick={send} disabled={thinking||!input.trim()||!isConnected}
            style={{ ...S.btn("gold",{ width:44, height:44, padding:0, borderRadius:10,
              opacity:thinking||!input.trim()||!isConnected?.4:1, fontSize:18 }) }}>↑</button>
        </div>
      </div>
    </div>
  );
}

// ─── ADMIN TAB ────────────────────────────────────────────────────────────────
// ─── ADD TASK INLINE WIDGET ──────────────────────────────────────────────────
function AddTaskInlineWidget({ tasks, setTasks, db }) {
  const [txt,     setTxt]     = useState("");
  const [priority,setPriority]= useState("medium");
  const [open,    setOpen]    = useState(false);
  const [saving,  setSaving]  = useState(false);

  const saveTask = async (updated) => {
    setTasks(updated);
    if (db) {
      try { await fsSet(fsDoc(db,"meta","tasks"),{list:updated},{merge:true}); } catch{}
    }
  };

  const add = async () => {
    if (!txt.trim()) return;
    setSaving(true);
    const updated = [...tasks, {
      id: "t" + Date.now(),
      text: txt.trim(),
      done: false,
      priority,
    }];
    await saveTask(updated);
    setTxt(""); setPriority("medium"); setOpen(false);
    setSaving(false);
  };

  return (
    <div style={{ marginTop:8 }}>
      {!open ? (
        <button onClick={()=>setOpen(true)} style={{
          display:"flex", alignItems:"center", gap:8,
          padding:"10px 16px", borderRadius:12, cursor:"pointer",
          background:"rgba(212,168,67,0.06)", border:"1px dashed rgba(212,168,67,0.25)",
          color:"rgba(212,168,67,0.7)", fontSize:13, fontFamily:"DM Sans,sans-serif",
          fontWeight:600, width:"100%", transition:"all .2s",
        }}
          onMouseEnter={e=>{e.currentTarget.style.background="rgba(212,168,67,0.1)";e.currentTarget.style.borderColor="rgba(212,168,67,0.4)";}}
          onMouseLeave={e=>{e.currentTarget.style.background="rgba(212,168,67,0.06)";e.currentTarget.style.borderColor="rgba(212,168,67,0.25)";}}
        >
          <span style={{fontSize:18}}>+</span> Add Task
        </button>
      ) : (
        <div style={{
          padding:"14px 16px", borderRadius:14,
          background:"rgba(212,168,67,0.04)",
          border:"1px solid rgba(212,168,67,0.2)",
          display:"flex", flexDirection:"column", gap:10,
          animation:"fadeUp .2s ease",
        }}>
          <input
            autoFocus
            value={txt}
            onChange={e=>setTxt(e.target.value)}
            onKeyDown={e=>{ if(e.key==="Enter") add(); if(e.key==="Escape") setOpen(false); }}
            placeholder="Task likhein… (Enter = save)"
            style={{
              background:"rgba(255,255,255,0.04)", border:"1px solid rgba(212,168,67,0.25)",
              borderRadius:10, padding:"10px 14px", color:"#F7EDD8",
              fontSize:14, fontFamily:"DM Sans,sans-serif", outline:"none", width:"100%",
            }}
          />
          <div style={{ display:"flex", gap:8, alignItems:"center" }}>
            <span style={{ fontSize:12, color:"rgba(247,237,216,0.45)" }}>Priority:</span>
            {["high","medium","low"].map(p => (
              <button key={p} onClick={()=>setPriority(p)} style={{
                padding:"4px 12px", borderRadius:20, border:"none", cursor:"pointer",
                fontSize:11, fontWeight:700, fontFamily:"DM Sans,sans-serif",
                background: priority===p
                  ? (p==="high"?"rgba(248,113,113,0.25)":p==="medium"?"rgba(251,191,36,0.25)":"rgba(74,222,128,0.2)")
                  : "rgba(255,255,255,0.04)",
                color: priority===p
                  ? (p==="high"?"#f87171":p==="medium"?"#fbbf24":"#4ade80")
                  : "rgba(247,237,216,0.35)",
              }}>{p}</button>
            ))}
            <div style={{ marginLeft:"auto", display:"flex", gap:6 }}>
              <button onClick={add} disabled={!txt.trim()||saving} style={{
                padding:"6px 16px", borderRadius:10, border:"none", cursor:"pointer",
                background:"linear-gradient(135deg,#A07830,#D4A843)", color:"#030201",
                fontWeight:700, fontSize:12, fontFamily:"DM Sans,sans-serif",
                opacity:!txt.trim()||saving?0.5:1,
              }}>
                {saving?"…":"+ Add"}
              </button>
              <button onClick={()=>{setOpen(false);setTxt("");}} style={{
                padding:"6px 12px", borderRadius:10, cursor:"pointer",
                background:"rgba(255,255,255,0.04)", border:"1px solid rgba(255,255,255,0.1)",
                color:"rgba(247,237,216,0.4)", fontSize:12, fontFamily:"DM Sans,sans-serif",
              }}>Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
