// ─────────────────────────────────────────────────────────────────────────────
// BRAND SETTINGS TAB — Owner/ACEO only
// Change WA number, email, website from inside the portal easily
// ─────────────────────────────────────────────────────────────────────────────
function BrandSettingsTab({ db }) {
  return (
    <div style={{ padding:"24px 24px 80px", maxWidth:600, margin:"0 auto" }}>
      <h2 style={{ fontSize:22, fontWeight:700, color:C.gold, marginBottom:6 }}>
        ⚙️ Brand Settings
      </h2>
      <p style={{ fontSize:13, color:C.muted, marginBottom:28 }}>
        Update your portal-wide contact details. Changes apply instantly across all WA buttons, links, and notifications.
      </p>
      <div style={{ background:"rgba(255,255,255,0.03)", border:"1px solid rgba(212,168,67,0.15)", borderRadius:16, padding:24 }}>
        <BrandSettingsWidget db={db}/>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// BRAND SETTINGS WIDGET
// Owner can update WA number, email, website from inside the portal
// Changes save to Firestore → reflected everywhere instantly
// ─────────────────────────────────────────────────────────────────────────────
function BrandSettingsWidget({ db }) {
  const [waNum,    setWaNum]    = useState(BRAND_WA);
  const [email,    setEmail]    = useState(OWNER_EMAIL);
  const [website,  setWebsite]  = useState(WEBSITE_URL);
  const [saving,   setSaving]   = useState(false);
  const [saved,    setSaved]    = useState(false);
  const [loading,  setLoading]  = useState(true);

  // Load from Firestore on mount
  useEffect(() => {
    if (!db) { setLoading(false); return; }
    fsGet(fsDoc(db, "meta", "brandConfig")).then(snap => {
      if (snap.exists()) {
        const d = snap.data();
        if (d.waNum)   setWaNum(d.waNum);
        if (d.email)   setEmail(d.email);
        if (d.website) setWebsite(d.website);
      }
    }).catch(() => {}).finally(() => setLoading(false));
  }, [db]);

  const save = async () => {
    setSaving(true);
    try {
      await fsSet(fsDoc(db, "meta", "brandConfig"), {
        waNum:   waNum.trim(),
        email:   email.trim(),
        website: website.trim(),
        updatedAt: new Date().toISOString(),
        updatedBy: "owner",
      }, { merge: true });
      setSaved(true);
      setTimeout(() => setSaved(false), 3000);
    } catch(e) {
      alert("Save failed: " + e.message);
    }
    setSaving(false);
  };

  const inp = {
    width: "100%",
    background: "rgba(255,255,255,0.04)",
    border: "1px solid rgba(212,168,67,0.2)",
    borderRadius: 10,
    padding: "10px 14px",
    color: "#F7EDD8",
    fontSize: 13,
    fontFamily: "DM Sans,sans-serif",
    outline: "none",
    marginTop: 6,
  };

  if (loading) return (
    <p style={{ fontSize:12, color:"rgba(247,237,216,0.4)" }}>Loading brand settings...</p>
  );

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:14 }}>

      {/* WhatsApp Number */}
      <div>
        <label style={{ fontSize:11, fontWeight:700, color:"rgba(212,168,67,0.6)", letterSpacing:"0.5px", textTransform:"uppercase" }}>
          📱 WhatsApp Number
        </label>
        <input
          value={waNum}
          onChange={e => setWaNum(e.target.value)}
          placeholder="+923183916019"
          style={inp}
        />
        <p style={{ fontSize:10, color:"rgba(247,237,216,0.3)", marginTop:4 }}>
          Format: 92 followed by number without 0 — e.g. 923183916019
        </p>
      </div>

      {/* Email */}
      <div>
        <label style={{ fontSize:11, fontWeight:700, color:"rgba(212,168,67,0.6)", letterSpacing:"0.5px", textTransform:"uppercase" }}>
          📧 Owner Email
        </label>
        <input
          value={email}
          onChange={e => setEmail(e.target.value)}
          placeholder="teamaskhushboo@gmail.com"
          style={inp}
        />
      </div>

      {/* Website */}
      <div>
        <label style={{ fontSize:11, fontWeight:700, color:"rgba(212,168,67,0.6)", letterSpacing:"0.5px", textTransform:"uppercase" }}>
          🌐 Website URL
        </label>
        <input
          value={website}
          onChange={e => setWebsite(e.target.value)}
          placeholder="https://askhushboo.com"
          style={inp}
        />
      </div>

      {/* Current values preview */}
      <div style={{ padding:"12px 14px", background:"rgba(255,255,255,0.02)", borderRadius:10, border:"1px solid rgba(212,168,67,0.08)" }}>
        <p style={{ fontSize:10, color:"rgba(212,168,67,0.5)", fontWeight:700, textTransform:"uppercase", letterSpacing:"0.5px", marginBottom:8 }}>
          Current Active Values
        </p>
        {[
          { icon:"💚", label:"WA",      val: waNum   },
          { icon:"📧", label:"Email",   val: email   },
          { icon:"🌐", label:"Website", val: website },
        ].map(({ icon, label, val }) => (
          <div key={label} style={{ display:"flex", gap:8, alignItems:"center", marginBottom:4 }}>
            <span style={{ fontSize:13 }}>{icon}</span>
            <span style={{ fontSize:10, color:"rgba(212,168,67,0.5)", width:50 }}>{label}</span>
            <span style={{ fontSize:12, color:"#F7EDD8", fontFamily:"monospace" }}>{val}</span>
          </div>
        ))}
      </div>

      {/* Save button */}
      <button
        onClick={save}
        disabled={saving}
        style={{
          padding: "12px 24px",
          borderRadius: 12,
          border: "none",
          cursor: saving ? "wait" : "pointer",
          background: saved
            ? "rgba(74,222,128,0.15)"
            : "linear-gradient(135deg,#A07830,#D4A843,#F0C84A)",
          color: saved ? "#4ade80" : "#030201",
          fontWeight: 800,
          fontSize: 14,
          fontFamily: "DM Sans,sans-serif",
          transition: "all 0.2s",
        }}
      >
        {saving ? "Saving..." : saved ? "✅ Saved! Applied portal-wide" : "💾 Save Brand Settings"}
      </button>

      <p style={{ fontSize:11, color:"rgba(247,237,216,0.3)", lineHeight:1.6 }}>
        ⚠️ Note: These values update in Firestore immediately. The portal's JS constants (BRAND_WA, OWNER_EMAIL, WEBSITE_URL) are defaults — Firestore values always take priority at runtime for WA buttons and links.
      </p>
    </div>
  );
}

function WorkflowTab({ orders, members, db, user, role, access,
  slaConfig, setSlaConfig, orderTasks, setOrderTasks }) {

  const [sub,      setSub]      = useState("board");
  const [filter,   setFilter]   = useState("all");
  const [savedMsg, setSavedMsg] = useState("");
  const [localCfg, setLocalCfg] = useState(slaConfig);

  useEffect(() => { setLocalCfg(slaConfig); }, [slaConfig]);

  const isAdmin = ["owner", "aceo"].includes(role);

  // ── Filter tasks by role ──────────────────────────────────────────────────
  const myTasks = orderTasks.filter(t =>
    isAdmin ? true : (t.role === role || t.assignedUid === user?.uid)
  );
  const activeTasks = myTasks.filter(t => t.status !== "done");
  const doneTasks   = myTasks.filter(t => t.status === "done");
  const shown = filter === "done"    ? doneTasks
    :           filter === "all"     ? activeTasks
    :                                  activeTasks.filter(t => t.priority === filter);

  // ── Orders with SLA ───────────────────────────────────────────────────────
  const activeOrders = orders
    .filter(o => !["delivered","cancelled"].includes(o.status || ""))
    .map(o => ({ ...o, sla: checkSLA(o, slaConfig), prio: calcPriority(o) }))
    .sort((a, b) => b.prio.score - a.prio.score);

  const breachCount = activeOrders.filter(o => o.sla?.breach).length;
  const warnCount   = activeOrders.filter(o => o.sla?.warn75).length;
  const critCount   = activeOrders.filter(o => o.prio?.level === "critical").length;

  // ── Task Actions ──────────────────────────────────────────────────────────
  const completeTask = async (id) => {
    const updated = orderTasks.map(t =>
      t.id === id
        ? { ...t, status:"done", completedAt:new Date().toISOString(),
            completedBy: user?.displayName || user?.email?.split("@")[0] || "Team" }
        : t
    );
    setOrderTasks(updated);
    try { await fsSet(fsDoc(db,"orderTasks","all"),{tasks:updated}); } catch {}
  };

  const reassign = async (id, newRole) => {
    const m = members.find(x => x.role === newRole && x.role !== "removed");
    const updated = orderTasks.map(t =>
      t.id === id
        ? { ...t, role:newRole,
            assignedTo: m?.name || m?.email?.split("@")[0] || newRole,
            assignedUid: m?.uid || null }
        : t
    );
    setOrderTasks(updated);
    try { await fsSet(fsDoc(db,"orderTasks","all"),{tasks:updated}); } catch {}
  };

  const saveSLA = async () => {
    setSlaConfig(localCfg);
    try {
      await fsSet(fsDoc(db,"workflowSettings","config"),
        { slaConfig:localCfg }, { merge:true });
      setSavedMsg("✅ SLA settings saved!");
      setTimeout(() => setSavedMsg(""), 2500);
    } catch {}
  };

  const fmtLeft = (iso) => {
    if (!iso) return "";
    const d = new Date(iso) - new Date();
    if (d < 0) return "OVERDUE";
    const h = Math.floor(d/3600000), m = Math.floor((d%3600000)/60000);
    return h > 0 ? `${h}h ${m}m` : `${m}m baqi`;
  };

  const PC = { critical:"#f87171", high:"#fbbf24", medium:"#60a5fa", low:"#4ade80" };
  const goldGrad = "linear-gradient(135deg,#A07830,#D4A843,#F0C84A,#FFE98A)";

  return (
    <div className="fadeUp" style={{ padding:16, display:"flex", flexDirection:"column", gap:16 }}>

      {/* ── Header Stats ── */}
      <div style={{ background:"linear-gradient(135deg,rgba(212,168,67,0.08),rgba(10,8,6,0.97))",
        border:"1px solid rgba(212,168,67,0.25)", borderRadius:20, padding:"20px 24px",
        position:"relative", overflow:"hidden" }}>
        <div style={{ position:"absolute",top:0,left:0,right:0,height:2, background:goldGrad }}/>
        <div style={{ display:"flex",justifyContent:"space-between",alignItems:"flex-start",flexWrap:"wrap",gap:12 }}>
          <div>
            <h2 style={{ fontFamily:"Cinzel,serif",fontSize:18,color:"#F7EDD8",letterSpacing:"1px",margin:"0 0 4px" }}>
              ⚡ Order Workflow
            </h2>
            <p style={{ fontSize:12,color:"rgba(247,237,216,0.4)",margin:0 }}>
              SLA tracking · Auto-tasks · Priority scoring · WA automation
            </p>
          </div>
          <div style={{ display:"flex",gap:8,flexWrap:"wrap" }}>
            {[
              { v:breachCount, l:"SLA Breach", c:"#f87171", warn:breachCount>0 },
              { v:warnCount,   l:"At Risk",    c:"#fbbf24", warn:false },
              { v:critCount,   l:"Critical",   c:"#D4A843", warn:false },
              { v:activeTasks.length, l:"My Tasks", c:"#60a5fa", warn:false },
            ].map(k => (
              <div key={k.l} style={{ padding:"10px 14px",borderRadius:12,textAlign:"center",
                background:k.warn?"rgba(248,113,113,0.08)":"rgba(212,168,67,0.06)",
                border:k.warn?"1px solid rgba(248,113,113,0.3)":"1px solid rgba(212,168,67,0.12)",
                animation:k.warn&&k.v>0?"glow 2s ease infinite":"none" }}>
                <div style={{ fontFamily:"Cormorant Garamond,serif",fontSize:22,fontWeight:700,color:k.c }}>{k.v}</div>
                <div style={{ fontSize:9,color:"rgba(247,237,216,0.35)",textTransform:"uppercase",letterSpacing:"0.5px" }}>{k.l}</div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ── Sub Tabs ── */}
      <div style={{ display:"flex",gap:8,flexWrap:"wrap" }}>
        {[
          ["board","📋 Tasks"],
          ["sla","⏱ SLA Monitor"],
          ...(isAdmin ? [["settings","⚙️ Settings"],["analytics","📊 Analytics"]] : []),
        ].map(([k,l]) => (
          <button key={k} onClick={() => setSub(k)} style={{
            padding:"8px 16px",borderRadius:10,border:"none",cursor:"pointer",
            fontFamily:"DM Sans,sans-serif",fontWeight:700,fontSize:12,transition:"all 0.2s",
            background:sub===k?goldGrad:"rgba(212,168,67,0.06)",
            color:sub===k?"#030201":"rgba(247,237,216,0.55)",
          }}>{l}</button>
        ))}
      </div>

      {/* ══════════════ TASK BOARD ══════════════ */}
      {sub === "board" && (
        <div style={{ display:"flex",flexDirection:"column",gap:12 }}>
          {/* Filter pills */}
          <div style={{ display:"flex",gap:6,flexWrap:"wrap",alignItems:"center" }}>
            {[["all","All Active"],["critical","🔴 Critical"],["high","🟡 High"],
              ["medium","🔵 Medium"],["done","✅ Done"]].map(([k,l]) => (
              <button key={k} onClick={() => setFilter(k)} style={{
                padding:"5px 12px",borderRadius:20,border:"none",cursor:"pointer",
                fontSize:11,fontWeight:600,transition:"all 0.2s",
                background:filter===k?goldGrad:"rgba(212,168,67,0.06)",
                color:filter===k?"#030201":"rgba(247,237,216,0.4)",
              }}>{l}</button>
            ))}
            <span style={{ marginLeft:"auto",fontSize:11,color:"rgba(247,237,216,0.35)" }}>
              {shown.length} tasks
            </span>
          </div>

          {shown.length === 0 && (
            <div style={{ background:"rgba(212,168,67,0.03)",border:"1px solid rgba(212,168,67,0.12)",
              borderRadius:16,padding:"40px 24px",textAlign:"center" }}>
              <div style={{ fontSize:48,marginBottom:12,opacity:.3 }}>✅</div>
              <p style={{ fontSize:13,color:"rgba(247,237,216,0.35)" }}>
                {filter==="done" ? "No completed tasks yet"
                  : "No pending tasks! Tasks will auto-create when orders come in."}
              </p>
            </div>
          )}

          {shown.map(task => {
            const pc      = PC[task.priority] || "#D4A843";
            const left    = task.dueDate ? fmtLeft(task.dueDate) : "";
            const overdue = left === "OVERDUE";
            const done    = task.status === "done";
            const mp      = members.find(m => m.role===task.role && m.phone && m.role!=="removed");
            return (
              <div key={task.id} style={{
                background: overdue?"rgba(248,113,113,0.04)":done?"rgba(74,222,128,0.03)":"rgba(212,168,67,0.03)",
                border:`1px solid ${overdue?"rgba(248,113,113,0.3)":done?"rgba(74,222,128,0.2)":pc+"33"}`,
                borderLeft:`3px solid ${overdue?"#f87171":done?"#4ade80":pc}`,
                borderRadius:14,padding:"14px 18px",opacity:done?0.55:1,
              }}>
                <div style={{ display:"flex",justifyContent:"space-between",alignItems:"flex-start",flexWrap:"wrap",gap:10 }}>
                  <div style={{ flex:1 }}>
                    <p style={{ fontWeight:700,fontSize:14,color:"#F7EDD8",marginBottom:4,
                      textDecoration:done?"line-through":"none" }}>{task.title}</p>
                    <div style={{ display:"flex",gap:6,flexWrap:"wrap",marginBottom:6 }}>
                      <span style={{ padding:"2px 8px",borderRadius:20,fontSize:9,fontWeight:700,
                        background:`${pc}18`,color:pc,border:`1px solid ${pc}40` }}>
                        {(task.priority||"").toUpperCase()}
                      </span>
                      <span style={{ padding:"2px 8px",borderRadius:20,fontSize:9,
                        background:"rgba(212,168,67,0.1)",color:"#D4A843",border:"1px solid rgba(212,168,67,0.25)" }}>
                        📋 {task.orderId}
                      </span>
                      {!done && left && (
                        <span style={{ padding:"2px 8px",borderRadius:20,fontSize:9,fontWeight:700,
                          background:overdue?"rgba(248,113,113,0.15)":"rgba(74,222,128,0.1)",
                          color:overdue?"#f87171":"#4ade80",
                          border:`1px solid ${overdue?"rgba(248,113,113,0.3)":"rgba(74,222,128,0.3)"}`,
                          animation:overdue?"pulse 1.5s ease infinite":"none" }}>
                          ⏱ {left}
                        </span>
                      )}
                      <span style={{ padding:"2px 8px",borderRadius:20,fontSize:9,
                        background:"rgba(255,255,255,0.04)",color:"rgba(247,237,216,0.35)" }}>
                        👤 {task.assignedTo}
                      </span>
                    </div>
                    <p style={{ fontSize:12,color:"rgba(247,237,216,0.45)",lineHeight:1.5,margin:0 }}>{task.desc}</p>
                    {done && task.completedBy && (
                      <p style={{ fontSize:11,color:"#4ade80",marginTop:4 }}>
                        ✅ {task.completedBy} · {new Date(task.completedAt||"").toLocaleDateString("en-PK")}
                      </p>
                    )}
                  </div>
                  {!done && (
                    <div style={{ display:"flex",flexDirection:"column",gap:6,minWidth:110 }}>
                      <button onClick={() => completeTask(task.id)} style={{
                        padding:"7px 14px",borderRadius:10,cursor:"pointer",fontWeight:700,fontSize:11,
                        background:"rgba(74,222,128,0.1)",color:"#4ade80",
                        border:"1px solid rgba(74,222,128,0.3)",fontFamily:"DM Sans,sans-serif" }}>
                        ✓ Done
                      </button>
                      {task.phone && (
                        <a href={`https://wa.me/92${task.phone.replace(/^0/,"").replace(/\D/g,"")}?text=${encodeURIComponent(
                          (CHANNEL_WA[task.channel]?.cust?.(task)) ||
                          `Salam ${task.customer}! BrandFlow order ${task.orderId} update.`
                        )}`} target="_blank" rel="noreferrer" style={{
                          padding:"6px 12px",borderRadius:10,cursor:"pointer",fontWeight:700,fontSize:11,
                          background:"rgba(212,168,67,0.06)",color:"#D4A843",
                          border:"1px solid rgba(212,168,67,0.25)",textDecoration:"none",textAlign:"center",
                          fontFamily:"DM Sans,sans-serif",display:"block" }}>
                          💬 Customer
                        </a>
                      )}
                      {mp && isAdmin && (
                        <a href={`https://wa.me/92${mp.phone.replace(/^0/,"").replace(/\D/g,"")}?text=${encodeURIComponent(
                          `🔔 Task Reminder:\n${task.title}\nOrder: ${task.orderId}\n${overdue?"⚠️ OVERDUE!":"Due: "+left}`
                        )}`} target="_blank" rel="noreferrer" style={{
                          padding:"6px 12px",borderRadius:10,cursor:"pointer",fontWeight:600,fontSize:11,
                          background:"rgba(255,255,255,0.03)",color:"rgba(247,237,216,0.4)",
                          border:"1px solid rgba(255,255,255,0.08)",textDecoration:"none",textAlign:"center",
                          fontFamily:"DM Sans,sans-serif",display:"block" }}>
                          📱 Ping Team
                        </a>
                      )}
                    </div>
                  )}
                </div>
                {/* Reassign — owner/ACEO only */}
                {isAdmin && !done && (
                  <div style={{ marginTop:10,paddingTop:10,borderTop:"1px solid rgba(212,168,67,0.08)",
                    display:"flex",gap:6,alignItems:"center",flexWrap:"wrap" }}>
                    <span style={{ fontSize:11,color:"rgba(247,237,216,0.35)" }}>Reassign:</span>
                    {["sales","customer_service","packaging","inventory","marketing","social_media"].map(r => (
                      <button key={r} onClick={() => reassign(task.id, r)} style={{
                        padding:"3px 10px",borderRadius:20,cursor:"pointer",fontSize:10,
                        fontFamily:"DM Sans,sans-serif",fontWeight:600,
                        background:task.role===r?"rgba(212,168,67,0.15)":"rgba(212,168,67,0.04)",
                        color:task.role===r?"#D4A843":"rgba(247,237,216,0.38)",
                        border:"1px solid rgba(212,168,67,0.2)" }}>
                        {r.replace(/_/g," ")}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* ══════════════ SLA MONITOR ══════════════ */}
      {sub === "sla" && (
        <div style={{ display:"flex",flexDirection:"column",gap:12 }}>
          <p style={{ fontSize:13,color:"rgba(247,237,216,0.4)" }}>
            Active orders ka SLA — 🔴 breach · 🟡 warning (75%+) · 🟢 on track
          </p>
          {activeOrders.length === 0 && (
            <div style={{ background:"rgba(212,168,67,0.03)",border:"1px solid rgba(212,168,67,0.12)",
              borderRadius:16,padding:"40px",textAlign:"center",color:"rgba(247,237,216,0.35)" }}>
              Koi active order nahi
            </div>
          )}
          {activeOrders.map((o, i) => {
            const sla  = o.sla;
            const prio = o.prio;
            const pc   = PC[prio?.level] || "#D4A843";
            return (
              <div key={o.orderId||i} style={{
                background:sla?.breach?"rgba(248,113,113,0.04)":sla?.warn75?"rgba(251,191,36,0.04)":"rgba(212,168,67,0.03)",
                border:`1px solid ${sla?.breach?"rgba(248,113,113,0.3)":sla?.warn75?"rgba(251,191,36,0.25)":"rgba(212,168,67,0.12)"}`,
                borderRadius:16,padding:"16px 20px",
              }}>
                <div style={{ display:"flex",justifyContent:"space-between",alignItems:"flex-start",flexWrap:"wrap",gap:10,marginBottom:12 }}>
                  <div>
                    <div style={{ display:"flex",gap:8,alignItems:"center",marginBottom:4,flexWrap:"wrap" }}>
                      <span style={{ fontSize:14,fontWeight:700,color:"#F7EDD8" }}>{o.product} ×{o.qty||1}</span>
                      <span style={{ padding:"2px 8px",borderRadius:20,fontSize:9,fontWeight:700,
                        background:`${pc}18`,color:pc,border:`1px solid ${pc}40` }}>
                        {prio?.emoji} {prio?.label} ({prio?.score})
                      </span>
                      {sla?.breach && (
                        <span style={{ padding:"2px 8px",borderRadius:20,fontSize:9,fontWeight:800,
                          background:"rgba(248,113,113,0.15)",color:"#f87171",
                          border:"1px solid rgba(248,113,113,0.3)",animation:"pulse 1s ease infinite" }}>
                          🚨 SLA BREACH
                        </span>
                      )}
                      {sla?.warn75 && !sla.breach && (
                        <span style={{ padding:"2px 8px",borderRadius:20,fontSize:9,fontWeight:800,
                          background:"rgba(251,191,36,0.15)",color:"#fbbf24",
                          border:"1px solid rgba(251,191,36,0.3)" }}>
                          ⚠️ AT RISK
                        </span>
                      )}
                    </div>
                    <div style={{ display:"flex",gap:8,flexWrap:"wrap" }}>
                      <span style={{ fontSize:12,color:"rgba(247,237,216,0.5)" }}>{o.customer||"Customer"}</span>
                      <span style={{ fontSize:12,color:"#D4A843" }}>·</span>
                      <span style={{ fontSize:12,color:"#D4A843",fontWeight:600 }}>
                        Rs.{Number(o.revenue||0).toLocaleString()}
                      </span>
                      <span style={{ fontSize:12,color:"#D4A843" }}>·</span>
                      <span style={{ fontSize:12,color:"rgba(247,237,216,0.4)" }}>{o.channel}</span>
                    </div>
                  </div>
                  <div style={{ textAlign:"right" }}>
                    <div style={{ fontSize:13,fontWeight:700,color:sla?.color||"#D4A843" }}>
                      {sla?.label || "—"}
                    </div>
                    <div style={{ fontSize:11,color:"rgba(247,237,216,0.38)" }}>Status: {o.status}</div>
                  </div>
                </div>
                {sla && (
                  <div style={{ marginBottom:10 }}>
                    <div style={{ display:"flex",justifyContent:"space-between",marginBottom:4 }}>
                      <span style={{ fontSize:10,color:"rgba(247,237,216,0.38)" }}>
                        {sla.cfg?.emoji} {sla.cfg?.label}
                      </span>
                      <span style={{ fontSize:10,fontWeight:700,color:sla.color }}>{sla.pct}%</span>
                    </div>
                    <div style={{ height:6,background:"rgba(255,255,255,0.05)",borderRadius:3,overflow:"hidden" }}>
                      <div style={{ width:`${sla.pct}%`,height:"100%",borderRadius:3,
                        background:`linear-gradient(90deg,${sla.color}80,${sla.color})`,
                        transition:"width 0.5s ease",boxShadow:`0 0 8px ${sla.color}60` }}/>
                    </div>
                  </div>
                )}
                <div style={{ display:"flex",gap:6,flexWrap:"wrap" }}>
                  {o.phone && (
                    <a href={`https://wa.me/92${o.phone.replace(/^0/,"").replace(/\D/g,"")}`}
                      target="_blank" rel="noreferrer" style={{
                        padding:"5px 12px",borderRadius:10,fontSize:11,fontWeight:700,
                        background:"rgba(37,211,102,0.1)",color:"#4ade80",
                        border:"1px solid rgba(37,211,102,0.3)",textDecoration:"none" }}>
                      💬 Customer WA
                    </a>
                  )}
                  {sla?.breach && (
                    <a href={`https://wa.me/${BRAND_WA}?text=${encodeURIComponent(
                      `🚨 SLA Breach!\nOrder: ${o.orderId}\n${o.product} | ${o.status}\n${sla.label}\nForan action lo!`
                    )}`} target="_blank" rel="noreferrer" style={{
                      padding:"5px 12px",borderRadius:10,fontSize:11,fontWeight:700,
                      background:"rgba(248,113,113,0.1)",color:"#f87171",
                      border:"1px solid rgba(248,113,113,0.3)",textDecoration:"none" }}>
                      🚨 Escalate to Owner
                    </a>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* ══════════════ SETTINGS ══════════════ */}
      {sub === "settings" && isAdmin && (
        <div style={{ display:"flex",flexDirection:"column",gap:16 }}>
          {savedMsg && (
            <div style={{ padding:"10px 16px",borderRadius:10,
              background:"rgba(74,222,128,0.08)",border:"1px solid rgba(74,222,128,0.3)",
              color:"#4ade80",fontSize:13 }}>{savedMsg}</div>
          )}
          <div style={{ background:"rgba(212,168,67,0.03)",border:"1px solid rgba(212,168,67,0.15)",
            borderRadius:18,padding:"20px 22px" }}>
            <h3 style={{ fontFamily:"Cinzel,serif",fontSize:13,color:"#D4A843",letterSpacing:"0.8px",marginBottom:16 }}>
              ⏱ SLA Time Limits (Owner/ACEO adjust kar sakte hain)
            </h3>
            <div style={{ display:"flex",flexDirection:"column",gap:12 }}>
              {Object.entries(localCfg).map(([key,cfg]) => (
                <div key={key} style={{ padding:"14px 16px",
                  background:"rgba(212,168,67,0.04)",border:"1px solid rgba(212,168,67,0.1)",
                  borderRadius:12,display:"flex",justifyContent:"space-between",
                  alignItems:"center",flexWrap:"wrap",gap:12 }}>
                  <div>
                    <p style={{ fontWeight:700,fontSize:13,color:"#F7EDD8",marginBottom:2 }}>
                      {cfg.emoji} {cfg.label}
                    </p>
                    <p style={{ fontSize:11,color:"rgba(247,237,216,0.4)" }}>
                      Role: {cfg.role?.replace(/_/g," ")} · Stage: {key.replace(/_/g," ")}
                    </p>
                  </div>
                  <div style={{ display:"flex",gap:8,alignItems:"center" }}>
                    <button onClick={() => setLocalCfg(p=>({...p,[key]:{...cfg,hours:Math.max(1,cfg.hours-4)}}))}
                      style={{ padding:"6px 12px",borderRadius:10,cursor:"pointer",fontWeight:700,fontSize:12,
                        background:"rgba(212,168,67,0.06)",color:"#D4A843",
                        border:"1px solid rgba(212,168,67,0.25)",fontFamily:"DM Sans,sans-serif" }}>
                      −4h
                    </button>
                    <span style={{ minWidth:60,textAlign:"center",
                      fontFamily:"Cormorant Garamond,serif",fontSize:24,fontWeight:700,color:"#D4A843" }}>
                      {cfg.hours}h
                    </span>
                    <button onClick={() => setLocalCfg(p=>({...p,[key]:{...cfg,hours:cfg.hours+4}}))}
                      style={{ padding:"6px 12px",borderRadius:10,cursor:"pointer",fontWeight:700,fontSize:12,
                        background:"rgba(212,168,67,0.06)",color:"#D4A843",
                        border:"1px solid rgba(212,168,67,0.25)",fontFamily:"DM Sans,sans-serif" }}>
                      +4h
                    </button>
                  </div>
                </div>
              ))}
            </div>
            <div style={{ marginTop:16,display:"flex",gap:10,alignItems:"center" }}>
              <button onClick={saveSLA} style={{
                padding:"11px 24px",borderRadius:10,cursor:"pointer",fontWeight:700,fontSize:13,
                background:goldGrad,color:"#030201",border:"none",fontFamily:"DM Sans,sans-serif" }}>
                💾 Save SLA Settings
              </button>
              <button onClick={() => setLocalCfg(DEFAULT_SLA_CONFIG)} style={{
                padding:"9px 18px",borderRadius:10,cursor:"pointer",fontWeight:600,fontSize:12,
                background:"rgba(212,168,67,0.06)",color:"#D4A843",
                border:"1px solid rgba(212,168,67,0.25)",fontFamily:"DM Sans,sans-serif" }}>
                Reset to Default
              </button>
            </div>
          </div>

          <div style={{ background:"rgba(212,168,67,0.03)",border:"1px solid rgba(212,168,67,0.15)",
            borderRadius:18,padding:"20px 22px" }}>
            <h3 style={{ fontFamily:"Cinzel,serif",fontSize:13,color:"#D4A843",marginBottom:14 }}>
              📡 Channel → Role Auto-Assignment
            </h3>
            <p style={{ fontSize:12,color:"rgba(247,237,216,0.4)",marginBottom:14 }}>
              Jab order aata hai, channel se yeh role automatically primary responsible hoti hai aur WA message auto-draft hota hai.
            </p>
            <div style={{ display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(170px,1fr))",gap:10 }}>
              {Object.entries(CHANNEL_WA).map(([ch,cfg]) => (
                <div key={ch} style={{ padding:"12px 14px",
                  background:"rgba(212,168,67,0.04)",border:"1px solid rgba(212,168,67,0.1)",borderRadius:10 }}>
                  <p style={{ fontWeight:700,fontSize:13,color:"#F7EDD8",marginBottom:4 }}>{ch}</p>
                  <p style={{ fontSize:11,color:"#D4A843" }}>Primary: {cfg.role.replace(/_/g," ")}</p>
                  <p style={{ fontSize:11,color:"rgba(247,237,216,0.38)" }}>Backup: {cfg.backup.replace(/_/g," ")}</p>
                </div>
              ))}
            </div>

          {/* ── BRAND SETTINGS ── */}
          <div style={{ background:"rgba(212,168,67,0.03)",border:"1px solid rgba(212,168,67,0.15)",
            borderRadius:18,padding:"20px 22px" }}>
            <h3 style={{ fontFamily:"Cinzel,serif",fontSize:13,color:"#D4A843",letterSpacing:"0.8px",marginBottom:6 }}>
              📱 Brand Contact Settings
            </h3>
            <p style={{ fontSize:12,color:"rgba(247,237,216,0.4)",marginBottom:16 }}>
              Update the WhatsApp number, email, and website used across the entire portal.
              Changes save to Firestore and apply immediately.
            </p>
            <BrandSettingsWidget db={db}/>
          </div>
          </div>
        </div>
      )}

      {/* ══════════════ ANALYTICS ══════════════ */}
      {sub === "analytics" && isAdmin && (
        <div style={{ display:"flex",flexDirection:"column",gap:16 }}>
          <div style={{ display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(130px,1fr))",gap:12 }}>
            {[
              { icon:"✅",l:"Done",    v:orderTasks.filter(t=>t.status==="done").length,    c:"#4ade80" },
              { icon:"⏳",l:"Pending", v:orderTasks.filter(t=>t.status==="pending").length, c:"#fbbf24" },
              { icon:"🚨",l:"SLA Breach",v:breachCount, c:"#f87171" },
              { icon:"⚠️",l:"At Risk",  v:warnCount,   c:"#fbbf24" },
              { icon:"🔴",l:"Critical",  v:critCount,   c:"#f87171" },
              { icon:"📦",l:"Active",    v:activeOrders.length, c:"#D4A843" },
            ].map(k => (
              <div key={k.l} style={{ background:"rgba(212,168,67,0.03)",
                border:"1px solid rgba(212,168,67,0.12)",borderRadius:16,padding:"16px 12px",textAlign:"center" }}>
                <div style={{ fontSize:22,marginBottom:6 }}>{k.icon}</div>
                <div style={{ fontFamily:"Cormorant Garamond,serif",fontSize:26,fontWeight:700,
                  color:k.c,marginBottom:2 }}>{k.v}</div>
                <div style={{ fontSize:10,color:"rgba(247,237,216,0.38)",textTransform:"uppercase" }}>{k.l}</div>
              </div>
            ))}
          </div>

          <div style={{ background:"rgba(212,168,67,0.03)",border:"1px solid rgba(212,168,67,0.12)",
            borderRadius:18,padding:20 }}>
            <h3 style={{ fontFamily:"Cinzel,serif",fontSize:13,color:"#D4A843",marginBottom:14 }}>
              Task Completion by Role
            </h3>
            {["sales","customer_service","packaging","inventory","marketing","social_media"].map(r => {
              const total = orderTasks.filter(t=>t.role===r).length;
              const done  = orderTasks.filter(t=>t.role===r&&t.status==="done").length;
              const pct   = total>0?Math.round((done/total)*100):0;
              return (
                <div key={r} style={{ marginBottom:12 }}>
                  <div style={{ display:"flex",justifyContent:"space-between",marginBottom:4 }}>
                    <span style={{ fontSize:13 }}>{r.replace(/_/g," ")}</span>
                    <span style={{ fontSize:12,fontWeight:600,
                      color:pct>=80?"#4ade80":pct>=50?"#fbbf24":"#f87171" }}>
                      {done}/{total} ({pct}%)
                    </span>
                  </div>
                  <div style={{ background:"rgba(212,168,67,0.08)",borderRadius:4,height:5,overflow:"hidden" }}>
                    <div style={{ width:`${pct}%`,height:"100%",borderRadius:4,
                      background:pct>=80?"#4ade80":pct>=50?"#fbbf24":"#f87171",
                      transition:"width .6s ease" }}/>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}
