// ─── MAIN APP ─────────────────────────────────────────────────────────────────
// ─── ATTENDANCE CLOCK-IN POPUP COMPONENT ─────────────────────────────────────
function AttendanceClockInPopup({ user, role, db, onClose, onClockIn }) {
  const [note, setNote]           = useState("");
  const [lateReason, setLateReason] = useState("");
  const [loading, setLoading]     = useState(false);
  const [todayRecord, setTodayRecord] = useState(null);
  const [checkingRecord, setCheckingRecord] = useState(true);

  const parseHHMM = (str) => { const [h,m]=(str||"09:00").split(":").map(Number); return h*60+(m||0); };

  useEffect(() => {
    const check = async () => {
      if (!db || !user) { setCheckingRecord(false); return; }
      try {
        const today = new Date().toISOString().split("T")[0];
        const ref   = fsDoc(db, "attendance", today, "records", user.uid);
        const snap  = await fsGet(ref);
        setTodayRecord(snap.exists() ? snap.data() : null);
      } catch(e) {}
      setCheckingRecord(false);
    };
    check();
  }, [db, user]);

  // Owner ka attendance track nahi hota
  if (role === "owner") return null;
  if (checkingRecord) return null;
  // Already clocked in today - don't show popup
  if (todayRecord?.clockIn) return null;

  const now        = new Date();
  const nowMins    = now.getHours()*60+now.getMinutes();
  const startMins  = parseHHMM("09:00");
  const graceMins  = 15;
  const isLate     = nowMins > startMins + graceMins;
  const timeStr    = now.toLocaleTimeString("en-PK",{hour:"2-digit",minute:"2-digit",hour12:true});

  const handleClockIn = async () => {
    if (isLate && !lateReason.trim()) return;
    setLoading(true);
    try {
      const today  = new Date().toISOString().split("T")[0];
      const record = {
        uid: user.uid,
        name: user.displayName || user.email.split("@")[0],
        role,
        clockIn:    now.toISOString(),
        clockOut:   null,
        status:     isLate ? "late" : "present",
        lateReason: isLate ? lateReason : "",
        note:       note || "",
        date:       today,
      };
      const ref = fsDoc(db, "attendance", today, "records", user.uid);
      await fsSet(ref, record);
      // Notify owner/aceo
      await triggerNotification(db, isLate ? "late_arrival" : "clock_in",
        isLate ? `⏰ Late Arrival — ${record.name}` : `✅ Clock In — ${record.name}`,
        `${record.name} ne ${timeStr} pe clock in kiya${isLate ? " (late)" : ""}`,
        user
      );
      if (onClockIn) onClockIn(record);
      onClose();
    } catch(e) { console.error(e); }
    setLoading(false);
  };

  return (
    <div style={{
      position:"fixed", inset:0,
      background:"rgba(3,2,1,0.88)",
      backdropFilter:"blur(12px)",
      zIndex:2000,
      display:"flex", alignItems:"center", justifyContent:"center",
      padding:20
    }}>
      <div className="attendance-popup" style={{
        background:"linear-gradient(145deg, #0F0C08 0%, #0A0806 60%, rgba(212,168,67,0.05) 100%)",
        border:`1px solid rgba(212,168,67,0.3)`,
        borderRadius:24,
        padding:"36px 32px",
        maxWidth:420,
        width:"100%",
        boxShadow:"0 24px 80px rgba(0,0,0,0.7), 0 0 0 1px rgba(212,168,67,0.08), inset 0 1px 0 rgba(212,168,67,0.15)",
        textAlign:"center",
      }}>
        {/* Top decoration */}
        <div style={{
          width:60, height:3,
          background:goldGrad,
          borderRadius:2,
          margin:"0 auto 28px",
          boxShadow:"0 0 12px rgba(212,168,67,0.5)",
        }}/>

        {/* Icon */}
        <div style={{
          fontSize:52,
          marginBottom:16,
          display:"inline-block",
          animation:"float 3s ease-in-out infinite",
          filter:"drop-shadow(0 0 12px rgba(212,168,67,0.4))",
        }}>
          {isLate ? "⏰" : "✅"}
        </div>

        <h2 style={{
          fontFamily:"Cinzel, serif",
          fontSize:22,
          letterSpacing:"1.5px",
          marginBottom:8,
          background:goldGrad,
          WebkitBackgroundClip:"text",
          WebkitTextFillColor:"transparent",
          backgroundSize:"200%",
          animation:"shimmer 3s ease infinite",
        }}>
          {isLate ? "You Are Late" : "Welcome!"}
        </h2>

        <p style={{ fontSize:14, color:"rgba(247,237,216,0.55)", marginBottom:6 }}>
          {new Date().toLocaleDateString("en-PK",{weekday:"long",day:"numeric",month:"long"})}
        </p>

        <div style={{
          display:"inline-block",
          padding:"8px 20px",
          background:"rgba(212,168,67,0.08)",
          border:`1px solid rgba(212,168,67,0.2)`,
          borderRadius:30,
          fontSize:20,
          fontWeight:700,
          color:C.gold,
          marginBottom:24,
          fontFamily:"Cormorant Garamond, serif",
          letterSpacing:1,
        }}>
          {timeStr}
        </div>

        {isLate && (
          <div style={{
            padding:"14px 16px",
            background:"rgba(248,113,113,0.06)",
            border:"1px solid rgba(248,113,113,0.2)",
            borderRadius:12,
            marginBottom:18,
            textAlign:"left",
          }}>
            <p style={{ fontSize:12, color:C.red, fontWeight:700, marginBottom:8, letterSpacing:"0.5px", textTransform:"uppercase" }}>
              ⚠️ Late Arrival — Reason Zaroor Likho
            </p>
            <input
              style={{...S.input(), fontSize:13}}
              placeholder="Late hone ki wajah likhein..."
              value={lateReason}
              onChange={e=>setLateReason(e.target.value)}
            />
          </div>
        )}

        <div style={{ marginBottom:20 }}>
          <input
            style={{...S.input(), fontSize:13, textAlign:"center"}}
            placeholder="Any note? (optional — e.g. WFH)"
            value={note}
            onChange={e=>setNote(e.target.value)}
          />
        </div>

        <div style={{ display:"flex", gap:10 }}>
          <button onClick={onClose} style={{
            ...S.btn("ghost", {flex:1, padding:"13px 0", fontSize:13})
          }} className="btn-ghost">
            Skip for now
          </button>
          <button
            onClick={handleClockIn}
            disabled={loading || (isLate && !lateReason.trim())}
            style={{
              ...S.btn("gold", {
                flex:2, padding:"13px 0", fontSize:14,
                opacity: (loading || (isLate && !lateReason.trim())) ? 0.5 : 1,
                boxShadow: "0 4px 20px rgba(212,168,67,0.3)",
              })
            }}
            className="btn-gold"
          >
            {loading ? "⏳ Clock In..." : isLate ? "⏰ Clock In (Late)" : "✅ Clock In"}
          </button>
        </div>

        {/* Bottom decoration */}
        <p style={{
          fontSize:11,
          color:"rgba(247,237,216,0.25)",
          marginTop:20,
          fontFamily:"Cormorant Garamond, serif",
          fontStyle:"italic",
          letterSpacing:"0.5px",
        }}>
          Khushboo That Speaks for You
        </p>
      </div>
    </div>
  );
}

// ── WooCommerce Auto-Sync helper (background, silent) ───────────────────────
async function autoSyncWooOrders(db, siteUrl, ck, cs, user) {
  if (!db || !siteUrl || !ck || !cs) return;
  try {
    const base = siteUrl.replace(/\/+$/, "");
    const auth = btoa(ck + ":" + cs);
    const url  = `${base}/wp-json/wc/v3/orders?per_page=50&status=processing,pending,on-hold&orderby=date&order=desc`;
    const resp = await fetch(url, { headers: { "Authorization": "Basic " + auth } });
    if (!resp.ok) return;
    const wooOrders = await resp.json();
    if (!Array.isArray(wooOrders) || wooOrders.length === 0) return;

    const existSnap = await fsGet(fsDoc(db, "meta", "wooSyncedIds"));
    const synced    = existSnap.exists() ? (existSnap.data().ids || []) : [];
    const newSynced = [...synced];
    let added = 0;

    for (const wo of wooOrders) {
      const wooId = String(wo.id);
      if (synced.includes(wooId)) continue;

      const billing   = wo.billing || {};
      const items     = wo.line_items || [];
      const firstItem = items[0] || {};
      const custName  = [billing.first_name, billing.last_name].filter(Boolean).join(" ") || "WooCommerce Customer";
      const statusMap = { "processing": "confirmed", "pending": "pending", "on-hold": "pending", "completed": "delivered", "cancelled": "cancelled" };

      const counterRef = fsDoc(db, "orderCounters", "main");
      const s    = await fsGet(counterRef);
      const n    = (s.exists() ? (s.data().count || 1000) : 1000) + 1;
      await fsSet(counterRef, { count: n }, { merge: true });
      const newId = "ASK-" + String(n).padStart(4, "0");

      const portalOrder = {
        orderId:         newId,
        wooOrderId:      wooId,
        product:         firstItem.name || "Online Order",
        qty:             firstItem.quantity || 1,
        price:           parseFloat(firstItem.price || 0),
        revenue:         parseFloat(wo.total || 0),
        customer:        custName,
        phone:           billing.phone || "",
        city:            billing.city || "",
        channel:         "Website",
        status:          statusMap[wo.status] || "pending",
        notes:           wo.customer_note || "",
        addedBy:         "WooCommerce Auto",
        addedById:       "woo_auto",
        createdAt:       new Date(wo.date_created || Date.now()).toISOString(),
        statusUpdatedAt: new Date().toISOString(),
        source:          "woocommerce",
        wooStatus:       wo.status,
      };

      const ref    = fsColl(db, "orders");
      const docRef = fsDoc(ref);
      await fsSet(docRef, { ...portalOrder, firestoreId: docRef.id });

      // Notification
      await triggerNotification(db, "new_order",
        "🛒 New Website Order — " + newId,
        `${portalOrder.product} × ${portalOrder.qty} | Rs.${Number(portalOrder.revenue).toLocaleString("en-PK")} | ${portalOrder.customer}`,
        user, { orderId: newId }
      );

      try { await triggerOrderChain(db, portalOrder, user); } catch(e) { console.warn("chain:", e); }
      newSynced.push(wooId);
      added++;
    }

    if (added > 0) {
      await fsSet(fsDoc(db, "meta", "wooSyncedIds"), { ids: newSynced.slice(-500) }, { merge: true });
      console.log(`[WooAutoSync] ✅ ${added} new order(s) added`);
    }
  } catch(e) {
    console.log("[WooAutoSync] Error:", e.message);
  }
}


export default function App() {
  const [fbReady, setFbReady] = useState(false);
  const [authUser, setAuthUser] = useState(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [role,      setRole]     = useState("member");
  const [penalty,   setPenalty]  = useState(null);
  const [points,    setPoints]   = useState(0);
  const [orderCount,setOrderCount]=useState(0);
  const [members,   setMembers]  = useState([]);
  const [orders,    setOrders]   = useState([]);
  const [globalUnread, setGlobalUnread] = useState(0);
  const [products,  setProducts] = useState(PRODUCTS_INITIAL);
  const [tasks,     setTasks]    = useState(DEFAULT_TASKS);
  const [tab,       setTab]      = useState("dashboard");

  // ── Brand Config (owner can update WA/email/website from portal) ──────────
  const [brandConfig, setBrandConfig] = useState({
    waNum:   BRAND_WA,
    email:   OWNER_EMAIL,
    website: WEBSITE_URL,
  });

  // ── Dynamic Event Theme ────────────────────────────────────────────────
  const [daysBeforeEvent, setDaysBeforeEvent] = useState(7);
  const [customEvents,    setCustomEvents]    = useState([]);
  const [activeTheme,     setActiveTheme]     = useState(() => getActiveEventTheme(7, []));
  const [themeOverride,   setThemeOverride]   = useState(null);

  const [slaConfig, setSlaConfig]  = useState(DEFAULT_SLA_CONFIG);
  const [orderTasks, setOrderTasks] = useState([]);
  const [waOrder,   setWaOrder]  = useState(null);
  const [levelPopup,setLevelPopup]=useState(null);
  const [db,        setDb]       = useState(null);
  const [showClockInPopup, setShowClockInPopup] = useState(false);
  const prevLevel = useRef(null);

  useEffect(()=>{
    loadFirebase().then(()=>{
      setFbReady(true);
      setDb(fb_db);
      onAuthChange(fb_auth, async (fbUser)=>{
        if (fbUser) {
          setAuthUser(fbUser);
          await loadUserData(fbUser);
        } else {
          setAuthUser(null);
          setAuthLoading(false);
        }
      });
    }).catch(e=>{ console.error("Firebase load error",e); setAuthLoading(false); });
  },[]);

  const loadUserData = async (fbUser) => {
    if (!fb_db) return;
    try {
      const uRef = fsDoc(fb_db,"users",fbUser.uid);
      let uSnap  = await fsGet(uRef);
      let userRole = "member"; // default
      let userPts  = 0, userOrds = 0, userPenalty = null;

      if (!uSnap.exists()) {
        await fsSet(uRef, {
          email:fbUser.email, role:userRole,
          name:fbUser.displayName||fbUser.email.split("@")[0],
          points:0, orderCount:0, createdAt:fsServerTime()
        });
      } else {
        const d = uSnap.data();
        userRole = d.role || "member";
        userPts  = d.points||0;
        userOrds = d.orderCount||0;
        userPenalty = d.penalty?.active ? d.penalty : null;
      }
      setRole(userRole); setPoints(userPts); setOrderCount(userOrds);
      setPenalty(userPenalty);
      prevLevel.current = getLoyaltyLevel(userPts);

      // ── Real-time orders listener — auto updates when new order arrives ──
      const oQ = fsQuery(fsColl(fb_db,"orders"), fsOrderBy("createdAt","desc"));
      const oSnap = await fsGetDocs(oQ);
      const loadedOrders = oSnap.docs.map(d=>({...d.data(), firestoreId:d.id}));
      setOrders(loadedOrders);

      // Real-time listener — portal auto-refreshes when WooCommerce/Zapier adds order
      if (fsOnSnapshot) {
        const ordersUnsub = fsOnSnapshot(oQ, (snap) => {
          const updated = snap.docs.map(d => ({...d.data(), firestoreId:d.id}));
          // Check for new orders — update global unread badge
          const prevCount = snap.docChanges ? snap.docChanges().filter(c=>c.type==="added").length : 0;
          if (prevCount > 0) setGlobalUnread(n => n + prevCount);
          setOrders(updated);
        }, (err) => console.warn("[Orders RT]", err));
        // Store unsub for cleanup (stored on window for simplicity)
        if (window._ordersUnsub) window._ordersUnsub();
        window._ordersUnsub = ordersUnsub;
      }

      const mSnap = await fsGetDocs(fsColl(fb_db,"users"));
      setMembers(mSnap.docs.map(d => {
        const data = d.data();
        // Always enforce correct owner role by email
        const correctedRole = data.email === OWNER_EMAIL ? "owner" : (data.role || "member");
        return { ...data, uid: d.id, role: correctedRole };
      }));

      try {
        const metaP = await fsGet(fsDoc(fb_db,"meta","products"));
        if (metaP.exists() && metaP.data().list?.length) setProducts(metaP.data().list);
      } catch{}
      try {
        const metaT = await fsGet(fsDoc(fb_db,"meta","tasks"));
        if (metaT.exists() && metaT.data().list?.length) setTasks(metaT.data().list);
      } catch{}

    } catch(e){ console.error("loadUserData error",e); }

    // ── Notification Permission + Listener (aggressive) ──
    try {
      if (typeof Notification !== "undefined") {
        // Always request permission aggressively
        await ensureNotifPermission();
        // Role Firestore se load hoti hai — email se determine karo
        const finalRole = fbUser.email === OWNER_EMAIL ? "owner" : (
          await fsGet(fsDoc(fb_db, "users", fbUser.uid))
            .then(s => s.exists() ? (s.data().role || "member") : "member")
            .catch(() => "member")
        );
        setupNotificationListener(fb_db, fbUser, finalRole);
        // FCM setup — app closed pe bhi notifications (optional, needs VAPID key)
        setupFCM(fb_db, fbUser.uid);
      }
    } catch(e) { console.warn("[Notif] Setup error:", e); }

    // ── Load SLA Config ──────────────────────────────────────────────────────
    try {
      const sSnap = await fsGet(fsDoc(fb_db, "workflowSettings", "config"));
      if (sSnap.exists() && sSnap.data().slaConfig)
        setSlaConfig(p => ({ ...DEFAULT_SLA_CONFIG, ...sSnap.data().slaConfig }));
    } catch {}
    // ── Load Order Tasks ─────────────────────────────────────────────────────
    try {
      const tSnap = await fsGet(fsDoc(fb_db, "orderTasks", "all"));
      if (tSnap.exists()) setOrderTasks(tSnap.data().tasks || []);
    } catch {}

    setAuthLoading(false);

    // ── Show clock-in popup for all team members ──
    setTimeout(() => setShowClockInPopup(true), 1000);
  };

  const handleLogin = async (fbUser) => {
    setAuthUser(fbUser);
    await loadUserData(fbUser);
  };

  const setTabWithRead = (tabId) => {
    setTab(tabId);
    if (tabId === "commandcenter" || tabId === "notifications") {
      setGlobalUnread(0);
    }
  };

  // ── SLA Escalation Checker — har 15 minute mein ──────────────────────────
  useEffect(() => {
    if (!db || !authUser) return;
    const run = async () => {
      const active = orders.filter(o => !["delivered","cancelled"].includes(o.status || ""));
      if (!active.length) return;
      let alerted = [];
      try {
        const snap = await fsGet(fsDoc(db, "slaAlerts", "log"));
        if (snap.exists()) alerted = snap.data().keys || [];
      } catch {}
      const newKeys = [];
      for (const o of active) {
        const sla = checkSLA(o, slaConfig);
        if (!sla?.breach) continue;
        const key = `${o.orderId}_${o.status}`;
        if (alerted.includes(key)) continue;
        try {
          await triggerNotification(db, "order_status",
            `🚨 SLA Breach — ${o.orderId}`,
            `${o.product} | ${o.customer||"Customer"} | ${o.status} | ${sla.label}. Foran action lo!`,
            authUser
          );
        } catch {}
        newKeys.push(key);
      }
      if (newKeys.length) {
        try {
          await fsSet(fsDoc(db, "slaAlerts", "log"),
            { keys: [...newKeys, ...alerted].slice(0, 500) }, { merge: true });
        } catch {}
      }
    };
    run();
    const t = setInterval(run, 15 * 60 * 1000);
    return () => clearInterval(t);
  }, [orders, db, slaConfig, authUser]);

  const handleSignOut = async () => {
    await signOutFn(fb_auth);
    setAuthUser(null); setRole("member"); setPoints(0); setOrderCount(0);
    setOrders([]); setMembers([]); setProducts(PRODUCTS_INITIAL); setTasks(DEFAULT_TASKS);
  };

  const onPointsEarned = async (pts) => {
    const newPts = points + pts;
    const newCnt = orderCount + 1;
    setPoints(newPts); setOrderCount(newCnt);
    const newLvl = getLoyaltyLevel(newPts);
    if (newLvl && newLvl.name !== prevLevel.current?.name) {
      setLevelPopup(newLvl);
      prevLevel.current = newLvl;
    }
    if (db && authUser) {
      try { await fsUpdate(fsDoc(db,"users",authUser.uid),{points:newPts,orderCount:newCnt}); } catch{}
    }
  };

  if (!fbReady || authLoading) return <><GlobalStyles/><LoadingScreen/></>;
  if (!authUser) return <><GlobalStyles/><LoginScreen onLogin={handleLogin}/></>;
  if (penalty?.active && role !== "owner" && role !== "aceo")
    return <PenaltyScreen penalty={penalty} onSignOut={handleSignOut}/>;

  const access = ACCESS(role);

  // ── UPDATED: Tabs array with Customers tab ────────────────────────────────
  const tabs = [
    { id:"dashboard",     icon:"◈",  label:"Dashboard"     },
    { id:"commandcenter", icon:"🎯", label:"Command Center" },
    { id:"notifications", icon:"🔔", label:"Notifications" },
    { id:"pkevents",      icon:"🇵🇰", label:"Seasonal Sales" },
    { id:"inventory",  icon:"📊", label:"Inventory"    },
    { id:"multiloc",   icon:"📍", label:"Multi-Location" },
    { id:"products",  icon:"✦",  label:"Products"   },
    { id:"ai",        icon:"✦",  label:"AI Brain"   },
    { id:"aireply",   icon:"💬", label:"AI Reply"   },
    { id:"aidesc",    icon:"✦",  label:"AI Descriptions" },
    ...(access.admin      ? [{ id:"admin",     icon:"⚙",  label:"Admin"      }] : []),
    ...(access.admin      ? [{ id:"workflow",  icon:"⚡", label:"Workflow"    }] : []),
    ...(access.admin      ? [{ id:"customers", icon:"👥", label:"Customers"  }] : []),
    ...(access.analytics  ? [{ id:"analytics", icon:"📈", label:"Analytics"  }] : []),
    ...(access.expenses   ? [{ id:"expenses",  icon:"💸", label:"Expenses"   }] : []),
    ...(access.teamPerf   ? [{ id:"teamperf",  icon:"🏆", label:"Team Stats" }] : []),
    { id:"leaderboard", icon:"🥇", label:"Leaderboard" },
    ...(access.coupons    ? [{ id:"coupons",    icon:"🎟", label:"Coupons"     }] : []),
    ...(access.influencer ? [{ id:"influencer", icon:"🌟", label:"Influencers"  }] : []),
    ...(access.contentCal ? [{ id:"content",    icon:"📅", label:"Content"      }] : []),
    ...(access.followup   ? [{ id:"followup",   icon:"🔔", label:"Follow-ups"   }] : []),
    { id:"reviews",  icon:"⭐", label:"Reviews" },
    { id:"wabiz",    icon:"💚", label:"WA Business" },
    ...(access.returns    ? [{ id:"returns",    icon:"↩",  label:"Returns"      }] : []),
    ...(access.team          ? [{ id:"team",          icon:"👥", label:"Team"           }] : []),
    ...(access.brandSettings ? [{ id:"brandsettings", icon:"⚙️", label:"Brand Settings"  }] : []),
    ...(access.attendance ? [{ id:"attendance", icon:"🕐", label:"Attendance"  }] : []),
    ...(access.designer   ? [{ id:"designer",   icon:"🎨", label:"Designer"    }] : []),
    ...(access.shoot      ? [{ id:"shoot",       icon:"📷", label:"Shoots"      }] : []),
    ...(access.bizManager ? [{ id:"bizmanager",  icon:"📊", label:"Biz Manager"     }] : []),
    ...(access.brandConn    ? [{ id:"brandconn",   icon:"🔗", label:"Brand Connections" }] : []),
    ...(access.intelligence ? [{ id:"intelligence", icon:"🧠", label:"Intelligence"       }] : []),
    { id:"brandreport", icon:"📄", label:"PDF Report" },
    { id:"guide",         icon:"📖", label:"My Guide"      },
    { id:"healthmonitor", icon:"🛡️", label:"Health Monitor" },
    { id:"ecommerce", icon:"🛒", label:"E-Commerce" },
    { id:"toolhub",   icon:"🛠️", label:"Tool Hub" },
  ];

  // Compute final theme (override takes priority)
  // Recompute theme when daysBeforeEvent or customEvents changes
  const theme = themeOverride || getActiveEventTheme(daysBeforeEvent, customEvents);

  return (
    <>
      <GlobalStyles/>
      <PWAInstallBanner/>
      {/* Inject event theme CSS variables — portal-wide deep theming */}
      <style>{`
        :root {
          --event-gold:    ${theme.gold   || "#D4A843"};
          --event-goldD:   ${theme.goldD  || "#A07830"};
          --event-goldL:   ${theme.goldL  || "#F0C84A"};
          --event-goldXL:  ${theme.goldXL || "#FFE98A"};
          --event-bg:      ${theme.bg     || "#030201"};
          --event-border:  ${theme.border || "rgba(212,168,67,0.18)"};
          --event-cardBg:  ${theme.cardBg || "rgba(212,168,67,0.04)"};
          --event-grad:    ${theme.grad   || "linear-gradient(135deg,#A07830,#D4A843,#F0C84A,#FFE98A)"};
        }
        body { background-color: ${theme.bg || "#030201"} !important; }
        ::-webkit-scrollbar-thumb { background: ${theme.grad || "linear-gradient(180deg,#D4A843,#A07830)"} !important; }
        input:focus, textarea:focus, select:focus {
          border-color: ${theme.gold || "#D4A843"} !important;
          box-shadow: 0 0 0 2px ${theme.gold || "#D4A843"}1f !important;
        }
        .fadeUp { animation: fadeUp 0.4s ease; }
      `}</style>
      <EventThemeBanner theme={theme}/>
      <EventParticles theme={theme}/>
      <div style={{
        minHeight:"100vh",
        background:`radial-gradient(ellipse at 15% 0%, rgba(212,168,67,0.04) 0%, transparent 55%),
                   radial-gradient(ellipse at 85% 100%, rgba(160,120,48,0.03) 0%, transparent 45%),
                   #030201`,
        overflowX:"hidden"
      }}>

        <Header user={authUser} role={role} points={points} onSignOut={handleSignOut} unreadCount={globalUnread} onBellClick={()=>setTabWithRead("commandcenter")} theme={theme}/>

        {/* ── DESKTOP LAYOUT: Sidebar + Content ── */}
        <div className="desktop-layout" style={{ display:"flex", alignItems:"flex-start" }}>

          {/* Sidebar — desktop only, hidden on mobile/tablet via CSS */}
          <div className="sidebar-wrapper">
            <PremiumSidebar
              tabs={tabs} active={tab} onChange={setTabWithRead}
              user={authUser} role={role} points={points}
            />
          </div>

          {/* Mobile TabBar — hidden on desktop via CSS */}
          <div className="tabbar-wrapper" style={{ width:"100%" }}>
            <TabBar tabs={tabs} active={tab} onChange={setTabWithRead}/>
          </div>

          {/* Main content */}
          <div className="main-content" style={{ flex:1, minWidth:0, padding:"0 0 80px", overflow:"hidden" }}>
          {tab==="commandcenter" && <CommandCenterTab
            user={authUser} role={role} orders={orders} products={products}
            members={members} db={db} access={access}
            onTabChange={setTabWithRead}/>}
          {tab==="notifications" && <NotificationsTab
            db={db} user={authUser} role={role}
            members={members} orders={orders}/>}
          {tab==="pkevents" && <PakistanEventsTab
            orders={orders} db={db} access={access}
            products={products} members={members}
            activeTheme={theme}
            onThemeOverride={setThemeOverride}
            daysBeforeEvent={daysBeforeEvent}
            onDaysChange={setDaysBeforeEvent}
            customEvents={customEvents}
            onCustomEventsChange={setCustomEvents}/>}
          {tab==="dashboard"  && <DashboardTab orders={orders} products={products}
            user={authUser} role={role} points={points} orderCount={orderCount}
            tasks={tasks} setTasks={setTasks} access={access} db={db}
            theme={theme}/>}
          {tab==="inventory"  && <InventoryTab products={products} setProducts={setProducts}
            access={access} db={db}/>}
          {tab==="multiloc"   && <MultiLocationTab products={products} db={db}/>}
          {tab==="products"   && <ProductsTab products={products} setProducts={setProducts}
            access={access} db={db}/>}
          {tab==="ai"         && <AIBrainTab role={role} products={products} orders={orders} db={db}/>}
          {tab==="admin"      && <AdminTab orders={orders} setOrders={setOrders}
            products={products} setProducts={setProducts}
            user={authUser} role={role} access={access} db={db}
            onWAPopup={setWaOrder} onPointsEarned={onPointsEarned}
            members={members}
            slaConfig={slaConfig}
            setOrderTasks={setOrderTasks}/>}
          {tab==="workflow"   && <WorkflowTab
            orders={orders} members={members} db={db}
            user={authUser} role={role} access={access}
            slaConfig={slaConfig} setSlaConfig={setSlaConfig}
            orderTasks={orderTasks} setOrderTasks={setOrderTasks}/>}
          {tab==="customers"  && <CustomerLoyaltyTab orders={orders} access={access}/>}
          {tab==="analytics"  && <SalesAnalyticsTab orders={orders} products={products}/>}
          {tab==="expenses"   && <ExpenseTrackerTab orders={orders} db={db} access={access}/>}
          {tab==="teamperf"   && <TeamPerformanceTab orders={orders} members={members} access={access}/>}
          {tab==="coupons"    && <CouponManagerTab db={db} access={access} orders={orders}/>}
          {tab==="influencer" && <InfluencerTrackerTab db={db} access={access} orders={orders}/>}
          {tab==="content"    && <ContentCalendarTab db={db} access={access} role={role}/>}
          {tab==="followup"   && <FollowUpTab db={db} access={access} orders={orders}/>}
          {tab==="returns"    && <ReturnRefundTab db={db} access={access} orders={orders}/>}
          {tab==="team"       && <TeamTab members={members} setMembers={setMembers}
            user={authUser} access={access} db={db} role={role}/>}
          {tab==="attendance" && <AttendanceTab user={authUser} role={role}
            members={members} db={db} access={access}/>}
          {tab==="designer"   && <DesignerTab db={db} role={role} user={authUser}/>}
          {tab==="shoot"      && <ShootTab db={db} user={authUser}/>}
          {tab==="bizmanager" && <BusinessManagerTab orders={orders} members={members} db={db} access={access}/>}
          {tab==="brandconn"  && <BrandConnectionsTab db={db} user={authUser} access={access} orders={orders}/>}
          {tab==="intelligence" && <IntelligenceTab orders={orders} members={members} db={db} user={authUser} access={access}/>}
          {tab==="guide"         && <MyGuideTab role={role}/>}
          {tab==="healthmonitor" && <SystemHealthTab db={db} orders={orders} products={products} members={members} role={role}/>}
          {tab==="ecommerce"  && <EcommerceTab orders={orders} products={products}
            members={members} db={db} user={authUser} role={role} access={access}/>}
          {tab==="toolhub"    && <ToolHubTab role={role} user={authUser}/>}
          {tab==="leaderboard"    && <TeamLeaderboardTab members={members} orders={orders} db={db} user={authUser} role={role}/>}
          {tab==="brandsettings"  && <BrandSettingsTab db={db}/>}
          {tab==="reviews"     && <ReviewCollectorTab orders={orders} db={db} user={authUser}/>}
          {tab==="wabiz"      && <WABusinessTab orders={orders} db={db} user={authUser}/>}
          {tab==="brandreport" && <BrandedReportTab orders={orders} products={products}/>}
          {tab==="aireply"    && <AIReplyTab db={db} orders={orders} products={products} user={authUser}/>}
          {tab==="aidesc"     && <AIProductDescTab db={db} products={products} user={authUser}/>}
          </div>
        </div>{/* end desktop-layout */}
      </div>

      {waOrder    && <WAPopup order={waOrder} onClose={()=>setWaOrder(null)}/>}
      {levelPopup && <LevelUnlockPopup level={levelPopup} onClose={()=>setLevelPopup(null)}/>}
      {showClockInPopup && authUser && (
        <AttendanceClockInPopup
          user={authUser}
          role={role}
          db={db}
          onClose={()=>setShowClockInPopup(false)}
          onClockIn={()=>setShowClockInPopup(false)}
        />
      )}
    </>
  );
}


// ═══════════════════════════════════════════════
// SERVICE WORKER REGISTRATION
// Paste this code at the BOTTOM of your App.jsx
// Just before the final closing brace: }
// ═══════════════════════════════════════════════

// PWA Service Worker Registration
if (typeof window !== "undefined" && "serviceWorker" in navigator) {
  window.addEventListener("load", () => {
    navigator.serviceWorker
      .register("/sw.js")
      .then((reg) => {
        console.log("[AS KHUSHBOO PWA] Service Worker registered:", reg.scope);

        // Check for updates every 60 minutes
        setInterval(() => reg.update(), 60 * 60 * 1000);
      })
      .catch((err) => {
        console.warn("[AS KHUSHBOO PWA] SW registration failed:", err);
      });
  });
}
